INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1754a16b-8af9-449c-b805-ed3921db5156', 'Core Build Commands', 'https://developer.android.com/build/building-cmdline', NULL, 'The Android Gradle Plugin (AGP) is the standard build system for Android. All builds are invoked via the Gradle wrapper (`./gradlew` on macOS/Linux, `gradlew` on Windows). Commands follow camelCase variant naming: `assemble{Flavor}{BuildType}`.', NULL, 'android', 'gradle-cli-implementverify', 'implement,verify', 'plugin', 'macos,android,windows,linux', 'bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4c624e32-aba1-4b7b-8dda-8d16d7e9fde0', 'Android Emulator', 'https://developer.android.com/studio/run/emulator-commandline', NULL, 'The Android Emulator simulates Android devices on your computer. It supports snapshots, GPU acceleration, network simulation, and headless mode for CI.', 'sdkmanager "emulator"', 'android', 'emulator-management-implementverify', 'implement,verify', 'mcp', 'android', 'swift,bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ccb4f3b6-68e4-4e49-81db-79542e94254e', 'avdmanager', 'https://developer.android.com/tools/avdmanager', NULL, 'CLI tool for creating, deleting, and listing Android Virtual Devices (AVDs). Part of the SDK Command-Line Tools.', 'sdkmanager "cmdline-tools;latest"', 'android', 'emulator-management-implementverify', 'implement', 'cli', 'android', 'go,bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0c5bc980-d2eb-47c1-a09c-8c1950199bf0', 'sdkmanager', 'https://developer.android.com/tools/sdkmanager', NULL, 'CLI tool for downloading, updating, and managing Android SDK packages. Essential for CI environments without Android Studio.', NULL, 'android', 'emulator-management-implementverify', 'implement', 'cli', 'android', 'bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('20274a37-2a70-4081-a7ed-e061eef36efa', 'bundletool', 'https://developer.android.com/tools/bundletool', NULL, 'The underlying tool Android Studio and Google Play use to build, deploy, and validate Android App Bundles (.aab). Generates device-specific APK sets, installs them on devices, measures sizes, and validates bundles.', 'brew install bundletool', 'android', 'app-bundle-apk-tools-verify', 'verify', 'cli', 'android', 'go,java,bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6f4e18fb-7dca-4b9d-bd0f-de597e415a24', 'apkanalyzer', 'https://developer.android.com/tools/apkanalyzer', NULL, 'CLI tool for inspecting APK composition: file sizes, manifest details, DEX method counts, class trees, and APK-to-APK comparisons. Useful for verifying APK size budgets and checking method reference counts (the 64K limit).', 'sdkmanager "cmdline-tools;latest"', 'android', 'app-bundle-apk-tools-verify', 'verify', 'cli', 'android', 'bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bce1727b-b5ae-4a79-a5cd-1141dacaa0ed', 'aapt2', 'https://developer.android.com/tools/aapt2', NULL, 'Compiles and links Android resources. Bundled with build-tools and used internally by AGP, but available for standalone resource compilation.', 'sdkmanager "build-tools;34.0.0"', 'android', 'app-bundle-apk-tools-verify', 'implement', NULL, 'android', 'bash', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ac1bd5b2-dfe1-4aa2-8cbf-cc571d43fc27', 'GitHub Actions', 'https://github.com/android-actions/setup-android', 'https://github.com/android-actions/setup-android', 'GitHub Actions provides first-party and community actions for Android CI/CD. `actions/setup-java` configures JDK. `android-actions/setup-android` installs the Android SDK. `ReactiveCircus/android-emulator-runner` boots an emulator with hardware acceleration for instrumented tests.', NULL, 'android', 'cicd-integration-verify', 'verify', NULL, 'android,linux', 'go,java', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9fb74d3d-9b50-44cb-9523-6f33d8b2e762', 'Bitrise', 'https://bitrise.io/solutions/technologies/android', NULL, 'Mobile-first CI/CD platform with pre-built steps for Android builds, unit tests, instrumented tests, and deployment. Configured via `bitrise.yml`.', NULL, 'android', 'cicd-integration-verify', 'verify', NULL, 'android', NULL, 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('131dcacd-4801-48b3-958c-7a942ee711ef', 'Codemagic', 'https://codemagic.io/android-continuous-integration/', NULL, 'CI/CD platform supporting native Android, Flutter, React Native, and more. Configured via `codemagic.yaml` or the web UI. Supports emulator-based testing and Firebase Test Lab integration.', NULL, 'android', 'cicd-integration-verify', 'verify', NULL, 'android,web', 'java', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0c0129c2-49f6-4220-b5d3-8be4bb194646', 'CircleCI', 'https://circleci.com/developer/orbs/orb/circleci/android', NULL, 'CI/CD platform with a dedicated Android orb providing executors, commands, and jobs for building and testing Android apps. Supports emulator-based instrumented testing via `android/start-emulator-and-run-tests`.', NULL, 'android', 'cicd-integration-verify', 'verify', NULL, 'android', 'go', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5c6cf06c-cc42-4c5f-bc84-af97bf6084d7', 'Kotlin Language Server', 'https://claude.com/plugins/kotlin-lsp', NULL, 'Provides IDE-level code intelligence for Kotlin in Claude Code: go-to-definition, find-references, hover documentation, document symbols, and diagnostics. Released December 2025.', 'brew install JetBrains/utils/kotlin-lsp', 'android', 'claude-code-integration-all-phases', 'plan,implement,verify', 'plugin', NULL, 'go,java,kotlin', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('804248cf-0c31-41f5-b078-894436451dfb', 'MCP Servers for Android', 'https://github.com/mobile-next/mobile-mcp', 'https://github.com/mobile-next/mobile-mcp', 'Platform-agnostic MCP server for both Android and iOS automation. Provides device management, app management, screen interaction (tap, swipe, type), screenshot capture, and element inspection.', NULL, 'android', 'claude-code-integration-all-phases', 'implement', 'mcp', 'ios,android', 'typescript', 'android/android-build-and-emulator.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ef3c6aa0-4987-48ad-92e6-33cc1ca90201', 'ktlint', 'https://github.com/pinterest/ktlint', 'https://github.com/pinterest/ktlint', '*What it does: Anti-bikeshedding Kotlin linter and formatter. Captures Kotlin coding conventions and the Android Kotlin Style Guide with zero configuration required. Auto-fixes most violations.', NULL, 'android', 'linters-formatters-implementverify', 'implement,verify', 'plugin', 'android', 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d9a882c2-f276-4655-b5df-661aace25b08', 'detekt', 'https://detekt.dev/', NULL, '*What it does: Static code analysis for Kotlin. Finds code smells, complexity issues, naming violations, and style problems. Highly configurable rule engine with 200+ built-in rules. Supports HTML, Markdown, SARIF, and XML reports.', NULL, 'android', 'linters-formatters-implementverify', 'implement,verify', 'plugin', NULL, 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4462ac50-5014-436b-a435-829eee831bc3', 'ktfmt', 'https://facebook.github.io/ktfmt/', NULL, '*What it does: Opinionated Kotlin code formatter based on google-java-format. Deterministic output regardless of input formatting. Non-customizable by design to enforce consistency. 40% faster than ktlint in large codebases (per Square''s benchmarks on 60,000+ files).', NULL, 'android', 'linters-formatters-implementverify', 'implement,verify', 'plugin', NULL, 'go,java,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3c9c215f-f7e7-4be9-910a-14bb3ce6ecbc', 'diktat', 'https://diktat.saveourtool.com/', NULL, '*What it does: Strict coding standard for Kotlin with 100+ checkers built on the ktlint rule engine. Focuses on code smells, style issues, and bugs. Includes auto-fixing capabilities.', NULL, 'android', 'linters-formatters-implementverify', 'implement,verify', 'plugin', NULL, 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('429d50b9-485c-4ae5-967e-34165051b3af', 'Android Lint', 'https://developer.android.com/studio/write/lint', NULL, '*What it does: Built-in static analysis tool for Android projects. Checks for structural issues, performance problems, accessibility, internationalization, security vulnerabilities, and correctness. Supports custom rule authoring. AGP version + 23 = Lint version (e.g., AGP 8.x = Lint 31.x).', NULL, 'android', 'linters-formatters-implementverify', 'implement,verify', 'plugin', 'android', 'go,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('73abff3c-4bef-4292-8c22-69da5c03d81a', 'JUnit 5', 'https://junit.org/junit5/', NULL, '*What it does: The standard test framework for JVM projects. JUnit Jupiter provides annotations (`@Test`, `@BeforeEach`, `@ParameterizedTest`), lifecycle callbacks, and an extension model. Recent releases add Kotlin-friendly features: top-level assertions with contracts, `Sequence` parameter sources, and native `suspend` test support.', NULL, 'android', 'testing-frameworks-verify', 'implement,verify', 'cli', NULL, 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b846b598-0a10-4333-9c7c-8e772d5a7e88', 'Kotest', 'https://kotest.io/', NULL, '*What it does: Multiplatform Kotlin test framework with 10+ testing styles (FunSpec, BehaviorSpec, StringSpec, etc.), 350+ built-in assertions, integrated property testing (100+ generators with shrinking), and data-driven testing (built into core since 6.0). First-class coroutine support.', NULL, 'android', 'testing-frameworks-verify', 'implement,verify', NULL, NULL, 'kotlin,lua', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f43970b8-aa3e-4e72-8bba-a5619767ad76', 'MockK', 'https://mockk.io/', NULL, '*What it does: Kotlin-native mocking library. Handles final classes (default in Kotlin), objects, companion objects, extension functions, top-level functions, and coroutines (`coEvery`/`coVerify`) without ceremony. Annotations: `@MockK`, `@RelaxedMockK`, `@InjectMockKs`. Integrates with JUnit 5, Kotest, and Spring (via SpringMockK).', NULL, 'android', 'testing-frameworks-verify', 'implement,verify', 'cli', 'ios,android', 'kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8769aa9c-b07a-4bac-8f35-9be6549957e0', 'Turbine', 'https://github.com/cashapp/turbine', 'https://github.com/cashapp/turbine', '*What it does: Small testing library for `kotlinx.coroutines` Flow. Converts push-based Flows into pull-based suspend functions for straightforward assertion. Default 3-second timeout on awaits. Supports `awaitItem()`, `awaitError()`, `awaitComplete()`, `skipItems()`, and `cancelAndIgnoreRemainingEvents()`.', NULL, 'android', 'testing-frameworks-verify', 'implement,verify', 'cli', NULL, 'kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('74c34987-98de-4e40-95a9-06e48ddcb13d', 'kotlin-test', 'https://kotlinlang.org/api/kotlin-test/', NULL, '*What it does: Official Kotlin multiplatform test library. Provides platform-agnostic annotations (`@Test`, `@BeforeTest`) and assertions (`assertEquals`, `assertTrue`, `assertFailsWith`). Thin abstraction over JUnit (JVM), XCTest (native), and Jasmine/Mocha (JS).', NULL, 'android', 'testing-frameworks-verify', 'implement,verify', NULL, NULL, 'kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('818832f7-037e-4037-aedc-5cd2886e8b34', 'Robolectric', 'https://robolectric.org/', NULL, '*What it does: Runs Android unit tests on the JVM without an emulator. Simulates Android framework APIs (Activities, Views, Resources, SQLite) via "shadows." Supports API levels 23-36 (Marshmallow through Baklava). Tests run ~10x faster than emulator tests.', NULL, 'android', 'testing-frameworks-verify', 'implement,verify', NULL, 'android', 'go,kotlin,bash,sql', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1b8ed226-df17-482a-b90b-f312a0c183aa', 'KSP', 'https://github.com/google/ksp', 'https://github.com/google/ksp', '*What it does: Kotlin-first annotation processing API. Analyzes Kotlin code directly (not Java stubs) for up to 2x faster builds than kapt. KSP2 is the default since early 2025. KSP1 is deprecated and incompatible with Kotlin 2.3+. Used by Room, Hilt, Moshi, and most modern Kotlin libraries.', NULL, 'android', 'code-generation-implement', 'implement', 'plugin', 'android', 'go,java,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('12218720-217a-468b-850c-4c43bc65e5cb', 'kapt', 'https://kotlinlang.org/docs/kapt.html', NULL, '*What it does: Kotlin Annotation Processing Tool. Generates Java stubs from Kotlin code, then runs Java annotation processors against those stubs. Slower than KSP because of the stub generation step. Now in maintenance mode — migrate to KSP when processors support it.', NULL, 'android', 'code-generation-implement', 'implement', 'plugin', 'android', 'java,kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f9aa59e8-3004-467c-aed1-21f61b707e55', 'Dagger / Hilt', 'https://dagger.dev/hilt/', NULL, '*What it does: Compile-time dependency injection framework for Android. Hilt is the opinionated Android layer over Dagger. Supports KSP since Hilt 2.48, with current version at 2.57.1. KSP processing is up to 2x faster than kapt.', NULL, 'android', 'code-generation-implement', 'implement,verify', 'plugin', 'android', 'go,kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1b470f4d-546f-4a9a-bc83-d93d0dd798b4', 'Room', 'https://developer.android.com/training/data-storage/room', NULL, '*What it does: SQLite abstraction layer for Android. Generates DAO implementations, migration helpers, and database classes at compile time. Room 3.0 (2026) is KSP-only, Kotlin-code-only, and coroutine-first — no more kapt or Java code generation. Supports Kotlin Multiplatform (Android, iOS, JVM).', NULL, 'android', 'code-generation-implement', 'implement', 'plugin', 'ios,android', 'go,java,kotlin,sql', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('52fefd4b-2add-4e49-93f1-e216e1469767', 'Gradle Build Scans / Develocity', 'https://scans.gradle.com/', NULL, '*What it does: Web-based build analysis. Captures dependency resolution, task execution times, test results, and failure details. Free public scans available at scans.gradle.com. Enterprise version (Develocity 2026.1) adds build caching and predictive test selection.', NULL, 'android', 'build-tooling-implementverify', 'implement,verify', 'plugin', 'web', 'bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('94dc38d1-c88d-4a07-b7bf-85dcd64311e0', 'Gradle Version Catalog', 'https://docs.gradle.org/current/userguide/version_catalogs.html', NULL, '*What it does: Centralizes dependency versions in a single `libs.versions.toml` file. Generates type-safe accessors for all modules. Sections: `[versions]`, `[libraries]`, `[bundles]`, `[plugins]`. Eliminates version duplication across multi-module projects.', NULL, 'android', 'build-tooling-implementverify', 'implement,verify', 'plugin', 'android', 'go,kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('64b5b0eb-3533-40df-8d41-0cad1b40160b', 'SonarQube / SonarCloud', 'https://www.sonarsource.com/knowledge/languages/kotlin/', NULL, '*What it does: Continuous code quality platform with hundreds of Kotlin-specific rules. Supports symbolic execution, taint analysis, and security hotspot detection. Imports detekt findings. Available as SonarQube Server (self-hosted) or SonarCloud (hosted).', NULL, 'android', 'static-analysis-verify', 'verify', 'plugin', 'web', 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('36702b7e-1081-46d2-8184-194545a5ca7e', 'Semgrep', 'https://semgrep.dev/docs/languages/kotlin', NULL, '*What it does: Lightweight static analysis with pattern-matching rules. Kotlin support is GA with framework-specific Pro rules. Covers 80% of critical CVEs since 2017 and 100% of critical+high CVEs since May 2022. Supply chain reachability analysis for Kotlin/Gradle (no lockfile required). December 2025 added new high-severity reachability rules for Java/Kotlin/Scala.', NULL, 'android', 'static-analysis-verify', 'verify', NULL, NULL, 'java,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f2587324-3d55-43a2-aa2a-a7cd5b3e9a89', 'konsist', 'https://docs.konsist.lemonappdev.com/', NULL, '*What it does: Architectural testing library for Kotlin (the ArchUnit equivalent). Write unit tests that enforce architectural boundaries, naming conventions, package structure, visibility modifiers, annotation placement, and layer dependencies. Supports hexagonal, onion, and 3-tier architectures. Works with JUnit and Kotest.', NULL, 'android', 'static-analysis-verify', 'plan,implement,verify', 'cli', NULL, 'go,kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a00c54b6-cf95-41fd-a265-d9187e49572f', 'Renovate', 'https://docs.renovatebot.com/modules/manager/gradle/', NULL, '*What it does: Automated dependency update bot. Parses `build.gradle`, `build.gradle.kts`, `gradle.properties`, `libs.versions.toml`, and `versions.props`. Opens PRs with dependency bumps. Highly configurable (hundreds of options, config presets, grouping strategies). Supports Gradle wrapper updates.', NULL, 'android', 'dependency-management-implement', 'implement,verify', NULL, NULL, 'kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('53b29544-94ba-473f-a3a2-a43c6b368155', 'Dependabot', 'https://docs.github.com/en/code-security/dependabot', 'https://docs.github.com/en/code-security/dependabot', '*What it does: GitHub-native dependency update bot. Supports Gradle (build.gradle, build.gradle.kts, settings.gradle). Opens PRs for version bumps. Simpler configuration than Renovate but fewer customization options.', NULL, 'android', 'dependency-management-implement', 'implement', 'cli', NULL, NULL, 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('45163796-8257-4f75-bd78-b5331a158010', 'dependency-analysis-gradle-plugin', 'https://github.com/autonomousapps/dependency-analysis-gradle-plugin', 'https://github.com/autonomousapps/dependency-analysis-gradle-plugin', '*What it does: Finds unused dependencies, used-but-undeclared transitive dependencies, and misplaced dependencies (e.g., `implementation` vs `api` vs `debugImplementation`). Uses bytecode analysis. Variant-aware for Android projects. Detects unused annotation processors.', NULL, 'android', 'dependency-management-implement', 'implement,verify', 'plugin', 'android', 'go,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('de261eab-4949-48f2-a8ed-7601b5439a0b', 'Dokka', 'https://github.com/Kotlin/dokka', 'https://github.com/Kotlin/dokka', '*What it does: Documentation engine for Kotlin. Understands KDoc comments and Java''s Javadoc. Generates HTML (custom modern format), Javadoc HTML, GFM Markdown, and Jekyll Markdown. Supports mixed Kotlin/Java projects and Kotlin Multiplatform. K2 analysis is stable and default since Dokka 2.1.0.', NULL, 'android', 'documentation-implement', 'implement,verify', 'plugin', NULL, 'go,java,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c10b3b2a-fa37-43ba-9457-09a522fc9b4c', 'kotlinx-coroutines-test', 'https://kotlinlang.org/api/kotlinx.coroutines/kotlinx-coroutines-test/', NULL, '*What it does: Official test utilities for Kotlin coroutines. `runTest` builder automatically skips `delay()` calls while preserving execution order. `TestDispatcher` types control virtual time. `StandardTestDispatcher` queues coroutines for manual advancement. `UnconfinedTestDispatcher` executes eagerly.', NULL, 'android', 'coroutine-tools-implementverify', 'implement,verify', NULL, NULL, 'kotlin', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2d14c963-a0d0-4f88-91c3-0061340f546a', 'Snyk', 'https://snyk.io/', NULL, '*What it does: SCA (Software Composition Analysis) tool that scans Gradle dependencies for known vulnerabilities. Supports both Groovy and Kotlin DSL build files. Gradle plugin (0.7.0) runs as a build task. Snyk CLI provides richer output and monitoring capabilities.', NULL, 'android', 'dependency-security-verify', 'verify', 'plugin', NULL, 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9c4798d5-53c6-4f5e-ae13-4821af0277be', 'OWASP Dependency-Check', 'https://owasp.org/www-project-dependency-check/', NULL, '*What it does: SCA tool that identifies known vulnerable dependencies by matching them against the NVD (National Vulnerability Database). Gradle plugin generates HTML/JSON/XML reports. Supports Java, Kotlin, and other JVM dependencies.', NULL, 'android', 'dependency-security-verify', 'verify', 'plugin', NULL, 'java,kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d0221759-0fbc-45a5-a48e-0371c080095f', 'Socket.dev', 'https://socket.dev/', NULL, '*What it does: Supply chain security platform that inspects packages for risky behaviors (network calls, obfuscated code, unsafe filesystem operations) rather than just matching CVEs. Kotlin/Gradle support added in 2025. Analyzes `build.gradle`, `build.gradle.kts`, and `gradle.lockfile`. Generates SBOM via CycloneDX.', NULL, 'android', 'dependency-security-verify', 'verify', 'cli', NULL, 'kotlin,bash', 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e68215d1-e095-43bd-b0b2-f3109c29198b', 'Format Kotlin code', NULL, NULL, 'ktlint or ktfmt (pick one)', NULL, 'android', 'tool-selection-quick-reference', 'implement', NULL, NULL, 'kotlin', 'android/kotlin-tooling.md');
