INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('96b2d6dd-a037-4244-9b15-0342bdaf545f', 'Annotation processing', NULL, NULL, 'KSP (not kapt)', NULL, 'android', 'tool-selection-quick-reference', 'implement', NULL, NULL, NULL, 'android/kotlin-tooling.md');
