INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f2f3d9f6-9dc6-491d-a54f-0d98c6393ef6', 'Dependency versions', NULL, NULL, 'Gradle Version Catalog', NULL, 'android', 'tool-selection-quick-reference', 'implement', NULL, NULL, NULL, 'android/kotlin-tooling.md');
