INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('af5f2a84-e0c5-4faa-8557-0e540c2a92b6', 'SAST', NULL, NULL, 'Semgrep', NULL, 'android', 'tool-selection-quick-reference', 'implement', NULL, NULL, NULL, 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d7f6261d-4d7d-47b1-bf8e-db641562514e', 'Supply chain', NULL, NULL, 'Socket.dev', NULL, 'android', 'tool-selection-quick-reference', 'implement', NULL, NULL, NULL, 'android/kotlin-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d704979b-a930-4467-9341-8631f9b8313f', 'Paparazzi', 'https://github.com/cashapp/paparazzi', 'https://github.com/cashapp/paparazzi', 'JVM-only screenshot testing library by Cash App. Renders Android screens using LayoutLib (the same renderer Android Studio uses for previews) without a physical device or emulator. Supports both Composables and Android Views. Almost twice as fast as Google''s Compose Preview Screenshot Testing because it runs entirely on the JVM. Current version: 2.0.0-alpha04. Requires Java 17+.', NULL, 'android', 'compose-screenshot-testing-verify', 'verify', 'plugin', 'android', 'go,java,kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e910e5ae-23f3-4f15-b240-811683207dff', 'Compose Preview Screenshot Testing', 'https://developer.android.com/studio/preview/compose-screenshot-testing', NULL, 'Google''s official screenshot testing tool, announced at Google I/O 2024. Leverages existing `@Preview` annotated composables as test inputs. Runs on the host JVM using LayoutLib. Minimal setup — if you already have `@Preview` functions, those become your screenshot tests automatically. Still experimental (version 0.0.1-alpha08+).', NULL, 'android', 'compose-screenshot-testing-verify', 'verify', 'plugin', 'android', 'go,kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1b6b57bd-3c24-4cb8-869b-eb7c78aacf9a', 'Roborazzi', 'https://github.com/takahirom/roborazzi', 'https://github.com/takahirom/roborazzi', 'JVM screenshot testing built on Robolectric. The most feature-rich option — supports Activity, Fragment, Composable, and interaction-based screenshots (click, scroll, then capture). Integrates with Hilt for dependency injection in tests. Supports time-based captures for animated components via `@RoboComposePreviewOptions`. Auto-generates tests from Compose Previews via ComposablePreviewScanner integration.', NULL, 'android', 'compose-screenshot-testing-verify', 'verify', 'plugin', 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e18ddd8a-1a5f-4d3f-9d6e-8a3a91a61618', 'Showkase', 'https://github.com/airbnb/Showkase', 'https://github.com/airbnb/Showkase', 'Annotation-processor library by Airbnb that creates a component browser app from `@Preview`, `@ShowkaseComposable`, `@ShowkaseColor`, and `@ShowkaseTypography` annotations. Provides a visual catalog of all composables, colors, and typography in a developer build. Integrates with Paparazzi for automatic screenshot testing of every cataloged component. Shows composables in multiple states (dark mode, larger fonts, RTL).', NULL, 'android', 'compose-screenshot-testing-verify', 'verify', NULL, 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7172b874-3f8b-4a95-8967-6c58f6c37e87', 'ComposablePreviewScanner', 'https://github.com/sergio-sastre/ComposablePreviewScanner', 'https://github.com/sergio-sastre/ComposablePreviewScanner', 'Meta-library that scans all `@Preview` composables in your project and feeds them to any screenshot testing library — JVM-based (Paparazzi, Roborazzi) or instrumentation-based (Shot, Dropshots, Android-Testify). Supports `@PreviewParameter`, multi-previews (`@PreviewScreenSizes`, `@PreviewFontScales`, `@PreviewLightDark`, `@PreviewDynamicColors`), and custom multi-previews. Over 150k monthly downloads.', NULL, 'android', 'compose-screenshot-testing-verify', 'verify', NULL, 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a54f902d-25d0-439d-9a85-22a317f9f92d', 'Shot', 'https://github.com/pedrovgs/Shot', 'https://github.com/pedrovgs/Shot', 'Gradle plugin by Karumi built on Facebook''s Screenshot Tests SDK. Instrumentation-based — runs on a device or emulator. Automatically disables flaky components (cursors, scrollbars, animations) before capture. Supports both Android Views and Compose.', NULL, 'android', 'view-system-screenshot-testing-verify', 'verify', 'plugin', 'android', 'kotlin,bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('98ca11ed-829b-4728-b209-6a95e823eceb', 'Dropshots', 'https://github.com/dropbox/dropshots', 'https://github.com/dropbox/dropshots', 'On-device screenshot testing by Dropbox. Unique approach: pushes reference images to the device and performs comparison on-device, making it suitable for validating system integrations like edge-to-edge display on Android 15. Includes `CountValidator` (max pixel differences) and `ThresholdValidator` (percentage tolerance).', NULL, 'android', 'view-system-screenshot-testing-verify', 'verify', 'plugin', 'android', 'kotlin,bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d3b98ffc-c6ff-412a-af92-6bfcdfc068e0', 'Android-Testify', 'https://github.com/ndtp/android-testify', 'https://github.com/ndtp/android-testify', 'Originally by Shopify, now community-maintained. Testify 2.0 separates core screenshot functionality from JUnit4 lifecycle, supporting classic Views, Compose UI, and Surface Views. Includes Gradle plugin for recording/verifying and an IntelliJ/Android Studio plugin for GUI access. Natively supports grouping tests by device characteristics (resolution, orientation, API level, language).', NULL, 'android', 'view-system-screenshot-testing-verify', 'verify', 'plugin', 'android', 'go,kotlin,bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('61957475-7b90-4509-9771-7499b295b1af', 'Compose UI Test', 'https://developer.android.com/develop/ui/compose/testing', NULL, 'Official testing framework for Jetpack Compose. Uses the semantics tree (not the rendered UI) for finding and asserting on nodes. Provides `ComposeTestRule` for setting content and `ComposeContentTestRule` for instrumentation. Finders: `onNodeWithText()`, `onNodeWithContentDescription()`, `onNodeWithTag()`, `onAllNodesWithText()`. Actions: `performClick()`, `performScrollTo()`, `performTextInput()`. Assertions: `assertIsDisplayed()`, `assertExists()`, `assertTextEquals()`, `assertIsEnabled()`.', NULL, 'android', 'ui-testing-frameworks-verify', 'verify', 'cli', 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ac354273-908b-4853-9c92-e14651ac3e88', 'Espresso', 'https://developer.android.com/training/testing/espresso/basics', NULL, 'Google''s UI testing framework for Android Views (2013+). Three core components: `ViewMatchers` (find views: `withId()`, `withText()`, `withTagKey()`), `ViewActions` (perform actions: `click()`, `longClick()`, `scrollTo()`, `typeText()`), `ViewAssertions` (verify state: `matches()`, `doesNotExist()`). Synchronizes automatically with the UI thread — waits for idle before assertions.', NULL, 'android', 'ui-testing-frameworks-verify', 'verify', 'cli', 'android', 'go,kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('27183dc4-bc05-4791-bd77-0dbef9011947', 'UI Automator', 'https://developer.android.com/training/testing/other-components/ui-automator', NULL, 'Cross-app UI testing framework. Unlike Espresso (single-app), UI Automator can interact with any app on the device including system settings, permission dialogs, notifications, and quick settings. Version 2.4 introduces a Kotlin-friendly DSL with predicate-based element finding. Essential for testing system integration points.', NULL, 'android', 'ui-testing-frameworks-verify', 'verify', 'cli', 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c2c64afa-1433-40ee-a864-824fcaa826e1', 'Accessibility Test Framework', 'https://developer.android.com/training/testing/espresso/accessibility-checking', NULL, 'Google''s open-source library that integrates with Espresso to automatically detect accessibility issues during UI testing. Runs checks whenever a `ViewAction` is performed — examines the view and surrounding UI for accessibility violations. Reports issues as ERROR, WARNING, or INFO. One line of code enables it for all existing Espresso tests.', NULL, 'android', 'accessibility-testing-verify', 'verify', NULL, 'android', 'go,kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a29d287a-a9db-4081-b0d3-eb314ddbbdb7', 'Accessibility Scanner', 'https://play.google.com/store/apps/details?id=com.google.android.apps.accessibility.auditor', NULL, 'Standalone Android app by Google that scans any app''s UI for accessibility improvements. Uses ATF under the hood. Does not require source code access — works on any installed app. Highlights issues like missing content descriptions, small touch targets, and low contrast.', NULL, 'android', 'accessibility-testing-verify', 'verify', NULL, 'android', 'go', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c055ba1e-4588-4f1c-9be5-a655cc624de0', 'Compose Semantics Testing', 'https://developer.android.com/develop/ui/compose/testing/semantics', NULL, 'Compose UI tests operate on the semantics tree, which is the same tree used by accessibility services (TalkBack, Switch Access). This means every Compose UI test is implicitly an accessibility test — if a node cannot be found via semantics, it is also invisible to accessibility services. Key properties: `contentDescription` (screen reader labels), `testTag` (test identifiers), `role`, `stateDescription`.', NULL, 'android', 'accessibility-testing-verify', 'verify', 'cli', 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4d7b2ff7-95e2-4379-921d-86fe4bfab92d', 'Screenshotbot', 'https://screenshotbot.io/', NULL, 'CI-integrated screenshot testing platform. Provides a Gradle plugin that auto-detects your screenshot library (Paparazzi, Shot, screenshot-tests-for-android) and uploads screenshots after each CI run. Tracks screenshots per commit across branches — automatically determines the baseline commit for comparison rather than requiring manual golden-image approval. Provides PR notifications when screenshots change. Eliminates the need for Git LFS to store baseline images. Open-source self-hosted option available.', NULL, 'android', 'visual-regression-verify', 'verify', 'plugin', 'android,web', 'go,kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('52a9f039-e1cf-424f-8c78-6703a8182a4f', 'Applitools Eyes', 'https://applitools.com/', NULL, 'Commercial AI-powered visual testing platform. Uses Visual AI (not pixel-by-pixel comparison) to detect meaningful layout and visual changes while ignoring rendering noise. Integrates with Espresso, Appium, and other Android testing frameworks. Cross-platform — can compare Android, iOS, and web screenshots of the same feature.', NULL, 'android', 'visual-regression-verify', 'verify', 'cli', 'ios,android,web', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('19aa4cdd-a236-4c6c-96e2-86a32803521d', 'Visual Regression Tracker', 'https://github.com/Visual-Regression-Tracker/Visual-Regression-Tracker', 'https://github.com/Visual-Regression-Tracker/Visual-Regression-Tracker', 'Open-source, self-hosted visual regression platform. Platform-agnostic — integrates with any test runner that can capture screenshots. Provides baseline management, region ignoring, and history tracking. Docker-based deployment.', NULL, 'android', 'visual-regression-verify', 'verify', 'cli', 'web,docker', NULL, 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a6fed7e4-75f9-483e-91dc-6cea6af4e08b', 'adb screencap', 'https://developer.android.com/tools/adb', NULL, 'Built-in ADB command for capturing device/emulator screenshots. Captures exactly what the user sees, including system UI, status bar, and navigation bar. Fastest way to capture a full-screen screenshot.', NULL, 'android', 'screenshot-capture-comparison-verify', 'verify', NULL, 'android', 'bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('585bbd85-6648-4219-b3fa-5a93dd2ab42a', 'UiDevice.takeScreenshot()', 'https://developer.android.com/reference/androidx/test/uiautomator/UiDevice', NULL, 'Programmatic screenshot capture within instrumentation tests. Captures the full device screen including system UI. Can be called at any point during a UI Automator or Espresso test.', NULL, 'android', 'screenshot-capture-comparison-verify', 'verify', NULL, 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4332e33f-9cf9-49fb-9b47-560b497059ef', 'Compose captureToImage()', 'https://developer.android.com/develop/ui/compose/testing', NULL, 'Compose testing API that captures a specific composable node as an `ImageBitmap`. Unlike full-screen captures, this isolates the exact component under test. Available on `SemanticsNodeInteraction` via the `captureToImage()` extension.', NULL, 'android', 'screenshot-capture-comparison-verify', 'verify', NULL, 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('aa1be19b-52f0-40d2-aec3-aaecc37698b2', 'Bitmap Comparison Approaches', NULL, NULL, 'Android screenshot testing fundamentally works by comparing `Bitmap` objects pixel-by-pixel. Most libraries use this internally but you can also build custom comparisons.', NULL, 'android', 'screenshot-capture-comparison-verify', 'verify', NULL, 'android', NULL, 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('588059b0-c7ae-44ed-933e-faf1d1f360a5', 'Material Design Compliance', 'https://m3.material.io/', NULL, 'Material 3 provides official Figma design kits with 1000+ components. Use these as the source of truth for verifying Compose Material3 implementations. The Figma kit includes component specs, spacing, typography scales, and color system definitions.', NULL, 'android', 'design-verification-verify', 'verify', NULL, 'android', NULL, 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('eba671f5-6549-47a1-9e6c-b5d4c63e488a', 'Relay', 'https://relay.material.io/', NULL, 'Google''s Figma-to-Compose code generation tool. Imported Figma component metadata and generated pixel-perfect Compose code. **Sunset on April 30, 2025.** No longer available for new projects.', NULL, 'android', 'design-verification-verify', 'implement', 'plugin', NULL, 'go', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('15d56980-435b-4819-be93-837bcc091560', 'Figma Design System Compliance Checker', 'https://www.figma.com/community/plugin/1577978298506710437/design-system-compliance-checker', NULL, 'Figma plugin that audits design files for consistency with design system variables. Checks that designs use proper tokens (colors, spacing, typography) rather than hardcoded values. Works with Figma''s variables system.', NULL, 'android', 'design-verification-verify', 'verify', 'plugin', NULL, NULL, 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('adf0f1b8-d639-4715-ad92-336d6f250617', 'Macrobenchmark', 'https://developer.android.com/topic/performance/benchmarking/macrobenchmark-overview', NULL, 'Measures end-user-visible performance: app startup (cold/warm/hot), scroll smoothness, animation frame times, and power consumption. Runs on real devices via instrumentation. Metrics: `StartupTimingMetric`, `FrameTimingMetric`, `TraceSectionMetric`, `PowerMetric`. Can generate and validate Baseline Profiles. Version 3 (2025) includes AI-based Baseline Profile hints, improved Compose LazyColumn/LazyGrid benchmarking, and automatic startup mode detection.', NULL, 'android', 'performance-ui-testing-verify', 'verify', 'plugin', 'android', 'kotlin,bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('aee5409c-072b-40ef-b5eb-a4b736002d29', 'Microbenchmark', 'https://developer.android.com/topic/performance/benchmarking/microbenchmark-overview', NULL, 'Measures isolated code blocks — individual functions, algorithms, data transformations. Runs in a tight loop with JIT warmup to produce stable, repeatable measurements. Useful for verifying that a specific computation (layout calculation, data parsing, image processing) meets performance requirements.', NULL, 'android', 'performance-ui-testing-verify', 'verify', NULL, 'android', 'go,kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('00409f15-9a98-4324-bcf4-e73911cbcc04', 'JankStats', 'https://developer.android.com/topic/performance/jankstats', NULL, 'Runtime library for detecting janky frames in production and development. Built on `FrameMetrics` API (Android 7+). Defines jank as a frame taking 2x the refresh rate duration. Provides a state API for contextualizing jank — attach UI state labels (e.g., "scrolling list", "opening drawer") so jank reports include what the user was doing. Works with Compose via `PerformanceMetricsState`.', NULL, 'android', 'performance-ui-testing-verify', 'verify', NULL, 'android', 'kotlin', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c3687cfc-906a-4e85-aef7-e71f910703ca', 'Compose Compiler Metrics', 'https://developer.android.com/develop/ui/compose/performance/stability/diagnose', NULL, 'The Compose compiler can output stability reports showing which composables are skippable (efficiently recomposable) vs. restartable-but-not-skippable (always recompose). Generates three report types: class stability report, composable restartability/skippability report, and a CSV version. Helps identify unnecessary recompositions caused by unstable parameters.', NULL, 'android', 'performance-ui-testing-verify', 'verify', NULL, 'android', 'kotlin,bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b8fea9cf-1d03-4cde-ae61-ff8b81c2b6fd', 'Layout Inspector', 'https://developer.android.com/develop/ui/compose/tooling/debug', NULL, 'Android Studio tool that shows the Compose component tree with recomposition counts and skip counts for each node. Highlights actively recomposing nodes with a gradient overlay — higher recomposition rates show stronger highlighting. Helps visually identify which composables are recomposing unnecessarily.', NULL, 'android', 'performance-ui-testing-verify', 'verify', NULL, 'android', NULL, 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e4820b41-4b61-4044-9306-54bf0bc33cda', 'Baseline Profiles', 'https://developer.android.com/topic/performance/baselineprofiles', NULL, 'Baseline Profiles tell the Android runtime (ART) which code paths to pre-compile, improving startup time and reducing jank during critical user journeys. Generated by Macrobenchmark test runs that exercise key flows. The profile is bundled in the APK/AAB and used during installation.', NULL, 'android', 'performance-ui-testing-verify', 'verify', 'plugin', 'android', 'kotlin,bash', 'android/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d91b88bc-73a4-41ee-92df-a06f0e0ecc3b', 'SwiftLint', 'https://github.com/realm/SwiftLint', 'https://github.com/realm/SwiftLint', 'The de facto standard linter for Swift. Enforces style and conventions based on community-accepted rules. Supports over 200 configurable rules (lint rules and opt-in analyzer rules). Configuration via `.swiftlint.yml`. Analyzer mode (`swiftlint analyze`) uses the full type-checked AST for deeper static analysis (slower, opt-in). Supports baselines to diff violations against a known state. Swift 6 compatible.', NULL, 'apple', 'linters-formatters-implementverify', 'implement,verify', 'plugin', 'ios,macos,watchos,tvos,visionos,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('86315b5e-a74c-48c8-9354-e068e61b4b52', 'SwiftFormat', 'https://github.com/nicklockwood/SwiftFormat', 'https://github.com/nicklockwood/SwiftFormat', 'Opinionated code formatter that adjusts whitespace, removes redundant syntax (parentheses, `self`, etc.), and enforces consistent style. Over 70 formatting rules. Highly configurable via `.swiftformat` config file. Can infer project style with `--infer-options`. Actively maintained with version 0.55+.', NULL, 'apple', 'linters-formatters-implementverify', 'implement,verify', NULL, 'ios,macos,watchos,tvos,visionos,windows,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0481c120-23e1-4b25-a234-fc01289e3367', 'swift-format', 'https://github.com/swiftlang/swift-format', 'https://github.com/swiftlang/swift-format', 'Apple''s official formatting technology, built on SwiftSyntax. Included in the Swift 6+ toolchain (invoked as `swift format` with a space). Provides both formatting and linting. No official Swift style guide yet -- the style applied is one possibility. Configuration via `.swift-format` JSON file. Used by SourceKit-LSP.', NULL, 'apple', 'linters-formatters-implementverify', 'implement,verify', NULL, 'ios,macos,watchos,tvos,visionos,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('cdd9065b-7546-4a2d-9a96-502454fd19ba', 'Periphery', 'https://github.com/peripheryapp/periphery', 'https://github.com/peripheryapp/periphery', 'Static analysis tool that detects unused Swift code -- classes, structs, protocols, functions, properties, enum cases, function parameters, protocol conformances, and redundant public accessibility. Works by building the project to generate an index store, then constructing an in-memory dependency graph. Version 3.0 added significant improvements. Essential for codebase hygiene.', NULL, 'apple', 'linters-formatters-implementverify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9107ea36-5c09-4ad1-bafc-72743f78b3e7', 'Tailor', 'https://github.com/sleekbyte/tailor', 'https://github.com/sleekbyte/tailor', 'Cross-platform static analyzer and linter for Swift. Written in Java. Supports Swift 2.x/3.x. **Effectively unmaintained** -- last meaningful updates targeted Swift 3.0. Not recommended for new projects; included for historical reference. SwiftLint has fully superseded it.', 'brew install tailor', 'apple', 'linters-formatters-implementverify', 'verify', NULL, 'macos,windows,linux', 'java,swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('77fac6bd-13e4-4e03-a269-0cc9e4a36959', 'Swift Testing', 'https://developer.apple.com/xcode/swift-testing/', NULL, 'Apple''s modern testing framework, introduced at WWDC24, shipping with Swift 6 and Xcode 16+. Uses `@Test` and `@Suite` macros for expressive, Swift-native test declarations. Parameterized tests, traits for configuration, parallel execution by default, full Swift Concurrency integration. Coexists with XCTest -- migrate incrementally. Does **not** yet support UI automation (`XCUIApplication`) or performance metrics (`XCTMetric`); use XCTest for those.', NULL, 'apple', 'testing-frameworks-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('65fcb9db-7678-4f61-b598-4fc71d65e063', 'XCTest', 'https://developer.apple.com/documentation/xctest', NULL, 'Apple''s original testing framework. Provides unit testing (`XCTestCase`), UI testing (`XCUIApplication`), and performance testing (`XCTMetric`, `measure {}`). Mature, stable, universally supported. Still required for UI automation and performance benchmarks. Runs via `xcodebuild test` or `swift test`.', NULL, 'apple', 'testing-frameworks-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6b7c5e18-cae5-4e17-b533-91890bfacc16', 'Quick / Nimble', 'https://github.com/Quick/Quick', 'https://github.com/Quick/Quick', 'BDD-style testing framework (Quick) paired with a matcher framework (Nimble). Quick provides `describe`/`context`/`it` blocks inspired by RSpec. Nimble provides expressive matchers (`expect(x).to(equal(y))`). Quick 7.x and Nimble 14.x are current. Good for teams that prefer BDD-style test organization.', NULL, 'apple', 'testing-frameworks-verify', 'verify', 'cli', 'ios,macos,watchos,tvos,visionos,linux', 'go,swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6355610d-f5db-4b83-9c7e-3942b38f4f4d', 'swift-snapshot-testing', 'https://github.com/pointfreeco/swift-snapshot-testing', 'https://github.com/pointfreeco/swift-snapshot-testing', 'Snapshot testing library that captures and compares artifacts (images, text, JSON, custom formats). Supports Swift Testing (beta) and XCTest. Version 1.17+ adds `withSnapshotTesting` for scoped configuration. Extensible snapshot strategies for SwiftUI views, UIKit views, Codable values, and more. Essential for UI regression testing.', NULL, 'apple', 'testing-frameworks-verify', 'verify', 'cli', 'ios,macos,tvos,linux', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ef7bf048-b340-4e2a-86a3-826d1392a48f', 'ViewInspector', 'https://github.com/nalexn/ViewInspector', 'https://github.com/nalexn/ViewInspector', 'Runtime introspection library for unit testing SwiftUI views. Traverses the compiled view hierarchy to inspect view structures, attributes, modifiers, and trigger callbacks. Two testing surfaces: "outside" (rendered structure) and "inside" (state and injected references). Version 0.10.x is current. Fills the gap left by Apple''s lack of official SwiftUI unit testing support.', NULL, 'apple', 'testing-frameworks-verify', 'verify', 'cli', 'ios,macos,watchos,tvos,visionos,linux', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a21ff91a-9a8a-4a17-8165-d9adcf2fe76e', 'swift-custom-dump', 'https://github.com/pointfreeco/swift-custom-dump', 'https://github.com/pointfreeco/swift-custom-dump', 'Debugging and testing toolkit providing: `customDump()` for pretty-printing any value, `diff()` for visual diffs between values, and `XCTAssertNoDifference` / `expectNoDifference` (Swift Testing) for assertions with rich failure messages. Far superior to `XCTAssertEqual` for complex types. Swift 6 and Swift Testing compatible.', NULL, 'apple', 'testing-frameworks-verify', 'verify', 'cli', 'ios,macos,watchos,tvos,visionos,linux', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8951afb9-8a98-49f6-a9ed-86523adf0e27', 'Sourcery', 'https://github.com/krzysztofzablocki/Sourcery', 'https://github.com/krzysztofzablocki/Sourcery', 'Meta-programming code generator for Swift, built on SwiftSyntax. Uses Stencil, EJS, or Swift templates to generate boilerplate code -- mocks, equatable conformances, enum cases, lenses, and arbitrary patterns. Used in 40,000+ projects (Airbnb, Bumble, NYT). Version 2.3.x is current. Supports daemon mode for live regeneration. Helped push Apple toward derived conformances.', NULL, 'apple', 'code-generation-implement', 'implement', NULL, 'ios,macos,watchos,tvos,visionos,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9b5fb437-62f4-4f26-80de-2764052cf77a', 'SwiftGen', 'https://github.com/SwiftGen/SwiftGen', 'https://github.com/SwiftGen/SwiftGen', 'Generates type-safe Swift code for project resources: asset catalogs (images, colors, symbols, AR resources, data sets), localized strings, fonts, storyboards/XIBs, Core Data models, plists, JSON/YAML files, colors (from text/JSON/XML/.clr), and file/directory structures. Eliminates stringly-typed resource access. Version 6.6.x is current. Customizable via Stencil templates. Configuration via `swiftgen.yml`.', NULL, 'apple', 'code-generation-implement', 'implement', NULL, 'ios,macos,watchos,tvos,visionos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('084bda88-8fa4-47b0-9c5a-94a37bdd559d', 'Needle', 'https://github.com/uber/needle', 'https://github.com/uber/needle', 'Compile-time safe dependency injection framework from Uber. Generates DI code during compilation so missing dependencies fail at build time, not runtime. Core concepts: dependency protocols, components, and child component instantiation. Designed for large-scale apps with complex dependency graphs. Requires both `NeedleFoundation` framework and a code generator binary.', NULL, 'apple', 'code-generation-implement', 'implement', 'cli', 'ios,macos,watchos,tvos,visionos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9e849ec2-1231-4c00-8e53-450e7005570f', 'swift-dependencies', 'https://github.com/pointfreeco/swift-dependencies', 'https://github.com/pointfreeco/swift-dependencies', 'Lightweight dependency management library inspired by SwiftUI''s environment. Uses `@Dependency` macro and Swift Task Locals for context-propagated dependency injection. Version 1.11.x is current. Supports Swift 6.1''s `TestScoping` for reliable test injection. Not a code generator per se, but provides the `@DependencyClient` macro for generating dependency interfaces.', NULL, 'apple', 'code-generation-implement', 'implement', 'cli', 'ios,macos,watchos,tvos,visionos,linux', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('fef8ac2c-198b-4144-bdab-b8123b5e495b', 'Swift Package Manager', 'https://github.com/swiftlang/swift-package-manager', 'https://github.com/swiftlang/swift-package-manager', 'Apple''s official package manager, built into the Swift toolchain and Xcode. Defines dependencies in `Package.swift`. Resolves versions via `Package.resolved`. Swift 6.1+ adds strict mode for tighter version matching, dry-run updates, dependency graph visualization, and package info commands. The standard for modern Swift projects.', NULL, 'apple', 'package-management-implement', 'implement', 'plugin', 'ios,macos,watchos,tvos,visionos,windows,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1827f89d-d80d-4981-868c-5013e2988019', 'CocoaPods', 'https://cocoapods.org/', NULL, 'Legacy dependency manager for Swift and Objective-C. **Trunk goes read-only December 2, 2026.** No new pods can be published after that date. Google dropping CocoaPods support for iOS SDKs after Q2 2026. Migrate to SPM. Still functional for existing projects during transition period.', NULL, 'apple', 'package-management-implement', 'implement', NULL, 'ios,macos,watchos,tvos', 'go,swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('54af004f-68f2-4e4c-af62-3e5002ebca91', 'Mint', 'https://github.com/yonaskolb/Mint', 'https://github.com/yonaskolb/Mint', 'Package manager for installing and running Swift CLI tools. Installs executables from any Swift package with an executable target. Supports multiple versions side-by-side. Central cache. Version 0.18.x is current. Ideal for managing project-specific tool versions (SwiftLint, SwiftFormat, Sourcery, etc.) via a `Mintfile`.', NULL, 'apple', 'package-management-implement', 'implement', 'cli', 'macos,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4cac934d-4bbc-4096-a710-3ac171dde239', 'SwiftLint Analyzer Mode', 'https://github.com/realm/SwiftLint', 'https://github.com/realm/SwiftLint', 'SwiftLint''s `analyze` command performs deeper static analysis using the full type-checked AST from a clean build. Analyzer rules are a separate opt-in rule set (enable via `analyzer_rules` in `.swiftlint.yml`). Slower than lint mode but catches issues that require type information. Requires passing a compiler log from a clean (non-incremental) build.', NULL, 'apple', 'static-analysis-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ef628721-328d-40fe-a071-8a9a281a6c70', 'Semgrep', 'https://semgrep.dev/docs/languages/swift', NULL, 'General-purpose static analysis tool with GA (General Availability) Swift support. 57 Pro rules covering security vulnerability classes (injection, auth, crypto, data exposure). Community Edition supports custom rule writing with Swift pattern matching. Supply Chain scanning supports SPM lockfiles. Pro Engine provides framework-specific analysis not available in CE.', NULL, 'apple', 'static-analysis-verify', 'verify', 'mcp', 'ios,macos,watchos,tvos,visionos,linux', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('43d8c2e1-0f54-475a-97ef-afa81fe6eacb', 'SonarQube', 'https://www.sonarsource.com/knowledge/languages/swift/', NULL, 'Enterprise code quality platform with native Swift analysis. Built directly in Swift using the official compiler and parser. Supports all Swift versions through 6.2. Available in Developer Edition and above (not Community). Open-source alternatives: [sonar-apple](https://github.com/insideapp-oss/sonar-apple) (SonarQube 9.9+) and [sonar-swift](https://github.com/Idean/sonar-swift) (wraps SwiftLint/Tailor).', NULL, 'apple', 'static-analysis-verify', 'verify', 'cli', 'ios,macos,watchos,tvos,visionos', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5bb7d660-e393-4125-bcb4-92c2773c4d90', 'Swift AST Explorer', 'https://swift-ast-explorer.com/', NULL, 'Web-based tool for visualizing the Abstract Syntax Tree of Swift source code. Write Swift on the left, explore the syntax tree on the right. Invaluable for understanding SwiftSyntax node types when writing macros, Sourcery templates, or custom SwiftLint rules. Apache 2.0 licensed.', NULL, 'apple', 'static-analysis-verify', 'plan', 'cli', 'web', 'swift,lua', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0bef1725-3e7e-454e-8700-3fa8e95b6f5d', 'Instruments / xctrace', 'https://developer.apple.com/instruments/', NULL, 'Apple''s profiling suite. The `xctrace` CLI provides full access to Instruments from the command line. Records traces for CPU, memory, SwiftUI view updates, Swift concurrency (Tasks, Actors), animation hitches, disk I/O, network, and more. Xcode 16+ recommends `--instrument` over `--template` for reliable export. Outputs `.trace` files analyzable in Instruments.app or via `xctrace export`.', NULL, 'apple', 'profiling-performance-verify', 'verify', 'mcp', 'ios,macos,watchos,tvos,visionos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4895411e-1593-4de0-9050-9b2d265d7f0f', 'Memory Graph Debugger', 'https://developer.apple.com/documentation/xcode/gathering-information-about-memory-use', NULL, 'Xcode tool that captures a snapshot of the object graph to detect retain cycles, leaked allocations, and abandoned memory. Available via Xcode''s Debug navigator or `leaks` and `heap` command-line tools. Captures `.memgraph` files for offline analysis.', NULL, 'apple', 'profiling-performance-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', 'bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8f818ca2-40f0-442e-a328-830e9c7e758d', 'os_signpost / OSSignposter', 'https://developer.apple.com/documentation/os/ossignposter', NULL, 'Apple''s instrumentation API for marking performance-critical code sections. Place signpost intervals around operations to measure duration in Instruments. Three types: event signposts (point-in-time), interval signposts (begin/end duration), and breadcrumbs (lightweight tracking). Integrated with the unified logging system. OSSignposter is the modern Swift API (replacing C-style `os_signpost`).', 'import os', 'apple', 'profiling-performance-verify', 'implement,verify', 'cli', 'ios,macos,watchos,tvos,visionos', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4d368d45-9517-458f-9b39-af07905e84c5', 'MetricKit', 'https://developer.apple.com/documentation/metrickit', NULL, 'Apple framework for collecting on-device performance and diagnostic data from production apps. Provides `MXMetricPayload` (CPU, memory, disk, network, app launch, animation hitches) and `MXDiagnosticPayload` (crashes, hangs, disk writes). Data delivered daily via `MXMetricManagerSubscriber`. Essential for production performance monitoring.', 'import MetricKit', 'apple', 'profiling-performance-verify', 'verify', 'cli', 'ios,macos,watchos,visionos', NULL, 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('61a8df50-0a23-4968-8174-3be52aa6639e', 'DocC', 'https://github.com/swiftlang/swift-docc', 'https://github.com/swiftlang/swift-docc', 'Apple''s documentation compiler for Swift frameworks and packages. Generates rich API reference documentation and interactive tutorials from doc comments and markdown articles. Powers most of Apple''s developer documentation. Supports customizable symbol access levels, C/C++/Objective-C targets, and static site hosting. swift-docc-plugin integrates with SPM.', NULL, 'apple', 'documentation-implement', 'implement', 'plugin', 'ios,macos,watchos,tvos,visionos,linux', 'swift,c++,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c9681b68-10f7-4b40-a53b-1a2d49e375c8', 'swift-docc-plugin', 'https://github.com/swiftlang/swift-docc-plugin', 'https://github.com/swiftlang/swift-docc-plugin', 'SPM command plugin that integrates Swift-DocC with Swift Package Manager. Enables `swift package generate-documentation` and `swift package preview-documentation` commands. Version 1.4.x is current. Supports generating documentation for multiple targets, customizing access levels, and exporting for static hosting (GitHub Pages, etc.).', NULL, 'apple', 'documentation-implement', 'implement', 'plugin', 'ios,macos,watchos,tvos,visionos,linux', 'swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d7ac61eb-cd5a-415c-afa1-cb007d924cc2', 'jazzy', 'https://github.com/realm/jazzy', 'https://github.com/realm/jazzy', 'Ruby-based documentation generator that produces Apple-style reference docs for Swift and Objective-C. Uses Clang/SourceKit AST or compiled module symbol graphs. Still maintained (last update October 2025) but superseded by DocC for new projects. Useful for projects that need HTML docs without adopting DocC''s format, or for Objective-C-heavy codebases.', NULL, 'apple', 'documentation-implement', 'implement', NULL, 'macos', 'swift,ruby,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f2504def-899c-49a4-b8e7-fc4ab7fb9610', 'Snyk', 'https://docs.snyk.io/supported-languages/supported-languages-list/swift-and-objective-c', NULL, 'Developer security platform with SCA (Software Composition Analysis) and SAST for Swift. SCA scans CocoaPods (`Podfile.lock`) and SPM (`Package.resolved`) dependencies for known vulnerabilities. SAST (Snyk Code) identifies security issues in Swift source code including grpc-swift. Uses `swift package show-dependencies` for SPM dependency graph construction. Requires Swift 3.0+.', NULL, 'apple', 'dependency-security-verify', 'verify', NULL, 'ios,macos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8ae63b42-6497-46bf-ba2f-71bb2d55a81a', 'Semgrep Supply Chain', 'https://semgrep.dev/products/product-updates/swift-support/', NULL, 'Semgrep''s supply chain scanning supports Swift via SPM lockfile analysis (`Package.resolved`). Detects known vulnerabilities in third-party dependencies. Part of the broader Semgrep platform -- combines with Semgrep Code for both dependency and source-level security scanning.', NULL, 'apple', 'dependency-security-verify', 'verify', NULL, 'ios,macos', 'swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('40e07e7c-34d0-485c-94d9-9af8caf65bf1', 'OWASP Dependency-Check', 'https://jeremylong.github.io/DependencyCheck/analyzers/swift.html', NULL, 'Open-source SCA tool with an experimental Swift Package Manager analyzer. Scans `Package.swift` to identify dependencies and map them to known CVEs via the NVD (National Vulnerability Database). Free and open-source alternative to commercial SCA tools. Java-based CLI.', NULL, 'apple', 'dependency-security-verify', 'verify', 'cli', 'macos,linux', 'java,swift,bash', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e501af7f-34ff-4bd1-8655-bc2eaad2fc04', 'Socket.dev', 'https://socket.dev/', NULL, 'Supply chain security platform that proactively detects malicious and compromised packages. **Does not currently support Swift/SPM.** Covers JavaScript (npm), Python (PyPI), Go, and Rust ecosystems. Included here for awareness -- may add Swift support in the future as it expands language coverage. Monitor their announcements.', NULL, 'apple', 'dependency-security-verify', 'implement', NULL, NULL, 'javascript,python,rust,go,java,swift', 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('20bf079d-ccff-4294-adc9-ee9f71849038', 'Quick/Nimble', NULL, NULL, 'Test', NULL, 'apple', 'tool-comparison-quick-reference', 'implement', NULL, NULL, NULL, 'apple/swift-tooling.md');
