INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('56b4be1a-f750-4282-a300-00618ce14a38', 'xctrace', NULL, NULL, 'Profiling', NULL, 'apple', 'tool-comparison-quick-reference', 'implement', NULL, NULL, NULL, 'apple/swift-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b6ac026b-6d5c-444d-a811-3d54037cef49', 'XCUITest', 'https://developer.apple.com/documentation/xctest/ui_tests', NULL, 'Apple''s first-party UI testing framework built into XCTest. Tests run in a separate process from the app, interacting through accessibility APIs. Supports element queries, gestures, screenshots, and assertions.', NULL, 'apple', 'ui-testing-with-xcuitest-verify', 'plan,verify', NULL, 'ios,macos,watchos,tvos,visionos', 'swift', 'apple/ui-verification.md');
