INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0f8a6224-cbcc-449b-b6e9-5edc02db4787', '`XCTAttachment`', NULL, NULL, 'Wraps screenshots or data for inclusion in test results', NULL, 'apple', 'xcuitest-apple-framework', 'verify', NULL, NULL, NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('84c551c4-10de-44ed-92fd-0ae6ede3c300', 'PreviewSnapshots', 'https://github.com/doordash-oss/swiftui-preview-snapshots', 'https://github.com/doordash-oss/swiftui-preview-snapshots', 'Reuse the same view configurations for both Xcode Previews and snapshot tests. Define states once, use them everywhere. Built on top of swift-snapshot-testing.', NULL, 'apple', 'swiftui-preview-testing-verify', 'verify', NULL, 'ios,macos', 'swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('27cb2210-69f6-4324-a5cb-87dd2e056e57', 'Prefire', 'https://github.com/BarredEwe/Prefire', 'https://github.com/BarredEwe/Prefire', 'Automatically generates snapshot tests, playbook views, and accessibility tests from `#Preview` blocks and `PreviewProvider` declarations. Uses swift-snapshot-testing under the hood. Build plugin -- no manual test writing needed.', NULL, 'apple', 'swiftui-preview-testing-verify', 'verify', 'plugin', 'ios', 'swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('168e414a-0229-4542-b3fc-0a7ad5a2f668', 'SnapshotPreviews', 'https://github.com/EmergeTools/SnapshotPreviews', 'https://github.com/EmergeTools/SnapshotPreviews', 'Zero-code snapshot testing from Xcode previews. Discovers all `#Preview` and `PreviewProvider` declarations automatically by parsing Mach-O binary metadata. Generates XCTest tests at runtime. Also provides an in-app Preview Gallery and accessibility audits.', NULL, 'apple', 'swiftui-preview-testing-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', 'swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('35b76b85-27e3-4bb3-b516-146b544b4801', 'performAccessibilityAudit', 'https://developer.apple.com/videos/play/wwdc2023/10035/', NULL, 'Built-in XCTest method (Xcode 15+) that audits any `XCUIElement` for accessibility issues. Fails the test automatically when issues are found. Scoped audits let you check the entire app, a single screen, or an individual component.', NULL, 'apple', 'accessibility-testing-verify', 'verify', 'cli', 'ios,macos,tvos,visionos', 'go,swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1e7ef710-c14a-447d-8793-361b53869cee', 'Accessibility Inspector', 'https://developer.apple.com/documentation/accessibility', NULL, 'Xcode''s built-in tool for inspecting accessibility properties of any element in the simulator or on-device. Shows labels, values, traits, and hierarchy. Includes a one-click audit that runs the same checks as `performAccessibilityAudit`.', NULL, 'apple', 'accessibility-testing-verify', 'verify', 'cli', 'ios,macos,watchos,tvos,visionos', 'bash', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ad747928-5142-4647-b54f-d4653d2fade7', 'AccessibilityPreviewTest', 'https://github.com/EmergeTools/SnapshotPreviews', 'https://github.com/EmergeTools/SnapshotPreviews', 'Runs VoiceOver accessibility audits on all discovered Xcode previews. Subclass `AccessibilityPreviewTest` to automatically audit every preview in your project.', NULL, 'apple', 'accessibility-testing-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d6d186ce-8a39-4fda-83f7-184fc2ef92dd', 'WWDC25: Record, Replay, and Review', 'https://developer.apple.com/videos/play/wwdc2025/344/', NULL, 'New Xcode 17 UI automation features for recording, replaying, and reviewing UI interactions. Includes improved accessibility-driven automation and stable element identification for SwiftUI views.', NULL, 'apple', 'accessibility-testing-verify', 'verify', NULL, 'ios,macos,visionos', 'swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('968b817e-850f-4f5e-bb16-b3179f4fd280', 'Screenshotbot', 'https://screenshotbot.io/', NULL, 'Cloud-hosted visual regression service for iOS, Android, and web. Integrates with CI to compare screenshots across builds, posting diff reports to pull requests (GitHub, GitLab). Stores screenshot history -- no Git LFS needed.', NULL, 'apple', 'visual-regression-verify', 'verify', 'cli', 'ios,android,web', 'swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('72107baa-839f-433d-a682-068ad2e584a5', 'Applitools Eyes', 'https://applitools.com/', NULL, 'AI-powered visual testing platform. Uses Visual AI to detect meaningful visual differences while ignoring rendering noise. Supports design-to-code comparison via Figma plugin. Eyes 10.22 added Storybook and Figma design validation.', NULL, 'apple', 'visual-regression-verify', 'verify', 'plugin', 'ios,android,web', NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3dedcf87-5ff4-4b1b-a05d-7306e4f6fa10', 'Percy', 'https://percy.io/', NULL, 'Visual review platform that captures and compares screenshots across builds. App Percy extends support to native iOS and Android apps on real devices.', NULL, 'apple', 'visual-regression-verify', 'verify', NULL, 'ios,android,web', NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b32c1bdd-a18b-4fe2-848a-fc1dd423d6e8', 'xcparse', 'https://github.com/ChargePoint/xcparse', 'https://github.com/ChargePoint/xcparse', 'Command-line tool for extracting screenshots and code coverage data from Xcode `.xcresult` bundles. Essential for CI pipelines that need to post-process test screenshots.', NULL, 'apple', 'visual-regression-verify', 'verify', NULL, 'macos', 'bash', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('97f3a39c-6140-47d2-ab36-f4ae1b5f920a', 'xcrun simctl', NULL, NULL, 'Apple''s command-line interface for interacting with iOS Simulator. Captures screenshots and records video directly from the simulator process.', NULL, 'apple', 'screenshot-capture-and-comparison-verify', 'verify', NULL, 'ios,watchos,tvos,visionos', 'bash', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('734d90e4-701b-4ad9-ab95-b040e38884dc', 'XCUIScreenshot and XCTAttachment', 'https://developer.apple.com/documentation/xctest/xcuiscreenshot', NULL, 'XCTest APIs for capturing screenshots during UI test execution and attaching them to test results. Screenshots persist in the `.xcresult` bundle.', NULL, 'apple', 'screenshot-capture-and-comparison-verify', 'plan,verify', NULL, 'ios,macos,tvos,visionos', 'swift', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3c7a51e1-6600-4ab5-acde-4e578b0e3a8c', 'MCP iOS Simulator Screenshot', 'https://glama.ai/mcp/servers/@yorifuji/mcp-ios-simulator-screenshot', NULL, 'MCP server that captures iOS Simulator screenshots and saves them to a specified directory. Lightweight, single-purpose tool.', NULL, 'apple', 'screenshot-capture-and-comparison-verify', 'verify', 'mcp', 'ios', NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('94bc793c-3c3c-46a4-a903-576cf7b57aec', 'iOS Simulator MCP', 'https://github.com/whitesmith/ios-simulator-mcp', 'https://github.com/whitesmith/ios-simulator-mcp', 'Full-featured MCP server for iOS Simulator interaction. Screenshots, UI hierarchy inspection, tap/swipe/type gestures, app management, GPS simulation. Uses IDB (Facebook''s iOS Development Bridge) under the hood.', NULL, 'apple', 'screenshot-capture-and-comparison-verify', 'verify', 'mcp', 'ios', 'python,bash', 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b3494f3a-9ac7-4d88-89d9-0f323795c4e0', '`screenshot`', NULL, NULL, 'Captures JPEG screenshot (~2MB max), returns image for visual inspection', NULL, 'apple', 'ios-simulator-mcp-whitesmith', 'verify', NULL, NULL, NULL, 'apple/ui-verification.md');
