INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1a259bfb-8a30-458d-afa4-8d5e4b9cc00c', 'Applitools Eyes Figma Plugin', 'https://applitools.com/docs/eyes/integrations/design-validation/figma-plugin', NULL, 'Export Figma frames as visual baselines, then compare live app screenshots against them. Visual AI detects meaningful differences, filtering out rendering noise and anti-aliasing artifacts.', NULL, 'apple', 'design-verification-verify', 'verify', 'plugin', NULL, NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('78cca7d6-f07f-45db-9301-1f6ed35773a0', 'Apple iOS Design Kit for Figma', 'https://www.figma.com/community/file/1527721578857867021/ios-and-ipados-26', NULL, 'Apple''s official Figma UI kit for iOS and iPadOS 26 (updated March 2026). Includes Liquid Glass components, system controls, and layout templates. Use as a reference to verify your app matches system design patterns.', NULL, 'apple', 'design-verification-verify', 'verify', NULL, 'ios', NULL, 'apple/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e22af64b-cfc3-4ed1-8687-48b2cdecbc6b', 'XCTMetric Framework', 'https://developer.apple.com/documentation/xctest/xctmetric', NULL, 'XCTest performance measurement framework. Wrap code in `measure(metrics:)` blocks to collect CPU, memory, storage, timing, and animation metrics. Baselines are stored per-device and Xcode flags regressions automatically.', NULL, 'apple', 'performance-ui-testing-verify', 'verify', NULL, 'ios,macos,watchos,tvos,visionos', 'go,swift,bash', 'apple/ui-verification.md');
