INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a4eaa1c1-2d54-4e5e-831c-14e6b14b060f', 'dotclaude.com', NULL, NULL, '[dotclaude.com/plugins](https://dotclaude.com/plugins)', NULL, 'claude', 'plugin-registries-directories', 'implement', 'plugin', NULL, NULL, 'claude/plugins-and-skills-catalog.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e615cf44-ec5e-4784-8eb5-e63a7097a904', 'clap', 'https://github.com/clap-rs/clap', 'https://github.com/clap-rs/clap', 'The dominant Rust CLI parsing library. Derive macros (`#[derive(Parser)]`) turn annotated structs into full CLIs with validation, subcommands, shell completions, and auto-generated help. Powers ripgrep, bat, fd, and hundreds of production tools. Current version 4.6.x.', 'cargo add clap --features derive', 'cli', 'rust', 'implement', 'cli', NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('56bd0733-fb27-4fa2-b221-e34bbf86d985', 'argparse', 'https://docs.python.org/3/library/argparse.html', NULL, 'Standard library argument parser. No dependencies, always available. Adequate for simple tools but verbose for complex CLIs.', NULL, 'cli', 'python', 'implement', 'cli', NULL, 'python,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2aa47d6c-4d59-4f22-8845-0dc31c474cc2', 'Click', 'https://click.palletsprojects.com/', NULL, 'Decorator-based CLI framework. Handles nested commands, lazy loading, parameter types, and context passing. ~38.7% of Python CLI projects use Click.', 'pip install click', 'cli', 'python', 'implement', 'cli', NULL, 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('42487c51-db90-4c9f-96b9-800ab420d668', 'Typer', 'https://typer.tiangolo.com/', NULL, 'Built on Click by the FastAPI creator. Uses Python type hints instead of decorators -- function signatures become the CLI interface automatically. Rich integration for colored output.', 'pip install typer[all]', 'cli', 'python', 'implement', 'cli', NULL, 'python,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('96a49a3b-4bb6-4516-b923-6b032e68394d', 'Commander.js', 'https://github.com/tj/commander.js', 'https://github.com/tj/commander.js', 'Lightweight, minimal API. ~500M weekly npm downloads. Excellent TypeScript support. 25ms startup time. Best for simple to moderate CLIs.', 'npm install commander', 'cli', 'nodejs-typescript', 'implement', 'cli', NULL, 'typescript', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ac4ccfd5-bbce-4b10-9d26-36f9c302c1a5', 'yargs', 'https://yargs.js.org/', NULL, 'Feature-rich parsing with middleware, configuration files, and advanced validation. ~30M weekly downloads. Richer than Commander but heavier (48ms startup).', 'npm install yargs', 'cli', 'nodejs-typescript', 'implement', NULL, NULL, 'typescript', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('411c3b29-2eb8-44f7-9227-ece526054ed9', 'oclif', 'https://oclif.io/', NULL, 'Enterprise CLI framework by Salesforce. Plugin architecture, code generation, hooks, and convention-over-configuration. 135ms startup. Best for large multi-command tools.', 'npx oclif generate', 'cli', 'nodejs-typescript', 'implement', 'plugin', NULL, 'typescript', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('27cc8a5b-6097-4e4b-8e3c-118c4162ba02', 'Cobra', 'https://github.com/spf13/cobra', 'https://github.com/spf13/cobra', 'The standard for Go CLIs. Nested commands, auto-help, shell completions, Viper integration for config. Used by kubectl, helm, Hugo. 35k+ GitHub stars.', 'go get -u github.com/spf13/cobra@latest', 'cli', 'go', 'implement', 'cli', NULL, 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('83c77360-d04c-4790-ab69-62a26b8c9db3', 'urfave/cli', 'https://github.com/urfave/cli', 'https://github.com/urfave/cli', 'Zero-dependency alternative. Commands with aliases, shell completion, flexible help. 20k+ GitHub stars. Better for single-command or lightweight tools.', 'go get github.com/urfave/cli/v3', 'cli', 'go', 'implement', 'cli', NULL, 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1b25f5b1-4d13-428a-8ef3-e75694e28770', 'System.CommandLine', 'https://github.com/dotnet/command-line-api', 'https://github.com/dotnet/command-line-api', 'Microsoft''s official CLI parsing library. Heading toward stable 2.0.0 release with .NET 10. 32% smaller than prior betas, 40% faster parsing, NativeAOT support.', 'dotnet add package System.CommandLine --prerelease', 'cli', 'net', 'implement', 'cli', NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9659eabc-c1eb-4996-9655-b263598349e7', 'ArgumentParser', 'https://github.com/apple/swift-argument-parser', 'https://github.com/apple/swift-argument-parser', 'Apple''s official library. Declarative via `@Option`, `@Argument`, `@Flag` property wrappers on `ParsableCommand` structs. Subcommands, validation, shell completions, rich error messages.', NULL, 'cli', 'swift', 'implement', NULL, NULL, 'swift', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2ef3a750-52a7-4b7f-972a-c04f50e94c7f', 'picocli', 'https://picocli.info/', NULL, 'Annotation-based framework supporting Java, Kotlin, Groovy, Scala. ANSI colors, TAB completion, subcommands. GraalVM native-image support for fast startup. Single source file -- can be vendored.', NULL, 'cli', 'java-kotlin', 'implement', 'cli', NULL, 'java,kotlin', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('874765a0-52fa-416c-a8b2-d5327037ac52', 'bats-core', 'https://github.com/bats-core/bats-core', 'https://github.com/bats-core/bats-core', 'Bash Automated Testing System. TAP-compliant. The most popular bash testing framework. Uses `@test` blocks with `run` and assertion helpers. Extensible via bats-assert and bats-support libraries.', 'npm install -g bats', 'cli', 'shell-testing-verify', 'verify', 'cli', NULL, 'bash', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c9b2cd9b-2a51-4b34-9491-2a947754578d', 'shunit2', 'https://github.com/kward/shunit2', 'https://github.com/kward/shunit2', 'xUnit-style framework for Bourne shell. Pure shell -- works on any POSIX shell. Oldest maintained bash test framework. Familiar `setUp`/`tearDown`/`assertEquals` pattern.', 'brew install shunit2', 'cli', 'shell-testing-verify', 'verify', NULL, NULL, 'go,bash', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('70cc2b69-f53a-4a22-9774-91cf0d5a4c70', 'ShellSpec', 'https://shellspec.info/', NULL, 'BDD testing framework. Supports any POSIX shell. Code coverage, mocking, parameterized tests, parallel execution. Most feature-rich shell testing tool.', 'brew install shellspec', 'cli', 'shell-testing-verify', 'verify', NULL, NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f0d3c3b7-fa82-465a-9fb2-7a2120b1178a', 'clitest', 'https://github.com/aureliojargas/clitest', 'https://github.com/aureliojargas/clitest', 'Doctest-style CLI testing. Paste interactive shell sessions as tests -- the tool replays commands and checks output. Can extract tests from Markdown docs. Single POSIX shell script.', NULL, 'cli', 'shell-testing-verify', 'verify', 'cli', NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('816c362d-35b5-4bc9-82d1-9d7f4f797f8f', 'shelltestrunner', 'https://github.com/simonmichael/shelltestrunner', 'https://github.com/simonmichael/shelltestrunner', 'Declarative CLI test runner. Define command, input, expected stdout/stderr, and exit code in simple text files. Cross-platform.', 'brew install shelltestrunner', 'cli', 'shell-testing-verify', 'implement,verify', 'cli', NULL, 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('49dd1e32-4fdc-46eb-8a6a-b36d5ce54fd9', 'ShellCheck', 'https://github.com/koalaman/shellcheck', 'https://github.com/koalaman/shellcheck', 'The standard static analysis tool for shell scripts. Finds bugs, syntax issues, quoting problems, and portability concerns. Outputs JSON, CheckStyle XML, or GCC-style warnings. Written in Haskell.', 'brew install shellcheck', 'cli', 'shell-linting-implementverify', 'implement,verify', NULL, NULL, 'bash', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('95ce144c-0d12-4eee-b4f5-976c1d240a56', 'shellharden', 'https://github.com/andsens/shellharden', 'https://github.com/andsens/shellharden', 'Syntax highlighter and automated rewriter. Semi-automatically rewrites scripts to ShellCheck conformance, focusing on proper quoting.', 'cargo install shellharden', 'cli', 'shell-linting-implementverify', 'implement,verify', NULL, NULL, 'go,bash', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e4c3cf18-4e9b-4584-8274-d45a24b5a0f5', 'bashate', 'https://github.com/openstack/bashate', 'https://github.com/openstack/bashate', 'Code style enforcement for bash, modeled on pycodestyle (PEP 8). Checks indentation, line length, and basic style rules.', 'pip install bashate', 'cli', 'shell-linting-implementverify', 'implement,verify', NULL, NULL, 'bash', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1eff3aed-c3f2-4403-9441-18d50d708696', 'insta', 'https://insta.rs/', NULL, 'Snapshot testing library for Rust. Captures values as YAML/JSON/TOML snapshots, stores them alongside tests, and diffs on change. `cargo-insta` CLI for reviewing and accepting snapshots. `insta-cmd` extension for testing CLI output directly.', 'cargo add insta --dev', 'cli', 'output-testing-snapshots-verify', 'verify', 'cli', NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8c05a099-5fd4-4cbb-90a6-13ff9561da7a', 'pexpect', 'https://github.com/pexpect/pexpect', 'https://github.com/pexpect/pexpect', 'Python module for controlling interactive programs in a pseudo-terminal. Spawn a process, send input, wait for expected output patterns. The Python equivalent of TCL Expect.', 'pip install pexpect', 'cli', 'output-testing-snapshots-verify', 'verify', 'cli', NULL, 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c6ee02d5-5a99-4694-98c0-bbd669885c16', 'Expect', 'https://core.tcl-lang.org/expect/', NULL, 'Original TCL-based tool for automating interactive programs. Spawns processes and scripts interactions via `expect`/`send` pairs. Mature, Unix-standard.', 'brew install expect', 'cli', 'output-testing-snapshots-verify', 'verify', 'cli', NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('fefbd20f-d07e-4640-b351-ee4033b8e4ea', 'assert_cmd', 'https://github.com/assert-rs/assert_cmd', 'https://github.com/assert-rs/assert_cmd', 'Rust crate for testing CLI binaries. Builds the binary, runs it with specified args, and asserts on exit code, stdout, and stderr. Often paired with `predicates` crate.', 'cargo add assert_cmd --dev', 'cli', 'output-testing-snapshots-verify', 'verify', 'cli', NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8a7afb20-e116-4a83-ac08-17232d1a537f', 'Approval Tests', 'https://approvaltests.com/', NULL, 'Multi-language approval testing pattern. Captures output, compares to approved baseline. Available for Java, C#, Python, JavaScript, and more.', 'pip install approvaltests', 'cli', 'output-testing-snapshots-verify', 'verify', 'cli', NULL, 'javascript,python,go,java,c#', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6545a40a-5da2-48f2-bada-60d6450e6879', 'Bubble Tea', 'https://github.com/charmbracelet/bubbletea', 'https://github.com/charmbracelet/bubbletea', 'TUI framework based on The Elm Architecture. Model/Update/View pattern with a managed event loop. Powers lazygit, Soft Serve, glow. Part of the Charm ecosystem (Lip Gloss for styling, Bubbles for components).', 'go get github.com/charmbracelet/bubbletea', 'cli', 'go', 'implement', NULL, NULL, 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1e28085d-16d1-40e5-9712-aefd2774e99c', 'Ratatui', 'https://ratatui.rs/', NULL, 'Community fork of tui-rs. Immediate-mode rendering with widgets and a flexible layout engine. Developer controls the event loop. Multiple backend choices (crossterm, termion, termwiz). Used by ATAC, rlt, and many others.', 'cargo add ratatui crossterm', 'cli', 'rust', 'implement', NULL, NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('620a9209-c77b-408a-88b9-e959f4b65103', 'Textual', 'https://textual.textualize.io/', NULL, 'Modern TUI framework inspired by web development. CSS-like styling, reactive state, comprehensive widget library (buttons, inputs, tables, trees). Async-first. Can also render in a web browser. 250k+ PyPI downloads in Q1 2025.', 'pip install textual', 'cli', 'python', 'implement', NULL, 'web', 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('fc7ac8b6-6c33-4c3a-9a78-3d1d97676d02', 'Ink', 'https://github.com/vadimdemedes/ink', 'https://github.com/vadimdemedes/ink', 'React for CLIs. Uses React components and Flexbox layout to build interactive terminal UIs. Full TypeScript support. Ships with `create-ink-app` scaffolding.', 'npm install ink react', 'cli', 'nodejs', 'implement', 'hook', NULL, 'typescript', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6aa87f5b-6865-4d2f-9b58-64b6bf23e74e', 'neo-blessed', 'https://github.com/embbnux/neo-blessed', 'https://github.com/embbnux/neo-blessed', 'Community fork of blessed. Widget-based TUI with layouts, mouse support, and terminal abstraction. Less actively maintained than Ink but offers a broader widget set.', 'npm install neo-blessed', 'cli', 'nodejs', 'implement', NULL, NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0f010974-f230-49d2-8a3c-c4a643b766ba', 'Spectre.Console', 'https://spectreconsole.net/', NULL, 'Rich console output library for .NET. Tables, trees, panels, progress bars, live rendering, prompts, and 24-bit color. .NET Foundation backed, 7k+ GitHub stars. Also includes Spectre.Console.Cli for argument parsing.', 'dotnet add package Spectre.Console', 'cli', 'net', 'implement', 'cli', NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bd84bae4-f9a9-455f-8fac-378f1298a775', 'VHS', 'https://github.com/charmbracelet/vhs', 'https://github.com/charmbracelet/vhs', 'Declarative terminal recorder by Charmbracelet. Write `.tape` scripts that type commands, wait for output, and capture GIF/MP4/WebM/PNG. CI-friendly for automated demo generation. Can produce `.txt`/`.ascii` golden files for regression testing.', 'brew install vhs', 'cli', 'tui-testing-recording-verify', 'verify', 'cli', 'web', 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bd143fc9-5098-4f80-a0b7-9f1da0f72456', 'tui-test', 'https://github.com/microsoft/tui-test', 'https://github.com/microsoft/tui-test', 'End-to-end terminal testing framework by Microsoft. Snapshot comparison, element visibility assertions, color assertions. Cross-platform (macOS, Linux, Windows) with multiple shell support.', 'npm install @vscode/tui-test', 'cli', 'tui-testing-recording-verify', 'verify', NULL, 'macos,windows,linux', NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5ec4d5c1-5ef9-41b3-b099-03a7f62e890a', 'Textual Pilot', 'https://textual.textualize.io/guide/testing/', NULL, 'Built-in headless testing for Textual apps. `run_test()` returns a `Pilot` object for simulating keyboard/mouse input without a real terminal. Fast, deterministic, CI-ready.', 'pip install textual', 'cli', 'tui-testing-recording-verify', 'verify', 'cli', NULL, 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0ac3d172-9e83-4725-8c48-13c994084250', 'teatest', 'https://github.com/charmbracelet/x/tree/main/exp/teatest', 'https://github.com/charmbracelet/x/tree/main/exp/teatest', 'Testing library for Bubble Tea programs. Sends messages to a Bubble Tea model and captures output for golden-file comparison.', 'go get github.com/charmbracelet/x/exp/teatest', 'cli', 'tui-testing-recording-verify', 'verify', NULL, NULL, 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c4bff96e-6c79-42b3-b577-a2497d7a2c62', 'cobra/doc', 'https://pkg.go.dev/github.com/spf13/cobra/doc', 'https://pkg.go.dev/github.com/spf13/cobra/doc', 'Built-in doc generation for Cobra CLIs. Outputs man pages, Markdown, reStructuredText, or YAML from command definitions. Used by Kubernetes, Hugo.', 'go get github.com/spf13/cobra', 'cli', 'documentation-generation-implement', 'implement', 'cli', 'kubernetes', 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('99f42ed4-ec82-4ef6-b7c4-2768c5f5607a', 'cobraman', 'https://github.com/rayjohnson/cobra-man', 'https://github.com/rayjohnson/cobra-man', 'Enhanced doc generator for Cobra using Go templates. Supports troff, mdoc, and Markdown output with full template customization.', 'go get github.com/rayjohnson/cobra-man', 'cli', 'documentation-generation-implement', 'implement', NULL, NULL, 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('dcc28fdc-1c97-4176-b0dc-2d474e7ade33', 'scdoc', 'https://git.sr.ht/~sircmpwn/scdoc', NULL, 'Minimal man page generator. Markdown-inspired syntax purpose-built for man pages (not actual Markdown). <1000 lines of C99, zero dependencies, 78 KiB static binary.', 'brew install scdoc', 'cli', 'documentation-generation-implement', 'implement', NULL, NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2c8f63c3-198d-4bbe-b2ae-334803991136', 'ronn-ng', 'https://github.com/apjanke/ronn-ng', 'https://github.com/apjanke/ronn-ng', 'Converts Markdown to roff man pages and HTML. Active fork of the original ronn. Markdown-based authoring with man-page extensions.', 'gem install ronn-ng', 'cli', 'documentation-generation-implement', 'implement', NULL, NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('dd072e49-9461-441e-bd2b-b1629149ace4', 'Pandoc', 'https://pandoc.org/', NULL, 'Universal document converter. Converts Markdown to man pages (among 50+ formats). Heavyweight but extremely flexible.', 'brew install pandoc', 'cli', 'documentation-generation-implement', 'implement', NULL, NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('776c51ed-09aa-4a7f-9ddc-7d4d1afe1e11', 'clap_mangen', 'https://github.com/clap-rs/clap/tree/master/clap_mangen', 'https://github.com/clap-rs/clap/tree/master/clap_mangen', 'Man page generator for clap-based Rust CLIs. Generates roff from clap''s command definitions at build time.', 'cargo add clap_mangen --build', 'cli', 'documentation-generation-implement', 'implement', 'cli', NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8cbe4acf-2562-4927-ae8c-25aa9e9acd89', 'help2man', 'https://www.gnu.org/software/help2man/', NULL, 'Generates man pages from `--help` and `--version` output of any CLI tool. Works with any language.', 'brew install help2man', 'cli', 'documentation-generation-implement', 'implement', 'cli', NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5b760096-e741-4e31-a3b9-bc2d00f8d30a', 'cargo publish', 'https://doc.rust-lang.org/cargo/commands/cargo-publish.html', NULL, 'Publish Rust crates to crates.io. Handles versioning, dependencies, and metadata. Users install via `cargo install`.', NULL, 'cli', 'language-native-package-registries', 'implement,verify', NULL, NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('582baa62-f0c6-4d6a-be57-308153458d08', 'npm publish', 'https://docs.npmjs.com/cli/v11/commands/npm-publish', NULL, 'Publish Node.js packages to npm. Set `"bin"` in `package.json` for CLI tools. Users install via `npm install -g`. Supports trusted publishing via GitHub Actions OIDC.', NULL, 'cli', 'language-native-package-registries', 'implement,verify', 'cli', NULL, 'typescript,javascript,rust,java', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('48fdeaa0-b05f-45e3-a769-4fc5248ee756', 'pip / PyPI', 'https://packaging.python.org/', NULL, 'Publish Python packages to PyPI. Use `[project.scripts]` in `pyproject.toml` for CLI entry points. Users install via `pip install` or `pipx install`.', 'pip install build twine', 'cli', 'language-native-package-registries', 'implement,verify', 'cli', NULL, 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b25ffc25-7a30-410e-bcb7-bdb19014cd2c', 'GoReleaser', 'https://goreleaser.com/', NULL, 'Release automation for Go. Cross-compiles, creates GitHub/GitLab releases, generates Homebrew taps, Docker images, Snap packages, and checksums. Transitioning from Homebrew formula to cask for binary distribution.', 'brew install goreleaser', 'cli', 'binary-packaging-single-executable-tools', 'implement,verify', NULL, 'docker', 'go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('164b41f7-ab83-4bda-8314-951bf0b7b3b9', 'PyInstaller', 'https://pyinstaller.org/', NULL, 'Bundles Python apps into standalone executables. Analyzes imports, collects dependencies, embeds interpreter. ~4.7M monthly PyPI downloads. Supports Python 3.8-3.14. Does not cross-compile.', 'pip install pyinstaller', 'cli', 'binary-packaging-single-executable-tools', 'implement,verify', 'cli', NULL, 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a368cbd0-21f8-4293-aa48-23ed79af81c5', 'Node.js SEA', 'https://nodejs.org/api/single-executable-applications.html', NULL, 'Built-in single executable application support in Node.js core (v19.7+, improving rapidly). Replaces deprecated `pkg`. Uses `--build-sea` flag with JSON config.', NULL, 'cli', 'binary-packaging-single-executable-tools', 'implement,verify', NULL, NULL, 'javascript,java', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('23740f45-6c5e-4ded-bd3c-012aff3f9258', 'nexe', 'https://github.com/nexe/nexe', 'https://github.com/nexe/nexe', 'Creates single executables from Node.js apps. Alternative to the now-deprecated pkg. Compiles Node.js from source for the target platform.', 'npm install -g nexe', 'cli', 'binary-packaging-single-executable-tools', 'implement,verify', 'cli', NULL, 'javascript,java', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('03783ba2-06a5-4c8e-8bf0-d5717b859d0e', 'Homebrew Tap', 'https://docs.brew.sh/Taps', NULL, 'Create a custom Homebrew tap repository (`homebrew-tap`) with formula files. Users install via `brew install user/tap/tool`. Works for any language that produces binaries.', NULL, 'cli', 'homebrew-distribution', 'implement,verify', NULL, NULL, NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b7fb9c3d-2d55-4b46-a719-6b04639ae70c', 'hyperfine', 'https://github.com/sharkdp/hyperfine', 'https://github.com/sharkdp/hyperfine', 'Statistical CLI benchmarking tool written in Rust. Automatic warmup, outlier detection, parameterized benchmarks, shell startup correction. Exports to CSV, JSON, Markdown. The standard tool for CLI performance measurement.', 'brew install hyperfine', 'cli', 'performance-benchmarking-verify', 'verify', 'cli', NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4a56a2f5-8211-474a-a58e-c09a17714162', 'time (GNU)', 'https://www.gnu.org/software/time/', NULL, 'Measures wall clock, user CPU, and system CPU time. Built into every Unix system. `/usr/bin/time -v` (GNU) gives detailed stats including max RSS memory.', 'brew install gnu-time', 'cli', 'performance-benchmarking-verify', 'verify', 'cli', 'macos,linux', NULL, 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c81a9da8-1ec6-49ea-b405-78a0ca6087c9', 'Valgrind (Massif)', 'https://valgrind.org/docs/manual/ms-manual.html', NULL, 'Heap memory profiler. Tracks memory allocations over time. Useful for finding memory bloat in long-running CLI tools. Linux-only.', 'brew install valgrind', 'cli', 'performance-benchmarking-verify', 'verify', 'cli', 'linux', 'rust,c++', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ed2012f4-63c1-4e1a-a7be-22555892bdb4', 'cargo flamegraph', 'https://github.com/flamegraph-rs/flamegraph', 'https://github.com/flamegraph-rs/flamegraph', 'Generates flamegraphs for Rust binaries. Identifies hot paths in CLI startup or processing.', 'cargo install flamegraph', 'cli', 'performance-benchmarking-verify', 'verify', 'cli', NULL, 'rust,go', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9ee375a3-0b50-4d36-9764-757a393ea1c3', 'py-spy', 'https://github.com/benfred/py-spy', 'https://github.com/benfred/py-spy', 'Sampling profiler for Python. Attaches to running processes without code changes. Generates flamegraphs. Low overhead.', 'pip install py-spy', 'cli', 'performance-benchmarking-verify', 'verify', 'cli', NULL, 'python', 'cli/cli-development-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0fbd7ff0-4baa-40f9-a30d-4cb718ad1301', 'Great Expectations (GX)', 'https://greatexpectations.io/', NULL, 'Full-featured data validation framework with 300+ built-in expectations. v1.15+ (March 2026). Define expectations as verifiable assertions, run them as Checkpoints against any data source. ExpectAI (Feb 2025) auto-suggests validation rules. Supports Pandas, Spark, SQL backends.', 'pip install great-expectations', 'data-ml', 'dataframe-schema-validation', 'verify', 'cli', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('77a76311-7ec3-4130-8c88-f595a6ccf34a', 'Pandera', 'https://pandera.readthedocs.io/', NULL, 'Type-safe DataFrame validation for Pandas, Polars, PySpark, and Ibis backends. v0.25+ adds Ibis support (Snowflake, BigQuery). Declarative schemas with mypy integration, statistical hypothesis testing (t-tests, chi-square), and built-in coercion. Leverages Polars lazy API for optimization.', 'pip install pandera', 'data-ml', 'dataframe-schema-validation', 'verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('92cfd63c-e9eb-4286-ae1f-dcbfbdfdb57d', 'Pydantic', 'https://docs.pydantic.dev/', NULL, 'The most widely used Python data validation library. v2.12+ with Rust-powered core for speed. Validates arbitrary Python objects via type hints. Strict and lax modes. Powers FastAPI, LangChain, and most modern Python frameworks.', 'pip install pydantic', 'data-ml', 'dataframe-schema-validation', 'verify', NULL, NULL, 'python,rust', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9643ca58-8d38-4a2f-b4c3-a160b518e4de', 'Cerberus', 'https://docs.python-cerberus.org/', NULL, 'Lightweight, extensible dictionary/document validation. Schema-driven with custom rules. Good for validating JSON configs, API payloads, and YAML-derived dicts. Less opinionated than Pydantic.', 'pip install cerberus', 'data-ml', 'dataframe-schema-validation', 'verify', 'cli', NULL, 'python,go', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2c26a49a-9ef1-4827-838a-f2342b0e3724', 'dbt tests', 'https://docs.getdbt.com/docs/build/data-tests', NULL, 'Built-in data tests for dbt models: `unique`, `not_null`, `accepted_values`, `relationships`. Run with every `dbt build` or `dbt test`. The foundation of SQL-layer data quality.', 'pip install dbt-core dbt-<adapter>', 'data-ml', 'sql-dbt-validation', 'verify', 'cli', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('92a68797-6bb2-4a2f-a5b2-496656bf663b', 'dbt-expectations', 'https://github.com/calogica/dbt-expectations', 'https://github.com/calogica/dbt-expectations', 'Port of Great Expectations patterns to dbt macros. 60+ tests covering schema validation, regex, time-series freshness, statistical distributions, outlier detection, and cross-column logic. Maintained by Datadog.', NULL, 'data-ml', 'sql-dbt-validation', 'verify', 'cli', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('57aa11ae-4460-48e4-989f-9281d58dbdfa', 'Soda', 'https://soda.io/', NULL, 'Data quality platform with open-source CLI (Soda Core) and commercial cloud. SodaCL provides 50+ built-in checks in a YAML-based DSL. v4.0 (Jan 2026) adds AI-assisted check generation. Works with any SQL warehouse.', 'pip install soda-core-<adapter>', 'data-ml', 'sql-dbt-validation', 'verify', 'cli', NULL, 'go,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('36472ff0-1bef-46f3-b7d4-79e922e9a7b9', 'nbstripout', 'https://github.com/kynan/nbstripout', 'https://github.com/kynan/nbstripout', 'Git filter that strips cell outputs and metadata from notebooks before commit. Keeps diffs clean and prevents large binary outputs from bloating the repo. Install once per repo as a git filter.', 'pip install nbstripout && nbstripout --install', 'data-ml', 'notebook-tooling-implementverify', 'implement,verify', 'hook', NULL, 'go', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('30c632e4-bd73-4acf-b5e1-f79e5b4076d7', 'nbqa', 'https://github.com/nbQA-dev/nbQA', 'https://github.com/nbQA-dev/nbQA', 'Run any Python linter or formatter on Jupyter notebooks. Supports ruff, black, isort, mypy, pyright, and custom tools. Extracts code cells, runs the tool, and reinjects results.', 'pip install nbqa', 'data-ml', 'notebook-tooling-implementverify', 'implement,verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e4a46e9a-c4e5-49f7-bc29-bd2b59d78775', 'jupytext', 'https://jupytext.readthedocs.io/', NULL, 'Bidirectional sync between `.ipynb` and plain-text formats (`.py`, `.md`, `.Rmd`). Edit notebooks as scripts, review diffs as code. Supports percent format, light format, and MyST Markdown.', 'pip install jupytext', 'data-ml', 'notebook-tooling-implementverify', 'implement,verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('852ad571-11a9-4172-ac13-1e1f80c82b5a', 'papermill', 'https://papermill.readthedocs.io/', NULL, 'Parameterized notebook execution. Inject parameters into tagged cells and execute notebooks programmatically. Produces output notebooks with full execution results. Used in production ML pipelines at Netflix.', 'pip install papermill', 'data-ml', 'notebook-tooling-implementverify', 'implement,verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4d511d46-696f-406a-b5e6-7745fc5354c2', 'nbconvert', 'https://nbconvert.readthedocs.io/', NULL, 'Convert notebooks to HTML, PDF, LaTeX, Markdown, Python scripts, and more. v7.17 (2026). Can also execute notebooks during conversion. Supports custom Jinja2 templates.', 'pip install nbconvert', 'data-ml', 'notebook-tooling-implementverify', 'implement,verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7e6f26af-c2eb-44be-bacb-37dfe619f291', 'nbformat', 'https://nbformat.readthedocs.io/', NULL, 'Programmatic notebook manipulation library. Create, modify, and validate `.ipynb` files from Python. The canonical API for notebook structure -- more stable than parsing JSON directly.', 'pip install nbformat', 'data-ml', 'notebook-tooling-implementverify', 'implement,verify', NULL, NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('878ff172-69b6-47c2-9db1-45d2aa9d1933', 'Airflow test utils', 'https://airflow.apache.org/docs/apache-airflow/stable/best-practices.html', NULL, 'DagBag import validation, `dag.test()` for local execution, task-level unit tests with pytest. Airflow 3.0 (April 2025) improved local dev experience. DagBag checks catch import errors; `dag.test()` supports regex-based task skipping for sensor bypass.', 'pip install apache-airflow', 'data-ml', 'pipeline-orchestration-testing-verify', 'verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2874fbc7-2944-43ba-a105-692d96653e3f', 'Dagster testing', 'https://docs.dagster.io/guides/test', NULL, 'First-class testing built into the framework. Test individual assets, ops, and resources with `materialize_to_memory()`. No external infrastructure needed. Components framework GA (Oct 2025), enhanced catalog in v1.7. Fastest local dev feedback loop of any orchestrator.', 'pip install dagster dagster-webserver', 'data-ml', 'pipeline-orchestration-testing-verify', 'verify', 'cli', 'web', NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('aae4e9eb-2c85-4550-87b5-d2fba11472d1', 'Prefect testing', 'https://docs.prefect.io/v3/how-to-guides/workflows/test-workflows', NULL, '`prefect_test_harness` context manager for testing flows against a temporary database. Call `.fn()` on tasks to test the underlying function directly. `disable_run_logger()` for clean test output.', 'pip install prefect', 'data-ml', 'pipeline-orchestration-testing-verify', 'verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f7eaa36d-2ae2-4e24-86c1-84380bb5ce8b', 'Luigi test helpers', 'https://luigi.readthedocs.io/', NULL, 'Target-based testing: verify task output files exist and contain expected data. Tasks are plain Python classes testable with pytest. Idempotent design means completed tasks won''t re-execute. Spotify no longer actively maintains Luigi; community-driven since ~2023.', 'pip install luigi', 'data-ml', 'pipeline-orchestration-testing-verify', 'verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e549bd70-5b91-4aeb-a415-6543f22b4a8f', 'dbt test / dbt build', 'https://docs.getdbt.com/docs/build/data-tests', NULL, 'Run data tests after model materialization. `dbt build` runs models + tests in dependency order. `dbt test --select model_name` for targeted testing. Integrates with dbt-expectations for advanced checks.', 'pip install dbt-core dbt-<adapter>', 'data-ml', 'pipeline-orchestration-testing-verify', 'verify', 'cli', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('45e6184a-78bc-479c-8e09-12a04998349a', 'pytest + Hypothesis', 'https://hypothesis.readthedocs.io/', NULL, 'Property-based testing for Python. Generates random inputs matching a specification and finds edge cases automatically. Research shows property-based tests find ~50x more mutations than average unit tests. Actively maintained with regular releases through 2026.', 'pip install hypothesis pytest', 'data-ml', 'model-testing-validation-verify', 'verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d4acd6c9-cebf-43fb-b723-14d76c2d3d06', 'deepchecks', 'https://deepchecks.com/open-source/', NULL, 'ML validation suite: 40+ built-in checks for data integrity, train/test comparison, model performance, and feature drift. Automated version comparisons and root cause analysis. Separate monitoring package for production.', 'pip install deepchecks', 'data-ml', 'model-testing-validation-verify', 'verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('408d45e2-ef8e-4132-8c0f-adc1887622f5', 'Evidently', 'https://www.evidentlyai.com/', NULL, 'Data and model monitoring framework. Drift detection (dataset, feature, target), model performance tracking, and interactive HTML reports. Strong on interpretation and usability. Open-source core with hosted dashboard option.', 'pip install evidently', 'data-ml', 'model-testing-validation-verify', 'verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1abf106b-a7b3-490f-b6f8-66a3cc50123e', 'whylogs', 'https://whylabs.ai/whylogs', NULL, 'Lightweight data profiling and logging. Creates statistical profiles of datasets (approximate histograms, cardinality, distributions) without storing raw data. Privacy-preserving by design. WhyLabs platform (open-sourced under Apache 2.0, Jan 2025) adds real-time monitoring.', 'pip install whylogs', 'data-ml', 'model-testing-validation-verify', 'verify', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('22f32334-cbf2-481a-a350-5cc08b585c7d', 'MLflow model validation', 'https://mlflow.org/', NULL, 'Model registry with validation workflows. Tag model versions with validation status, use aliases (champion/challenger) for deployment promotion. v3.0 extends to GenAI/agents. Integrates with Unity Catalog on Databricks.', 'pip install mlflow', 'data-ml', 'model-testing-validation-verify', 'verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9dbe0be6-10a7-49d4-8810-9029e6a9f224', 'SQLFluff', 'https://www.sqlfluff.com/', NULL, 'Modular SQL linter and auto-formatter. Supports 20+ SQL dialects, Jinja templating, and dbt. Monthly releases. Configurable rules with `.sqlfluff` config file. The standard SQL linter for data teams.', 'pip install sqlfluff', 'data-ml', 'sql', 'implement,verify', 'hook', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('360653ca-ecc4-4dd2-b077-a8a94182c2e6', 'sqlfmt', 'https://sqlfmt.com/', NULL, 'Opinionated SQL formatter (not a linter). Zero config beyond line length. Powers the dbt Cloud IDE "Format" button. Lexer-based, not AST-based -- fast but less precise than SQLFluff for linting.', 'pip install shandy-sqlfmt', 'data-ml', 'sql', 'implement,verify', 'cli', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('679ab782-4fea-45f6-a3af-c3635922fddf', 'Ruff', 'https://docs.astral.sh/ruff/', NULL, 'Extremely fast Python linter and formatter, written in Rust. v0.15+ (March 2026). 800+ built-in rules replacing Flake8, Black, isort, pydocstyle, pyupgrade, and autoflake. 10-100x faster than the tools it replaces. The new default for Python projects.', 'pip install ruff', 'data-ml', 'python', 'implement,verify', 'hook', NULL, 'python,rust,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ebf27e79-1c21-47c3-9645-663861b86950', 'mypy', 'https://mypy-lang.org/', NULL, 'The original Python type checker. Reference implementation for the typing spec. v1.18+ brought ~40% speed improvements. Comprehensive but slower on large codebases. Best for CI pipelines where correctness matters more than speed.', 'pip install mypy', 'data-ml', 'python', 'implement,verify', 'cli', NULL, 'python,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('07e01168-cff8-45d7-9906-cbd216c37820', 'Pyright', 'https://github.com/microsoft/pyright', 'https://github.com/microsoft/pyright', 'Fast Python type checker written in TypeScript. Powers Pylance in VS Code. 3-5x faster than mypy on large codebases. Checks all code regardless of annotations. Implements typing features ahead of other checkers.', 'pip install pyright', 'data-ml', 'python', 'implement,verify', 'cli', NULL, 'typescript,python,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('13e3f619-1663-4274-9743-fd96fb5eeb52', 'ty', 'https://docs.astral.sh/ty/', NULL, 'Astral''s new Python type checker, written in Rust. Beta (Dec 2025). 10-60x faster than mypy/Pyright without caching. Built-in language server with code navigation, completions, and auto-import. From the makers of Ruff and uv. Astral joined OpenAI (Codex team) in March 2026.', 'pip install ty', 'data-ml', 'python', 'implement,verify', 'cli', NULL, 'python,rust,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('efe5f43a-5925-465b-9ca1-f781b916d40e', 'yamllint', 'https://yamllint.readthedocs.io/', NULL, 'YAML linter checking syntax validity plus cosmetic issues (line length, trailing spaces, indentation, key repetition). v1.38 (2026). Configurable rules via `.yamllint` config.', 'pip install yamllint', 'data-ml', 'config-files', 'implement,verify', 'hook', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c4337a42-d272-4d98-a9d5-164026789558', 'uv', 'https://docs.astral.sh/uv/', NULL, 'Extremely fast Python package manager and environment tool, written in Rust by Astral. Replaces pip, virtualenv, pyenv, and pip-tools in a single binary. 10-100x faster than pip. Handles Python version management, lockfiles, and virtual environments. The new default for Python projects in 2026.', NULL, 'data-ml', 'environment-management-implement', 'implement', 'cli', NULL, 'python,rust', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('76433c3b-45be-4bb9-9b58-353e1cec7cf5', 'conda / mamba', 'https://docs.conda.io/', NULL, 'Cross-language environment manager essential for ML workloads with C/C++/CUDA dependencies that pip cannot handle. Mamba is a C++ reimplementation with parallel downloads and faster solving. Most data science teams use mamba (or micromamba for containers) instead of base conda in 2026.', 'brew install micromamba', 'data-ml', 'environment-management-implement', 'implement', 'cli', NULL, 'python,c++', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('58ba0c36-f224-475f-823f-b6782e6401da', 'Poetry', 'https://python-poetry.org/', NULL, 'Python dependency management with lockfile support and PyPI publishing. Mature, well-documented, large ecosystem. Still the smoothest workflow for library publishing to PyPI, though uv is catching up.', 'pip install poetry', 'data-ml', 'environment-management-implement', 'implement', 'cli', NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('df6c88ce-76c2-44d1-b4a3-29e48be1b283', 'Docker', 'https://www.docker.com/', NULL, 'Container-based environment isolation. The standard for reproducible ML environments in 2026, with 92% developer adoption. Docker Desktop 4.60+ adds GPU acceleration and tighter AI framework integration. 35% faster deployments and 50% fewer environment bugs in CI/CD pipelines.', 'brew install --cask docker', 'data-ml', 'environment-management-implement', 'implement', 'cli', 'macos,docker', NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('23741b07-9899-4379-ae67-49c4ea7dde26', 'Dev Containers', 'https://containers.dev/', NULL, 'Standardized development container specification. Define `.devcontainer/devcontainer.json` for reproducible, IDE-integrated environments. 64% of developers use non-local environments as primary setup in 2026 (up from 36% in 2024).', NULL, 'data-ml', 'environment-management-implement', 'implement', NULL, NULL, 'python', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d414d61d-2cb7-4f3a-b9d8-0ec29c7295d3', 'MLflow', 'https://mlflow.org/', NULL, 'Open-source AI/ML platform. Experiment tracking, model registry, model serving, and evaluation. v3.0 extends to GenAI agents. Backed by Databricks. The open-source standard with the largest community. Unity Catalog integration for enterprise governance.', 'pip install mlflow', 'data-ml', 'experiment-tracking-implementverify', 'implement,verify', 'cli', NULL, 'go,lua', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('99424859-de9a-4a24-9a62-2cff9c96da47', 'Weights & Biases (W&B)', 'https://wandb.ai/', NULL, 'Developer-first experiment tracking with best-in-class visualization. Real-time dashboards, hyperparameter sweeps, artifact versioning, and team collaboration. Vertically integrated with CoreWeave GPU cloud. The default for teams prioritizing developer experience.', 'pip install wandb', 'data-ml', 'experiment-tracking-implementverify', 'implement,verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('acbe7e42-0734-4f3f-9059-74319acf1ea7', 'DVC', 'https://dvc.org/', NULL, '"Git for data" -- version control for datasets and models alongside code. Stores data in remote storage (S3, GCS, Azure) with lightweight pointer files in Git. DVCLive for experiment tracking. Acquired by lakeFS (Nov 2025), remains open source.', 'pip install dvc', 'data-ml', 'experiment-tracking-implementverify', 'implement,verify', 'cli', 'azure', NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d2ce7702-2c8b-487d-a56a-7a5f7dc19672', 'ClearML', 'https://clear.ml/', NULL, 'All-in-one open-source MLOps platform: experiment tracking, data versioning, pipeline orchestration, and model serving in one package. Auto-logs metrics, hyperparameters, model checkpoints, stdout, and system resources with minimal code changes.', 'pip install clearml', 'data-ml', 'experiment-tracking-implementverify', 'implement,verify', 'cli', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3d944558-da64-4860-b5f9-365b80f2e83c', 'Feast', 'https://feast.dev/', NULL, 'Open-source feature store for ML. Manages feature engineering pipelines, serves features for training and inference, and ensures consistency between offline (batch) and online (real-time) feature access. Community plugins for DataHub and Amundsen integration.', 'pip install feast', 'data-ml', 'feature-stores', 'plan', 'plugin', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2a8f98e7-3f7c-4bd0-ac0b-4e102fdb345b', 'DataHub', 'https://datahubproject.io/', NULL, 'The most actively maintained open-source data catalog in 2026. Metadata platform with fine-grained lineage, governance, 70+ connectors, and a modern UI. Pre-release v1.4.0. Strong roadmap and large community. Recommended over alternatives for new projects.', NULL, 'data-ml', 'data-catalogs', 'plan', NULL, 'docker', 'go', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e29b5539-266d-456a-ba89-697f0c24278d', 'Amundsen', 'https://www.amundsen.io/', NULL, 'Open-source data catalog originally from Lyft. Search-based discovery with PageRank-style relevance. Integrates with Feast. **Caution:** No active roadmap as of 2025-2026; development has stagnated. Not recommended for new production deployments.', NULL, 'data-ml', 'data-catalogs', 'plan', NULL, 'docker', NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4620d616-9ba3-48c7-8de7-758389e6c632', 'Apache Atlas', 'https://atlas.apache.org/', NULL, 'Metadata management and governance for Apache Hadoop ecosystem. v2.4.0 (Jan 2025), v2.5.0 planned with Trino extractor and PostgreSQL backend. Integrates with Apache Ranger for access control. Best fit for Hadoop-native stacks.', NULL, 'data-ml', 'data-catalogs', 'plan', NULL, NULL, 'go,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('90b60238-9305-4fe2-a690-f766e407f568', 'OpenMetadata', 'https://open-metadata.org/', NULL, 'Rising open-source metadata platform with 84+ connectors, data quality, lineage, and governance. Active development and growing community. Strong alternative to DataHub with a more modern UI.', NULL, 'data-ml', 'data-catalogs', 'plan', NULL, 'docker', 'go', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('882c44f6-d3c6-46ea-a737-25b575d51d14', 'Jupyter MCP Server', 'https://github.com/datalayer/jupyter-mcp-server', 'https://github.com/datalayer/jupyter-mcp-server', 'MCP server for interacting with Jupyter notebooks in any JupyterLab environment. Real-time cell control, smart execution, instant visibility of changes, and automatic error recovery.', 'pip install jupyter-mcp-server', 'data-ml', 'mcp-servers', 'implement', 'mcp', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9bf2713b-6c15-4136-99a4-7537cadb1ffb', 'PostgreSQL MCP', 'https://github.com/aftabbs/postgresql-mcp-server', 'https://github.com/aftabbs/postgresql-mcp-server', 'Query databases, inspect schemas, and assist with writing migrations. Claude translates natural language to SQL and explains results. Configurable read/write permissions.', NULL, 'data-ml', 'mcp-servers', 'plan', 'mcp', NULL, 'sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f7dd0f0a-b0b5-4dde-b50c-e7619ac6ae22', 'Supabase MCP', 'https://supabase.com/docs/guides/getting-started/mcp', NULL, 'MCP server for Supabase projects. Query tables, manage auth, inspect storage, and work with edge functions.', NULL, 'data-ml', 'mcp-servers', 'implement', 'mcp', NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('63f3141c-6de8-4a4c-b5bd-7285bfec8cca', 'SQLite MCP', 'https://github.com/ergut/sqlite-mcp-server', 'https://github.com/ergut/sqlite-mcp-server', 'Lightweight MCP server for SQLite databases. Read/write access, schema inspection, and query execution. Good for local development and testing.', NULL, 'data-ml', 'mcp-servers', 'implement', 'mcp', NULL, 'go,sql', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('86099898-7c1f-4b4e-b460-8e5f0b0193a9', 'Python LSP (Pylance/Pyright)', NULL, NULL, 'Language server providing completions, type checking, go-to-definition, and refactoring for Python. Claude Code''s built-in Python support uses these under the hood.', NULL, 'data-ml', 'language-tooling', 'implement', NULL, NULL, 'python,go', 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d702335c-3e94-4ea2-9af4-e113c9125c23', 'Ruff LSP', 'https://docs.astral.sh/ruff/editors/', NULL, 'Ruff''s built-in language server for real-time linting and formatting feedback. Integrated into VS Code, Neovim, and other editors.', 'pip install ruff', 'data-ml', 'language-tooling', 'implement', NULL, NULL, NULL, 'data-ml/data-pipeline-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2ce7de61-87bf-49fa-b55b-b32c6f2244ba', 'wait-for-it', 'https://github.com/vishnubob/wait-for-it', 'https://github.com/vishnubob/wait-for-it', 'Also listed under Health Check Tools. Use these to verify dependent services (database, cache, message queue) are reachable before the application starts accepting traffic.', NULL, 'infrastructure', 'dependency-connectivity-checks', 'verify', NULL, 'docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('90cd49db-0a8a-4e4e-b3fb-05618c2758fa', 'dockerize', 'https://github.com/jwilder/dockerize', 'https://github.com/jwilder/dockerize', 'Go utility that waits for services (TCP, HTTP, Unix socket) and renders templates. More capable than wait-for-it with HTTP health check support.', 'brew install dockerize', 'infrastructure', 'wait-for-readiness-scripts', 'verify', 'cli', 'docker', 'go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e7eedd7b-cb2f-4c4f-9f21-2b46ac47f5fa', 'wait-on', 'https://www.npmjs.com/package/wait-on', NULL, 'Node.js utility that waits for files, ports, sockets, and HTTP(S) resources. Supports TCP, HTTP HEAD/GET, file existence, and socket checks.', 'npm install -g wait-on', 'infrastructure', 'wait-for-readiness-scripts', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9996d03b-bf05-445a-abfe-984741931094', 'Docker HEALTHCHECK', 'https://docs.docker.com/reference/dockerfile/#healthcheck', NULL, 'Built-in Docker instruction that runs a command inside the container at intervals to verify health. Combined with `depends_on: condition: service_healthy` in Compose, replaces external wait scripts entirely.', NULL, 'infrastructure', 'docker-health-checks', 'verify', NULL, 'docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c04b1920-122a-49d2-af74-64da556376da', 'UptimeRobot', 'https://uptimerobot.com/', NULL, 'Free-tier uptime monitoring (50 monitors) with 5-minute checks. Supports HTTP, ping, port, and keyword monitoring. Status pages included. Founded 2010, one of the most established services.', 'curl -X POST https://api.uptimerobot.com/v2/newMonitor -d "api_key=...&url=..."', 'infrastructure', 'uptime-endpoint-monitoring', 'verify', NULL, 'web', 'go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5f4a5095-95e6-4b4c-b982-33de1f02bfc6', 'Better Stack', 'https://betterstack.com/uptime', NULL, 'All-in-one monitoring platform: uptime checks every 30 seconds from multiple locations, incident management, status pages, and on-call scheduling. More complete than UptimeRobot.', NULL, 'infrastructure', 'uptime-endpoint-monitoring', 'verify', 'cli', 'web', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3c907024-4d5e-48ec-8061-b5cd0e9caa88', 'Pingdom', 'https://www.pingdom.com/', NULL, 'SolarWinds uptime and performance monitoring from 100+ global locations. Synthetic transaction checks simulate user journeys (login, checkout). Real User Monitoring (RUM) included.', NULL, 'infrastructure', 'uptime-endpoint-monitoring', 'verify', NULL, 'web', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('80117659-7461-47f2-b38b-21c3d348d6fe', 'Uptime Kuma', 'https://github.com/louislam/uptime-kuma', 'https://github.com/louislam/uptime-kuma', 'Self-hosted open-source monitoring tool. Supports HTTP, TCP, DNS, Docker, and push monitors. Clean UI with status pages. 60k+ GitHub stars.', 'docker run -d -p 3001:3001 louislam/uptime-kuma', 'infrastructure', 'uptime-endpoint-monitoring', 'verify', NULL, 'docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('632912ca-d82c-4a76-b08a-f38712957649', 'Healthchecks.io', 'https://healthchecks.io/', NULL, 'Cron job and heartbeat monitoring. Services ping a unique URL at expected intervals; if a ping is missed, alerts fire. Open source, self-hostable.', 'docker run healthchecks/healthchecks', 'infrastructure', 'uptime-endpoint-monitoring', 'verify', NULL, 'docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('78b3dc15-d909-4658-adb6-73bce63ec5d1', 'Playwright', 'https://playwright.dev/', NULL, 'Microsoft''s cross-browser automation framework. 78k+ GitHub stars, 45% adoption among QA professionals in 2026. Supports Chromium, Firefox, WebKit. Fastest execution of the major E2E frameworks.', 'npm install -D @playwright/test && npx playwright install', 'infrastructure', 'browser-based-smoke-tests', 'verify', 'cli', 'web', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('75f3a8ad-e2e8-4ee3-a310-ff0c3e5cd703', 'Cypress', 'https://www.cypress.io/', NULL, 'Developer-friendly E2E framework with time-travel debugging and automatic waiting. Superior debugging experience with DOM snapshots at each step.', 'npm install -D cypress', 'infrastructure', 'browser-based-smoke-tests', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4a7032fd-94dc-4ce4-af13-c2eb90072e0a', 'Newman', 'https://github.com/postmanlabs/newman', 'https://github.com/postmanlabs/newman', 'Runs Postman collections from the command line. Export your Postman smoke test collection and run it in CI/CD. Supports environment files and test assertions.', 'npm install -g newman', 'infrastructure', 'api-script-based-smoke-tests', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9a5a3f51-52de-4f34-8094-16e6a111e71c', 'curl', 'https://curl.se/', NULL, 'Universal HTTP clients for scripting smoke checks. curl is pre-installed everywhere; httpie offers a more readable syntax. Both support headers, auth, timing, and response validation.', 'pip install httpie', 'infrastructure', 'api-script-based-smoke-tests', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e2c77624-e7c7-4c1d-aca4-289033dd9fc6', 'k6', 'https://grafana.com/docs/k6/latest/', NULL, 'Grafana''s load testing tool, excellent for smoke tests at low VU counts. Write tests in JavaScript, get structured metrics output. Can verify response times stay under thresholds.', 'brew install k6', 'infrastructure', 'api-script-based-smoke-tests', 'verify', 'cli', NULL, 'javascript,go,java', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b3447715-746c-4cc6-88f9-f587b5827fb8', 'Pester', 'https://pester.dev/', NULL, 'The ubiquitous test framework for PowerShell. Used for infrastructure smoke tests on Windows/Azure: verify services are running, ports are open, configs are correct. Supports the Operation Validation Framework (OVF).', NULL, 'infrastructure', 'infrastructure-smoke-tests', 'verify', 'cli', 'windows,azure', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a16d72a7-d00d-4016-8b4f-d280a839de73', 'Terratest', 'https://github.com/gruntwork-io/terratest', 'https://github.com/gruntwork-io/terratest', 'Go library for writing automated tests against real infrastructure. First-class support for Terraform, Packer, Docker, Kubernetes, AWS, GCP, Azure. Deploys real resources, validates behavior, then tears them down. End-to-end acceptance testing, not unit testing.', 'go get github.com/gruntwork-io/terratest/modules/terraform', 'infrastructure', 'infrastructure-testing-verify', 'verify', NULL, 'aws,gcp,azure,docker,kubernetes', 'go,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('cebdd9fa-60e9-482b-a852-c0b916b1283b', 'Argo Rollouts', 'https://argoproj.github.io/rollouts/', NULL, 'Kubernetes controller providing advanced deployment strategies: canary with analysis, blue-green, and experimentation. Integrates with ingress controllers and service meshes for traffic shaping. Queries metrics providers (Prometheus, Datadog, CloudWatch) to drive automated promotion or rollback.', NULL, 'infrastructure', 'canary-deployment', 'verify', 'cli', 'kubernetes', 'go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('63666e50-6c5e-464d-8b1d-a03aa5274245', 'Flagger', 'https://flagger.app/', NULL, 'Kubernetes operator for automated canary deployments. Integrates with Istio, Linkerd, App Mesh, NGINX, Contour, and Gloo. Runs canary analysis using Prometheus, Datadog, or CloudWatch metrics to determine promotion or rollback.', NULL, 'infrastructure', 'canary-deployment', 'verify', 'cli', 'kubernetes', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('35c4f259-336e-4130-8b5d-27d1a805e018', 'AWS CodeDeploy', 'https://aws.amazon.com/codedeploy/', NULL, 'Managed deployment service supporting canary (two-increment traffic shift), linear (fixed % every N minutes), and all-at-once strategies for EC2, ECS, and Lambda. Automatic rollback based on CloudWatch alarms.', NULL, 'infrastructure', 'canary-deployment', 'verify', 'cli', 'aws', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0804682b-619f-48da-afe0-d9f84623c83d', 'LaunchDarkly', 'https://launchdarkly.com/', NULL, 'Enterprise feature management platform. Sub-millisecond flag evaluation, advanced targeting rules, percentage rollouts, kill switches. The most widely adopted commercial solution.', 'npm install launchdarkly-node-server-sdk', 'infrastructure', 'feature-flags-for-progressive-rollout', 'verify', NULL, NULL, 'lua', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9565bd89-9782-4815-b56a-8ad54b51cf54', 'Unleash', 'https://www.getunleash.io/', NULL, 'Leading open-source feature management platform. Gradual rollouts, kill switches, user segmentation. Self-hostable with a managed cloud option.', 'docker run -p 4242:4242 unleashorg/unleash-server', 'infrastructure', 'feature-flags-for-progressive-rollout', 'verify', 'cli', 'docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('eb900adf-ac7f-4bb2-9917-901c2c2a78c0', 'Flagsmith', 'https://flagsmith.com/', NULL, 'Open-source feature flag platform with remote configuration. Supports web, mobile, and server-side SDKs. Granular feature control with real-time updates.', NULL, 'infrastructure', 'feature-flags-for-progressive-rollout', 'verify', 'cli', 'web,docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ef8d26c2-44cf-4bb0-8402-ab3a384f6fe3', 'Kubernetes Service Switching', 'https://kubernetes.io/docs/concepts/services-networking/service/', NULL, 'Native Kubernetes blue-green via label selectors. Deploy green with new labels, update Service selector to point to green, keep blue running for rollback. No extra controllers needed.', NULL, 'infrastructure', 'blue-green-deployment', 'verify', NULL, 'kubernetes', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9bda104a-3468-49a5-be05-75d26ab369a8', 'Devtron', 'https://devtron.ai/', NULL, 'Kubernetes-native DevOps platform with UI-based blue-green deployment. Handles environment provisioning, traffic switching, and instant rollback without scripts.', NULL, 'infrastructure', 'blue-green-deployment', 'verify', NULL, 'web,kubernetes', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e2e8710b-aa1d-4239-8efd-10c94f43259a', 'kubectl rollout', 'https://kubernetes.io/docs/reference/kubectl/generated/kubectl_rollout/', NULL, 'Built-in Kubernetes rollback commands. `kubectl rollout undo` reverts to the previous revision; `--to-revision=N` targets a specific revision. `kubectl rollout history` shows revision history. `kubectl rollout status` monitors progress.', NULL, 'infrastructure', 'kubernetes-rollback', 'verify', 'cli', 'kubernetes', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('474d52f7-0fd5-4c4b-bbf6-afc859ca800b', 'Helm rollback', 'https://helm.sh/docs/helm/helm_rollback/', NULL, 'Rolls back a Helm release to a previous revision. Helm maintains release history with all manifests, making rollback deterministic.', 'brew install helm', 'infrastructure', 'kubernetes-rollback', 'verify', 'cli', NULL, 'go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7a7279fb-450d-40d3-9585-2bfa47cd99f0', 'Terraform', 'https://www.terraform.io/', NULL, 'Infrastructure-as-code with state tracking. Rollback is a roll-forward: revert the code change and re-apply. `terraform state` commands allow manual state manipulation for recovery. Remote state backends (S3, GCS) provide versioning for state file recovery.', 'brew install terraform', 'infrastructure', 'infrastructure-rollback', 'plan,verify', 'cli', NULL, 'terraform', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2cc19b58-b0fb-4f03-bd09-7e91b5e6c926', 'Pulumi', 'https://www.pulumi.com/', NULL, 'Infrastructure-as-code using general-purpose languages (TypeScript, Python, Go, C#). Stack history provides full rollback: `pulumi stack history` and targeted updates.', 'brew install pulumi', 'infrastructure', 'infrastructure-rollback', 'plan,verify', 'cli', NULL, 'typescript,python,go,c#', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('acc9e0d7-19e6-4678-9abb-7235f651261a', 'Flyway', 'https://flywaydb.org/', NULL, 'SQL-based database migration tool. Undo migrations (file prefix `U`) available in Enterprise edition. Community edition supports clean + re-migrate for non-production. As of 2025, only Community and Enterprise editions exist (Teams discontinued).', 'brew install flyway', 'infrastructure', 'database-migration-rollback', 'verify', 'cli', NULL, 'sql', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3cc393e7-be3d-4a44-a7ff-7b6cb657a668', 'Liquibase', 'https://www.liquibase.com/', NULL, 'Database schema change management with built-in rollback support. Supports XML, YAML, JSON, and SQL changelogs. Liquibase 5.0 (September 2025) requires Java 17+. Rollback-one-changeset available in paid tiers; Community supports tag-based rollback.', 'brew install liquibase', 'infrastructure', 'database-migration-rollback', 'verify', 'cli', NULL, 'java,sql', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2652e978-4556-4a9e-ab15-25a8f385754b', 'Alembic', 'https://alembic.sqlalchemy.org/', NULL, 'Migration tool for Python/SQLAlchemy. Supports upgrade and downgrade operations per revision. Each migration file has both `upgrade()` and `downgrade()` functions.', 'pip install alembic', 'infrastructure', 'database-migration-rollback', 'verify', 'cli', NULL, 'python,sql', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ddf31658-4d48-4568-956e-e900b592f7f2', 'Prisma Migrate', 'https://www.prisma.io/migrate', NULL, 'Schema-first migrations for TypeScript/Node.js. Prisma 7 (late 2025) dropped the Rust engine for pure TS. No built-in rollback command; rollback strategy is creating a new migration that reverses changes, or using `prisma db execute` for manual SQL.', 'npm install prisma', 'infrastructure', 'database-migration-rollback', 'verify', 'cli', NULL, 'typescript,rust,sql', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('19a12fca-c456-4dea-a41d-0ceabcc17c11', 'Checkly', 'https://www.checklyhq.com/', NULL, 'Developer-focused synthetic monitoring using Playwright scripts. Monitor APIs and browser flows as code. Tests run from 20+ global locations. Integrates with CI/CD via the Checkly CLI.', 'npm install -g checkly', 'infrastructure', 'synthetic-monitoring-verify', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b20edefc-cd8d-4a28-9703-ba1fab19e02e', 'Datadog Synthetic Tests', 'https://docs.datadoghq.com/synthetics/', NULL, 'Enterprise synthetic monitoring with API tests, browser tests (no-code recorder), and multi-step API tests. AI anomaly detection, self-healing tests, 1000+ integrations. Correlates synthetic results with traces and logs.', 'curl -X POST "https://api.datadoghq.com/api/v1/synthetics/tests/trigger"', 'infrastructure', 'synthetic-monitoring-verify', 'verify', NULL, 'web', 'terraform', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f8be6277-28bf-44f5-9734-1287087497e1', 'Grafana Synthetic Monitoring', 'https://grafana.com/docs/grafana-cloud/testing/synthetic-monitoring/', NULL, 'Proactive endpoint monitoring using Prometheus Blackbox exporter probes. Pre-configured sensitivity tiers: High (5% probe failure for 5m), Medium (10%), Low (25%). Available in Grafana Cloud with configurable check types (HTTP, DNS, TCP, ping).', NULL, 'infrastructure', 'monitoring-observability-setup-verify', 'verify', NULL, NULL, NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5bf4b7c4-c797-4b69-ad1a-c72f19acaed5', 'Pingdom Transaction Tests', 'https://www.pingdom.com/', NULL, 'Synthetic transaction monitoring that simulates user journeys (login, checkout, form submission) from 100+ global locations. Part of the SolarWinds platform.', NULL, 'infrastructure', 'synthetic-monitoring-verify', 'verify', NULL, 'web', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9dd68437-d008-469f-b09d-2d756b82376d', 'Grafana Loki', 'https://grafana.com/oss/loki/', NULL, '"Prometheus for logs." Indexes metadata (labels) not full text, making it cost-effective at scale. Alerting rules can fire on log patterns (error spikes, new exception types). Pairs with Promtail or Grafana Agent for log collection.', NULL, 'infrastructure', 'log-analysis', 'verify', 'agent', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('dd007851-35cf-49f9-b6cc-a0df8bedd253', 'Sentry', 'https://sentry.io/', NULL, 'Error tracking platform that groups errors by root cause, shows first/last seen, and tracks error frequency. SDKs for every major language. Release tracking shows which deploy introduced which errors.', 'npm install @sentry/node', 'infrastructure', 'log-analysis', 'verify', NULL, NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3aecaf94-cfd6-4e9a-941b-37d50444a680', 'Datadog Log Management', 'https://docs.datadoghq.com/logs/', NULL, 'Centralized logging with real-time search, pattern detection, and anomaly alerts. Log-based metrics let you create monitors on error rates without custom instrumentation.', NULL, 'infrastructure', 'log-analysis', 'verify', 'agent', NULL, 'bash', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('81a87c4c-e422-41d6-a0fa-a079938eed5e', 'Prometheus', 'https://prometheus.io/', NULL, 'Open-source metrics collection and alerting. PromQL queries define alert conditions (latency P99, error rate, saturation). Alertmanager handles routing, grouping, silencing, and notification (Slack, PagerDuty, email).', 'brew install prometheus', 'infrastructure', 'metric-monitoring-alerting', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d070700a-213c-4956-815f-65b578caa747', 'Grafana', 'https://grafana.com/', NULL, 'Visualization and alerting dashboard. Unified alerting supports Prometheus, Loki, and other data sources. Alert rules can trigger on metric thresholds, log patterns, or composite conditions.', 'brew install grafana', 'infrastructure', 'metric-monitoring-alerting', 'verify', NULL, 'docker', 'terraform', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('45ed2d44-7e48-4ff6-8b4b-ddb0ffc08cab', 'PagerDuty', 'https://www.pagerduty.com/', NULL, 'Incident management platforms that receive alerts from monitoring tools, manage on-call schedules, and escalate. PagerDuty supports automated runbooks for common remediation.', NULL, 'infrastructure', 'metric-monitoring-alerting', 'verify', 'hook', 'web', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('77aa4e41-2bca-48cf-9330-7301576a93fc', 'Rundeck', 'https://www.rundeck.com/', NULL, 'Open-source runbook automation. Define operational procedures as jobs with steps, run them on-demand or triggered by alerts. Supports node filtering, approval workflows, and audit logging.', 'brew install rundeck', 'infrastructure', 'automated-runbooks', 'verify', 'hook', 'web,docker', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b9ba30eb-ef99-4e9e-8e9a-df2e1aa52319', 'incident.io', 'https://incident.io/', NULL, 'Incident management with automated workflows. Can auto-detect deployment-related incidents, run diagnostic steps, and execute remediation. Integrates with Slack for collaborative response.', NULL, 'infrastructure', 'automated-runbooks', 'verify', NULL, 'web', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('780c58d3-25a3-4685-8545-1e625312fdb4', 'testssl.sh', 'https://testssl.sh/', NULL, 'Comprehensive bash-based TLS/SSL scanner. Tests ciphers, protocols, vulnerabilities (Heartbleed, ROBOT, CCS injection), and certificate details. Works on any port, not just 443. Runs locally -- safe for internal/staging environments. Machine-readable output (CSV, JSON, HTML).', 'brew install testssl', 'infrastructure', 'ssltls-certificate-verification-verify', 'verify', 'cli', NULL, 'bash', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b1d34252-7391-4ece-825b-abc4417bcd87', 'SSLyze', 'https://github.com/nabla-c0d3/sslyze', 'https://github.com/nabla-c0d3/sslyze', 'Python-based SSL/TLS scanner. Tests against Mozilla''s recommended TLS configurations (modern, intermediate, old). Battle-tested on hundreds of thousands of servers daily. Can run from CI/CD pipelines.', 'pip install sslyze', 'infrastructure', 'ssltls-certificate-verification-verify', 'verify', 'cli', NULL, 'python', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('37c27845-c39e-4001-bb7d-0afee81516c5', 'SSL Labs API', 'https://www.ssllabs.com/ssltest/', NULL, 'Qualys free SSL server test. The industry standard for public-facing TLS assessment. Grades A+ through F. API available for automation but rate-limited.', 'curl "https://api.ssllabs.com/api/v3/analyze?host=example.com&startNew=on"', 'infrastructure', 'ssltls-certificate-verification-verify', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e3186660-9c08-4fae-9087-73a0f530c086', 'certbot', 'https://certbot.eff.org/', NULL, 'Let''s Encrypt client with certificate management. `certbot certificates` shows installed certs and expiry dates. Post-deploy, verify renewed certs are correctly served.', 'pip install certbot', 'infrastructure', 'ssltls-certificate-verification-verify', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('dacbf8ae-7ddc-4c64-b0ab-167071374387', 'cert-manager', 'https://cert-manager.io/', NULL, 'Kubernetes-native certificate management. Automatically provisions and renews TLS certificates from Let''s Encrypt, HashiCorp Vault, Venafi, and more. Certificate resources show status.', NULL, 'infrastructure', 'ssltls-certificate-verification-verify', 'verify', 'cli', 'kubernetes', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('82fabc0d-ae0f-47c1-9b88-90f23add419c', 'dig', 'https://man.openbsd.org/dig.1', NULL, 'DNS lookup utility. Query any record type (A, AAAA, CNAME, MX, TXT, SRV) against specific nameservers. Shows full DNS response including TTL and authority section.', 'brew install bind', 'infrastructure', 'dns-verification', 'verify', 'cli', 'macos', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('73ea682e-a279-4060-84bc-eb8223ee1773', 'nslookup', 'https://man.openbsd.org/nslookup.1', NULL, 'Simpler DNS query tool. Less powerful than dig but available everywhere including Windows.', NULL, 'infrastructure', 'dns-verification', 'verify', 'cli', 'windows', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d3e693dd-65d0-44f7-b28d-d280bba0a65b', 'dog', 'https://github.com/ogham/dog', 'https://github.com/ogham/dog', 'Modern DNS client with colorized output, JSON support, and DNS-over-HTTPS/TLS. A friendlier alternative to dig.', 'brew install dog', 'infrastructure', 'dns-verification', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6e69f826-5f6b-4a9f-ad58-2cfbd3dac80f', 'mtr', 'https://github.com/traviscross/mtr', 'https://github.com/traviscross/mtr', 'Combines traceroute and ping in a single tool. Shows packet loss and latency at each hop. Essential for diagnosing routing issues after infrastructure changes.', 'brew install mtr', 'infrastructure', 'network-diagnostics', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('82588825-3d50-41c3-b16c-58f2b7559a87', 'curl timing', 'https://curl.se/', NULL, 'curl''s `-w` flag exposes detailed timing breakdown: DNS lookup, TCP connect, TLS handshake, time to first byte (TTFB), and total time. Essential for performance regression detection.', 'curl -o /dev/null -s -w "dns:%{time_namelookup} connect:%{time_connect} ttfb:%{time_starttransfer} total:%{time_total}\n" https://example.com', 'infrastructure', 'network-diagnostics', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2e1927c5-3761-4ad7-b44f-4a8275bcdc18', 'hey', 'https://github.com/rakyll/hey', 'https://github.com/rakyll/hey', 'Simple HTTP load generator (formerly boom). Written in Go. Quick way to verify a service handles expected load after deploy.', 'brew install hey', 'infrastructure', 'http-benchmark-tools', 'verify', 'cli', NULL, 'go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9af4992b-8f48-479b-b875-bf5469ca5a62', 'wrk', 'https://github.com/wg/wrk', 'https://github.com/wg/wrk', 'High-performance HTTP benchmark tool using epoll/kqueue. Lua scripting for custom request generation. More throughput than hey for stress testing.', 'brew install wrk', 'infrastructure', 'http-benchmark-tools', 'verify', 'cli', NULL, 'lua', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d7978b00-23f9-411a-85c8-9ad8670eefca', 'bombardier', 'https://github.com/codesenberg/bombardier', 'https://github.com/codesenberg/bombardier', 'Fast cross-platform HTTP benchmarking tool written in Go. Uses fasthttp for maximum performance. Supports HTTP/1.x and HTTP/2.0. Clean output with latency distribution and throughput stats.', 'brew install bombardier', 'infrastructure', 'http-benchmark-tools', 'verify', 'cli', NULL, 'go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('be1e6cd6-df90-4b87-bd71-8b2dedce249d', 'dotenv-linter', 'https://dotenv-linter.github.io/', NULL, 'Lightning-fast linter for `.env` files written in Rust. Checks for duplicates, incorrect ordering, missing values, extra blanks, and inconsistencies across `.env` files.', 'brew install dotenv-linter', 'infrastructure', 'configuration-validation', 'verify', 'cli', NULL, 'rust,go', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c03e8e74-c5e2-41b5-bd55-a22cfc0b0b2f', 'envalid', 'https://www.npmjs.com/package/envalid', NULL, 'Node.js runtime environment variable validation. Defines a schema for required vars with types, defaults, and descriptions. Fails fast at startup with clear error messages if vars are missing or malformed.', 'npm install envalid', 'infrastructure', 'configuration-validation', 'verify', NULL, NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d51599bf-cf2a-4cb3-b6b8-80d3e1145fa7', 'env-sentinel', 'https://www.envsentinel.dev/', NULL, 'Environment variable management and validation platform. Three-layer merge (base, environment-specific, personal overrides). Startup validation with format checking.', NULL, 'infrastructure', 'configuration-validation', 'verify', NULL, NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('030a0834-603e-45e4-8d66-6de08b1d4477', 'pg_isready', 'https://www.postgresql.org/docs/current/app-pg-isready.html', NULL, 'PostgreSQL connection checker. Returns exit code 0 if the server is accepting connections. Works with connection strings, supports timeout.', 'brew install libpq', 'infrastructure', 'dependency-connectivity-checks', 'verify', 'cli', NULL, 'sql', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('713afae3-de21-49b8-a883-e31db9bb938e', 'mysqladmin ping', 'https://dev.mysql.com/doc/refman/en/mysqladmin.html', NULL, 'MySQL/MariaDB connectivity check. Verifies the server is alive and accepting connections.', 'brew install mysql-client', 'infrastructure', 'dependency-connectivity-checks', 'verify', 'cli', NULL, 'sql', 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f9ce3111-dfa1-48e3-b655-fc9a9275daf1', 'redis-cli ping', 'https://redis.io/docs/latest/commands/ping/', NULL, 'Redis connectivity and latency check. `PING` returns `PONG` if the server is responsive.', 'brew install redis', 'infrastructure', 'dependency-connectivity-checks', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c1744da8-2703-4e4b-b5c2-6e93983f7b0e', 'Custom startup probes', NULL, NULL, 'Shell scripts that verify all required environment variables exist, secrets are readable, and external service endpoints respond. Run as a Kubernetes init container, Docker entrypoint check, or CI pipeline step.', NULL, 'infrastructure', 'dependency-connectivity-checks', 'verify', NULL, 'docker,kubernetes', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('fdae518f-215f-40be-8600-423c59ab8170', 'Vault', 'https://www.vaultproject.io/', NULL, 'Secret management platform. Post-deploy, verify the application can read required secrets from Vault. `vault kv get` retrieves secrets; `vault status` checks server health.', 'brew install vault', 'infrastructure', 'secret-verification', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d03e02c1-7fc2-49bb-b8dc-26f6574d7a64', 'AWS Secrets Manager', 'https://aws.amazon.com/secrets-manager/', NULL, 'AWS-managed secret store. Post-deploy, verify the application''s IAM role can access required secrets.', NULL, 'infrastructure', 'secret-verification', 'verify', 'cli', 'aws', NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7ac26616-2dbd-4a2a-b282-bf174207e980', '1Password CLI', 'https://developer.1password.com/docs/cli/', NULL, '1Password secret management for development and CI/CD. `op read` retrieves secrets; `op inject` populates templates.', 'brew install 1password-cli', 'infrastructure', 'secret-verification', 'verify', 'cli', NULL, NULL, 'infrastructure/deployment-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('627417ff-17bc-4746-9246-08e7944a7275', 'TFLint', 'https://github.com/terraform-linters/tflint', 'https://github.com/terraform-linters/tflint', 'Pluggable linter for Terraform and OpenTofu. Catches deprecated syntax, provider-specific errors, naming convention violations, and enforces best practices via rulesets.', 'brew install tflint', 'infrastructure', 'terraform-opentofu-planimplementverify', 'verify', 'plugin', 'linux,aws', 'bash,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('226be37b-6ece-4867-a073-b2204de2f4a8', 'Trivy (IaC scanning)', 'https://github.com/aquasecurity/trivy', 'https://github.com/aquasecurity/trivy', 'Comprehensive security scanner that subsumes the former tfsec project. Scans Terraform, CloudFormation, Kubernetes manifests, Dockerfiles, and more for misconfigurations and CVEs. Trivy is the recommended successor to tfsec.', 'brew install trivy', 'infrastructure', 'terraform-opentofu-planimplementverify', 'verify', NULL, 'docker,kubernetes', 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('360e1592-0eff-42e6-b217-e999e1247550', 'terraform validate', 'https://developer.hashicorp.com/terraform/cli/commands/validate', NULL, 'Built-in Terraform command that checks configuration syntax and internal consistency (references, types, required attributes) without accessing remote state or providers.', 'brew install terraform', 'infrastructure', 'terraform-opentofu-planimplementverify', 'verify', 'cli', NULL, 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8ea62644-35be-4931-8f48-273f0738b369', 'terraform plan', 'https://developer.hashicorp.com/terraform/cli/commands/plan', NULL, 'Generates an execution plan showing what Terraform will create, modify, or destroy. Critical for reviewing infrastructure changes before apply.', 'terraform', 'infrastructure', 'terraform-opentofu-planimplementverify', 'plan,verify', 'cli', NULL, 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5618db54-7990-4714-968c-c2ac7480467b', 'terraform-docs', 'https://github.com/terraform-docs/terraform-docs', 'https://github.com/terraform-docs/terraform-docs', 'Generates documentation from Terraform modules in various formats (Markdown, JSON, AsciiDoc). Auto-generates input/output tables and module descriptions.', 'brew install terraform-docs', 'infrastructure', 'terraform-opentofu-planimplementverify', 'implement', 'hook', NULL, 'go,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3e043b89-a4f4-4df6-8b81-01dcd5f00cf5', 'Checkov', 'https://github.com/bridgecrewio/checkov', 'https://github.com/bridgecrewio/checkov', 'Open-source static analysis tool by Bridgecrew with 1000+ built-in policies. Scans Terraform, CloudFormation, Kubernetes, Dockerfiles, Helm, Kustomize, Ansible, ARM, Bicep, and CI/CD workflow files (GitHub Actions, GitLab CI, Azure Pipelines, CircleCI). Context-aware graph-based scanning detects cross-resource issues.', 'pip install checkov', 'infrastructure', 'terraform-opentofu-planimplementverify', 'verify', NULL, 'aws,azure,docker,kubernetes', 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('93e6786d-a614-45d2-b52e-e2ec685e1bfc', 'Infracost', 'https://github.com/infracost/infracost', 'https://github.com/infracost/infracost', 'Cloud cost estimation for Terraform. Shows cost impact of infrastructure changes before deployment. Supports AWS, Azure, GCP. Integrates with pull requests to show cost diffs.', 'brew install infracost', 'infrastructure', 'terraform-opentofu-planimplementverify', 'plan,verify', NULL, 'aws,gcp,azure', 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9dd515f6-9dd9-4dcf-a620-322e0c7eda15', 'Terragrunt', 'https://github.com/gruntwork-io/terragrunt', 'https://github.com/gruntwork-io/terragrunt', 'Thin wrapper around Terraform/OpenTofu that keeps configurations DRY, manages remote state, and orchestrates multi-module deployments. Provides dependency management between modules and environment-specific variable injection.', 'brew install terragrunt', 'infrastructure', 'terraform-opentofu-planimplementverify', 'implement,verify', NULL, NULL, 'hcl,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8ac3a622-5083-4198-80c9-32a05c9aaa57', 'OpenTofu', 'https://github.com/opentofu/opentofu', 'https://github.com/opentofu/opentofu', 'Community-driven, open-source fork of Terraform under the Linux Foundation. Drop-in compatible with Terraform 1.5.x. All major Terraform ecosystem tools (TFLint, Checkov, Infracost, Terragrunt) work with OpenTofu.', 'brew install opentofu', 'infrastructure', 'terraform-opentofu-planimplementverify', 'implement', NULL, 'linux', 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c41bb285-9715-40e5-a140-61f6c93e9d50', 'Hadolint', 'https://github.com/hadolint/hadolint', 'https://github.com/hadolint/hadolint', 'Dockerfile linter written in Haskell. Checks Dockerfiles against best practices from the official Docker documentation and uses ShellCheck to lint `RUN` instruction shell code. Does not detect CVEs (use Trivy or Scout for that).', 'brew install hadolint', 'infrastructure', 'docker-containers-implementverify', 'verify', NULL, 'docker', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a31a412b-a308-42bc-847c-56c1749f236b', 'Dive', 'https://github.com/wagoodman/dive', 'https://github.com/wagoodman/dive', 'Interactive CLI tool for exploring Docker image layers. Visualizes filesystem changes per layer (green=added, yellow=modified, red=deleted), calculates wasted space, and identifies optimization opportunities.', 'brew install dive', 'infrastructure', 'docker-containers-implementverify', 'verify', 'cli', 'docker', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('02a30e2b-d9c6-4953-a920-5151106f7ac8', 'Dockle', 'https://github.com/goodwithtech/dockle', 'https://github.com/goodwithtech/dockle', 'Container image linter focused on security, based on CIS Docker Benchmarks. Scans built images (not Dockerfiles) for security issues like running as root, exposed secrets, and missing health checks.', 'brew install goodwithtech/r/dockle', 'infrastructure', 'docker-containers-implementverify', 'verify', NULL, 'docker', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('983dff77-45ce-4955-8ef8-826aaa9ca1e7', 'Docker Scout', 'https://docs.docker.com/scout/', NULL, 'Docker''s built-in vulnerability scanning and supply chain security platform. Generates SBOMs, matches against CVE databases, provides EPSS scores (exploit probability), and supports policy-based evaluation.', 'curl -fsSL https://raw.githubusercontent.com/docker/scout-cli/main/install.sh | sh', 'infrastructure', 'docker-containers-implementverify', 'verify', 'cli', 'docker', 'lua', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7e045919-3327-4a95-b84b-948283c9ee35', 'Trivy (container scanning)', 'https://github.com/aquasecurity/trivy', 'https://github.com/aquasecurity/trivy', 'Also scans container images for OS package and application dependency vulnerabilities. Comprehensive alternative to Docker Scout with broader ecosystem support.', NULL, 'infrastructure', 'docker-containers-implementverify', 'verify', NULL, 'docker', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2155867d-e017-4074-8dbb-11159278dc33', 'Snyk Container', 'https://snyk.io/product/container-vulnerability-management/', NULL, 'Commercial container vulnerability scanner with developer-focused remediation guidance. Provides base image upgrade recommendations and monitors running containers for new vulnerabilities.', 'npm install -g snyk', 'infrastructure', 'docker-containers-implementverify', 'verify', NULL, 'docker', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e8814e24-082f-4677-bba8-0e9700cfda3e', 'docker compose', 'https://docs.docker.com/compose/', NULL, 'Tool for defining and running multi-container Docker applications via `compose.yaml`. Manages service dependencies, networks, volumes, and environment configuration.', 'apt-get install docker-compose-plugin', 'infrastructure', 'docker-containers-implementverify', 'implement,verify', 'plugin', 'docker', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a3fde971-9241-4aed-bdd8-e08d9c7008b3', 'actionlint', 'https://github.com/rhysd/actionlint', 'https://github.com/rhysd/actionlint', 'Static checker for GitHub Actions workflow files. Validates YAML syntax against the GitHub Actions schema, checks expression types, verifies action input/output usage, detects script injection vulnerabilities, and validates reusable workflow references.', 'brew install actionlint', 'infrastructure', 'cicd-linting-validation-verify', 'verify', NULL, NULL, 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('43f612cb-8697-4b4f-8bc9-4a9960f8df52', 'yamllint', 'https://github.com/adrienverge/yamllint', 'https://github.com/adrienverge/yamllint', 'YAML linter that checks syntax, formatting, indentation, key duplication, line length, and trailing spaces. Works on any YAML file (CI configs, Kubernetes manifests, Ansible playbooks).', 'pip install yamllint', 'infrastructure', 'cicd-linting-validation-verify', 'verify', NULL, 'kubernetes', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('60f97c8b-66e5-419a-90f2-97fbe95c961e', 'circleci config validate', 'https://circleci.com/docs/how-to-use-the-circleci-local-cli/', NULL, 'CircleCI CLI command that validates `.circleci/config.yml` against the CircleCI schema. Catches syntax errors, invalid orb references, and misconfigured workflows.', 'brew install circleci', 'infrastructure', 'cicd-linting-validation-verify', 'verify', 'cli', NULL, 'bash', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d1165f54-20b1-42c1-952d-f43170c33f88', 'Checkov (CI/CD scanning)', 'https://github.com/bridgecrewio/checkov', 'https://github.com/bridgecrewio/checkov', 'In addition to IaC, Checkov scans CI/CD configuration files for security issues: GitHub Actions, GitLab CI, Azure Pipelines, BitBucket Pipelines, CircleCI, and Argo Workflows. Detects insecure permissions, missing pinned versions, and credential exposure patterns.', NULL, 'infrastructure', 'cicd-linting-validation-verify', 'verify', NULL, 'azure', 'go,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d80574cf-5443-4220-8de7-52852b642b9a', 'InSpec', 'https://github.com/inspec/inspec', 'https://github.com/inspec/inspec', 'Chef''s infrastructure testing framework for security compliance and system state verification. Write human-readable tests ("describe" blocks) that assert properties of OS packages, files, services, ports, cloud resources, and more. Supports AWS, Azure, GCP resource packs.', 'brew install chef/chef/inspec', 'infrastructure', 'infrastructure-testing-verify', 'verify', NULL, 'aws,gcp,azure', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c85a69e4-9f1e-4d45-b0a5-94a464af7038', 'ServerSpec', 'https://serverspec.org/', NULL, 'Ruby-based RSpec framework for testing server state. Verifies packages, services, ports, files, commands, and users on remote servers via SSH. Predecessor to InSpec (simpler but less feature-rich).', 'gem install serverspec', 'infrastructure', 'infrastructure-testing-verify', 'verify', NULL, NULL, 'ruby', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b9dfcc02-84a0-4540-a022-a2bf9b7bc4e9', 'Test Kitchen', 'https://github.com/test-kitchen/test-kitchen', 'https://github.com/test-kitchen/test-kitchen', 'Ruby-based integration testing harness from the Chef ecosystem. Creates VMs or containers, converges configuration code, then runs test suites (InSpec, ServerSpec, BATS). Supports Vagrant, Docker, EC2, Azure, GCP drivers.', 'gem install test-kitchen', 'infrastructure', 'infrastructure-testing-verify', 'verify', NULL, 'gcp,azure,docker', 'ruby', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f318e204-5d85-4658-bb20-eb06cf8423e7', 'Molecule', 'https://github.com/ansible/molecule', 'https://github.com/ansible/molecule', '(Also listed under Infrastructure Testing.) The standard testing framework for Ansible roles. Creates test instances, applies the role, checks idempotence, runs verifiers, and destroys instances. Supports Docker, Podman, Vagrant, and cloud drivers.', 'pip install molecule[docker]', 'infrastructure', 'configuration-management-implementverify', 'verify', NULL, 'ios,docker', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('06557661-5c72-471d-b7b0-90d1002145a2', 'BATS (Bash Automated Testing System)', 'https://github.com/bats-core/bats-core', 'https://github.com/bats-core/bats-core', 'TAP-compliant testing framework for Bash scripts. Each test case is a function with standard shell commands; all commands must exit 0 for the test to pass. Includes setup/teardown hooks. Helper libraries (bats-assert, bats-support) provide richer assertions.', 'npm install -g bats', 'infrastructure', 'infrastructure-testing-verify', 'verify', 'hook', NULL, 'bash,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('16e3fe13-bcb6-4d30-8f19-e99f89c5a383', 'kubectl', 'https://kubernetes.io/docs/reference/kubectl/', NULL, 'Official Kubernetes CLI. Manages all cluster resources: pods, deployments, services, configmaps, secrets, etc. Supports declarative (`apply`) and imperative commands, dry-run validation, and JSON/YAML output.', 'brew install kubectl', 'infrastructure', 'kubernetes-implementverify', 'implement,verify', 'cli', 'kubernetes', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7943e390-5902-433a-baf0-db58813724aa', 'kubeconform', 'https://github.com/yannh/kubeconform', 'https://github.com/yannh/kubeconform', 'Fast Kubernetes manifest validator inspired by kubeval. Validates YAML/JSON against Kubernetes OpenAPI schemas with multi-goroutine processing. Supports CRD schema validation via configurable schema locations. Kubeval is deprecated; kubeconform is the recommended replacement.', 'brew install kubeconform', 'infrastructure', 'kubernetes-implementverify', 'verify', NULL, 'kubernetes', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a8a25aac-96f7-4b00-a276-086c971d014c', 'kube-linter', 'https://github.com/stackrox/kube-linter', 'https://github.com/stackrox/kube-linter', 'Static analysis tool by StackRox/Red Hat that checks Kubernetes YAML files and Helm charts against production readiness and security best practices. Detects missing resource limits, running as root, missing liveness probes, etc.', 'brew install kube-linter', 'infrastructure', 'kubernetes-implementverify', 'verify', NULL, 'kubernetes', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('71c8d525-0336-4969-a054-f473849e91b2', 'Polaris', 'https://github.com/FairwindsOps/polaris', 'https://github.com/FairwindsOps/polaris', 'Best practices and policy enforcement engine for Kubernetes. Runs as CLI, dashboard, admission controller, or CI validator. Covers security, efficiency, and reliability categories with configurable severity levels.', 'brew install FairwindsOps/tap/polaris', 'infrastructure', 'kubernetes-implementverify', 'verify', 'cli', 'kubernetes', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('072da9fd-fccd-4812-8706-e92d66113bb8', 'Kustomize', 'https://kustomize.io/', NULL, 'Template-free Kubernetes configuration customization tool. Composes, patches, and transforms YAML manifests using overlays without forking base configurations. Built into kubectl (`kubectl apply -k`).', 'brew install kustomize', 'infrastructure', 'kubernetes-implementverify', 'implement', NULL, 'kubernetes', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8e28aa62-eb24-4f0e-984d-bf998771ef0f', 'Helm (lint)', 'https://helm.sh/', NULL, 'Kubernetes package manager. `helm lint` validates chart structure, template rendering, and values. `helm template` renders charts locally for inspection without a cluster.', 'brew install helm', 'infrastructure', 'kubernetes-implementverify', 'implement,verify', NULL, 'kubernetes', 'bash', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('39fe92c1-1ffc-4208-a215-70a1785672da', 'kubectx / kubens', 'https://github.com/ahmetb/kubectx', 'https://github.com/ahmetb/kubectx', 'Power tools for kubectl context and namespace switching. `kubectx` switches between clusters; `kubens` switches between namespaces. Interactive fuzzy selection with fzf integration.', 'brew install kubectx', 'infrastructure', 'kubernetes-implementverify', 'implement', NULL, 'kubernetes', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e4d201b8-7395-4d10-9f72-c6a9d9502577', 'k9s', 'https://github.com/derailed/k9s', 'https://github.com/derailed/k9s', 'Terminal-based Kubernetes dashboard. Provides real-time cluster resource views, pod logs, exec into containers, port-forwarding, and resource editing. Keyboard-driven interface with vim-like navigation.', 'brew install derailed/k9s/k9s', 'infrastructure', 'kubernetes-implementverify', 'verify', NULL, 'kubernetes', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d9a8d3d6-da61-4fa2-81fe-803e40c27795', 'stern', 'https://github.com/stern/stern', 'https://github.com/stern/stern', 'Multi-pod and multi-container log tailing for Kubernetes. Matches pods by regex, color-codes output per pod/container, and follows logs in real time. Essential for debugging distributed services.', 'brew install stern', 'infrastructure', 'kubernetes-implementverify', 'verify', NULL, 'kubernetes', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7abc9acc-f1f7-4be9-9742-f3e2366900df', 'Ansible', 'https://docs.ansible.com/', NULL, 'Agentless configuration management via YAML playbooks. `ansible-lint` checks playbooks, roles, and collections against best practices: task naming, FQCN usage, deprecated modules, idempotency issues, and formatting.', 'pip install ansible ansible-lint', 'infrastructure', 'configuration-management-implementverify', 'implement,verify', 'agent', NULL, NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('fb5f275d-ac34-4785-8997-095c62770d83', 'Chef', 'https://www.chef.io/', NULL, 'Ruby-based configuration management with a rich testing ecosystem. Cookstyle is a RuboCop-based linter for Chef cookbooks. ChefSpec runs unit tests against Chef recipes in-memory without converging real nodes. InSpec and Test Kitchen handle integration testing.', 'gem install chefspec', 'infrastructure', 'configuration-management-implementverify', 'implement,verify', NULL, NULL, 'ruby', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('23115c2c-aba6-4251-85f4-a46b18c79e68', 'Puppet', 'https://puppet.com/', NULL, 'Declarative configuration management with its own DSL. `puppet-lint` checks Puppet manifests against the official style guide: indentation, quoting, resource ordering, and deprecated syntax.', 'gem install puppet-lint', 'infrastructure', 'configuration-management-implementverify', 'implement,verify', NULL, NULL, NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9a294570-c0a5-4fc8-93d3-56ee2e660a68', 'AWS CLI', 'https://aws.amazon.com/cli/', NULL, 'Official CLI for Amazon Web Services. Covers every AWS service API. Essential for verifying deployed infrastructure state, querying resources, and debugging.', 'pip install awscli', 'infrastructure', 'cloud-provider-clis-all-phases', 'implement', 'cli', 'linux,web,aws', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bc4ed97a-fd02-4bdf-a6d9-ed5d1ebf04ea', 'Google Cloud CLI (gcloud)', 'https://cloud.google.com/sdk/gcloud', NULL, 'Official CLI for Google Cloud Platform. Manages Compute Engine, GKE, Cloud Storage, IAM, and all GCP services. Includes `gsutil` for storage and `bq` for BigQuery.', 'brew install google-cloud-sdk', 'infrastructure', 'cloud-provider-clis-all-phases', 'implement', 'cli', 'gcp', 'go,bash', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('49ba83f4-e182-4437-ae1d-0dbb112a2576', 'Azure CLI (az)', 'https://learn.microsoft.com/en-us/cli/azure/', NULL, 'Official CLI for Microsoft Azure. Manages VMs, AKS, Storage, Entra ID (formerly AAD), and all Azure services.', 'brew install azure-cli', 'infrastructure', 'cloud-provider-clis-all-phases', 'implement', 'cli', 'azure', 'bash', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9ec9ffaf-5d70-4720-9ed7-4f4f4171dd5c', 'Pulumi CLI', 'https://www.pulumi.com/docs/iac/cli/', NULL, 'Infrastructure-as-code using real programming languages (TypeScript, Python, Go, C#, Java). The CLI manages stacks, deploys changes, and provides drift detection. Uses cloud provider CLIs for authentication.', 'brew install pulumi', 'infrastructure', 'cloud-provider-clis-all-phases', 'implement', 'cli', 'aws', 'typescript,python,go,java,c#', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bed86ea7-a3b6-433d-b92d-b3fd4c7cf6cc', 'promtool (Prometheus)', 'https://prometheus.io/docs/prometheus/latest/command-line/promtool/', NULL, 'Official Prometheus CLI tool for config and rule validation. Validates `prometheus.yml` syntax, checks alerting/recording rule files, and runs unit tests against rules with simulated time-series data. Essential for CI pipelines that manage Prometheus configs.', 'brew install prometheus', 'infrastructure', 'monitoring-observability-setup-verify', 'verify', 'cli', NULL, 'lua', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3c2ff171-5adc-4a58-a345-76b160d4c715', 'Grafana Dashboard Validation', 'https://grafana.com/docs/grafana/latest/', NULL, 'Grafana dashboards are JSON files that can be validated for structure, datasource references, and panel configuration. Grafana''s provisioning system allows dashboards-as-code.', 'brew install grafana', 'infrastructure', 'monitoring-observability-setup-verify', 'verify', 'cli', 'docker', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5e73866a-5310-4948-85e9-7ddab0ce5da8', 'Alertmanager Configuration', 'https://prometheus.io/docs/alerting/latest/configuration/', NULL, 'Prometheus Alertmanager routes, groups, and silences alerts. Its config (`alertmanager.yml`) defines notification routing trees, receivers (Slack, PagerDuty, email), and inhibition rules.', 'brew install alertmanager', 'infrastructure', 'monitoring-observability-setup-verify', 'verify', NULL, NULL, NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('92140ae9-c52f-4dd1-aaff-24917dda8900', 'Terraform MCP Server (HashiCorp)', 'https://github.com/hashicorp/terraform-mcp-server', 'https://github.com/hashicorp/terraform-mcp-server', 'Official HashiCorp MCP server providing seamless integration with Terraform Registry APIs. Enables Claude Code to query provider documentation, resource schemas, module interfaces, and best practices directly from the Terraform ecosystem during planning and implementation.', 'claude mcp add terraform -- npx @hashicorp/terraform-mcp-server', 'infrastructure', 'claude-code-integration-all-phases', 'plan,implement', 'mcp', NULL, 'hcl,terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8101173b-3c75-4855-a299-927721620035', 'Kubernetes MCP Server', 'https://github.com/containers/kubernetes-mcp-server', 'https://github.com/containers/kubernetes-mcp-server', 'Go-based native MCP server that interacts directly with the Kubernetes API server (not a kubectl wrapper). Provides 40+ tools for managing cluster resources. Supports multi-cluster management, read-only mode for safe inspection, and natural language cluster queries.', 'claude mcp add kubernetes -- npx mcp-server-kubernetes', 'infrastructure', 'claude-code-integration-all-phases', 'implement,verify', 'mcp', 'kubernetes', 'go', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a010add5-e9aa-4b41-b64e-b77b5bf9ad20', 'AWS MCP Servers', 'https://github.com/awslabs/mcp', 'https://github.com/awslabs/mcp', 'Official AWS Labs MCP server collection with 45+ tools for Claude Code. Covers documentation lookup, CDK infrastructure, CloudFormation, DynamoDB (read-only), Lambda management, cost analysis, Bedrock knowledge bases, and more. Requires Core MCP Server as orchestrator.', 'claude mcp add aws-docs -- npx @awslabs/aws-docs-mcp-server', 'infrastructure', 'claude-code-integration-all-phases', 'implement', 'mcp', 'aws', NULL, 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4645a82d-dbca-457d-87f5-49fc8faddfbb', 'Terraform Cloud MCP', 'https://mcpservers.org/servers/severity1/terraform-cloud-mcp', NULL, 'MCP server for Terraform Cloud / HCP Terraform. Enables Claude Code to interact with workspaces, runs, state, and plan outputs from Terraform Cloud without leaving the coding session.', '.mcp.json', 'infrastructure', 'claude-code-integration-all-phases', 'plan,verify', 'mcp', NULL, 'terraform', 'infrastructure/devops-tools.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d7607db3-4a11-4ab0-b929-5d7563e5c6f9', 'General CLI Integration', NULL, NULL, 'Claude Code can invoke any CLI tool directly via its Bash tool. All tools in this catalog that have a command-line interface can be used by Claude Code without an MCP server. MCP servers add richer tool descriptions and structured interactions but are not required for basic usage.', NULL, 'infrastructure', 'claude-code-integration-all-phases', 'implement', 'mcp', NULL, 'bash,terraform', 'infrastructure/devops-tools.md');
