INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('db794a31-dfd6-42bb-a7ca-cc586bc81b90', 'Express', 'https://expressjs.com/', NULL, 'The most widely used Node.js web framework. Mature ecosystem, extensive middleware, massive community. Battle-tested since 2010.', 'npm install express', 'web-backend', 'nodejs', 'implement', NULL, 'web', NULL, 'web/backend-tools.md');
