INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5937c50a-4ce3-4aa0-bf8c-35b306eadabb', 'Hono', 'https://hono.dev/', NULL, 'Ultralight, cross-runtime framework (Node, Deno, Bun, Cloudflare Workers, AWS Lambda). Minimal bundle, fast cold starts.', 'npm install hono', 'web-backend', 'nodejs', 'implement', NULL, 'cloudflare,aws', NULL, 'web/backend-tools.md');
