INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f21163ed-168e-416a-8820-afb67833a9bd', 'Zod', 'https://zod.dev/', NULL, 'TypeScript-first schema validation with static type inference. The dominant choice for TypeScript projects. Integrates with tRPC, React Hook Form, and most TypeScript frameworks.', 'npm i zod', 'web-client-server', 'schema-validation', 'implement,verify', 'hook', NULL, 'typescript', 'web/client-server-patterns.md');
