INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8ae41d06-10da-4ad7-bd61-62fc9861c146', 'Marshmallow', 'https://marshmallow.readthedocs.io/', NULL, 'Python library for object serialization/deserialization and validation. v4.1 current. Flask-Marshmallow for Flask integration.', 'pip install marshmallow', 'web-client-server', 'schema-validation', 'implement,verify', 'cli', NULL, 'python', 'web/client-server-patterns.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d75c9227-6274-4fd6-b349-88b18c834061', 'Pact', 'https://pact.io/', NULL, 'Consumer-driven contract testing. The consumer writes tests defining expectations; the provider verifies against them. Gold standard for microservice contract testing.', 'npm i @pact-foundation/pact --save-dev', 'web-client-server', 'api-contract-testing', 'implement,verify', 'cli', NULL, 'go', 'web/client-server-patterns.md');
