INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b6708f8a-55e5-4377-bec2-0cd23f431b70', 'Stylelint', 'https://stylelint.io', NULL, 'CSS linter with 100+ rules. Supports CSS, SCSS, Less, and CSS-in-JS. The CSS equivalent of ESLint.', 'npm install -D stylelint stylelint-config-standard', 'web-frontend', 'css-styling-tools-implementverify', 'implement,verify', 'cli', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('984afaf6-08ea-4ecc-bedd-c6da3fab946f', 'stylelint-declaration-strict-value', 'https://github.com/AndyOGo/stylelint-declaration-strict-value', 'https://github.com/AndyOGo/stylelint-declaration-strict-value', 'Stylelint plugin that enforces CSS custom properties (design tokens) instead of hardcoded values for specified properties. Catches literal hex colors, pixel values, etc. where tokens should be used.', 'npm install -D stylelint-declaration-strict-value', 'web-frontend', 'css-styling-tools-implementverify', 'verify', 'plugin', NULL, 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('54714544-a2c4-40b5-a279-20471f78c358', 'Tailwind CSS IntelliSense / tailwind-lint', NULL, NULL, 'Validates Tailwind class usage, detects conflicting utilities, and enforces correct directive usage. The IntelliSense extension is VS Code-only; `tailwind-lint` brings the same checks to the CLI.', 'npm install -D tailwind-lint', 'web-frontend', 'css-styling-tools-implementverify', 'verify', 'hook', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('465a962d-e5b4-4899-9ef2-8db5e0b1ad08', 'eslint-plugin-tailwindcss', 'https://github.com/francoismassart/eslint-plugin-tailwindcss', 'https://github.com/francoismassart/eslint-plugin-tailwindcss', 'ESLint plugin with 5+ rules for Tailwind: class ordering, no contradicting classes, no custom classnames (enforce utility-first), and enforced shorthand.', 'npm install -D eslint-plugin-tailwindcss', 'web-frontend', 'css-styling-tools-implementverify', 'implement,verify', 'plugin', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('cb25e1f7-5366-4ba3-aaeb-7f7bf24b2f9c', 'Lightning CSS', 'https://lightningcss.dev', NULL, 'Extremely fast Rust-based CSS parser, transformer, bundler, and minifier. Replaces PostCSS + autoprefixer + postcss-preset-env in one tool.', 'npm install -D lightningcss-cli', 'web-frontend', 'css-styling-tools-implementverify', 'implement', 'cli', NULL, 'rust', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('aea57553-c2d6-4cca-b347-812375c68ddc', 'PostCSS', 'https://postcss.org', NULL, 'CSS transformation framework with a plugin ecosystem. Handles autoprefixing, nesting, custom properties polyfills, and more.', 'npm install -D postcss postcss-cli autoprefixer', 'web-frontend', 'css-styling-tools-implementverify', 'implement', 'plugin', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b6c35448-728a-4782-b8f2-ef5ad6e24739', 'Vite', 'https://vite.dev', NULL, 'Dev server with native ES module serving and Rollup-based production bundling. HMR is near-instant regardless of app size.', 'npm install -D vite', 'web-frontend', 'build-tools-implement', 'implement', 'plugin', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1583dcd7-0c8d-4ae6-b21f-b24ff0370e48', 'Turbopack', 'https://turbo.build/pack', NULL, 'Rust-based bundler from Vercel, now the default in Next.js 16. Claims 700x faster updates than webpack and 10x faster than Vite for large apps. Cold starts under 1 second for 30,000+ module apps.', NULL, 'web-frontend', 'build-tools-implement', 'implement', 'cli', 'web', 'rust', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b2d32709-e9f7-444d-9790-43234a867b4e', 'Rspack', 'https://rspack.rs', NULL, 'Drop-in webpack replacement written in Rust. 10-23x faster than webpack 5 with ~85% webpack ecosystem compatibility (loaders, plugins).', 'npm install -D @rspack/cli @rspack/core', 'web-frontend', 'build-tools-implement', 'implement', 'plugin', 'web', 'rust', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2c6416df-53d0-4143-9cdd-1f4b8de229f7', 'esbuild', 'https://esbuild.github.io', NULL, 'Extremely fast Go-based bundler and minifier. Cold production builds in ~300ms for small libraries, ~700ms for larger ones. 10-100x faster than webpack.', 'npm install -D esbuild', 'web-frontend', 'build-tools-implement', 'implement', 'cli', 'web', 'typescript,go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f1571454-49d0-4470-815a-e8b2f79b5b92', 'webpack', 'https://webpack.js.org', NULL, 'The original JavaScript module bundler. Massive plugin ecosystem. Still powers many production applications.', 'npm install -D webpack webpack-cli', 'web-frontend', 'build-tools-implement', 'implement', 'plugin', 'web', 'javascript,java', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a02a6af2-984a-4c51-9807-daab3159f013', 'shadcn/ui', 'https://ui.shadcn.com', NULL, 'Copy-paste component collection built on Radix UI (or Base UI as of Feb 2026) and Tailwind CSS. Components live in your codebase, not node_modules. 75,000+ GitHub stars.', 'npx shadcn@latest init', 'web-frontend', 'component-libraries-implement', 'implement', 'cli', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('45486770-2508-419e-8744-3a2350c2287a', 'Radix UI Primitives', 'https://www.radix-ui.com', NULL, 'Unstyled, accessible React component primitives. Handles ARIA, keyboard navigation, and focus management. The foundation under shadcn/ui.', 'npm install @radix-ui/react-dialog @radix-ui/react-dropdown-menu ...', 'web-frontend', 'component-libraries-implement', 'implement', 'cli', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f12f4cd8-d346-447b-b310-0d5a96964fbb', 'Headless UI', 'https://headlessui.com', NULL, 'Unstyled, accessible UI components from the Tailwind CSS team. Covers common patterns: dialogs, menus, listboxes, comboboxes, tabs, transitions.', 'npm install @headlessui/react', 'web-frontend', 'component-libraries-implement', 'implement', NULL, NULL, 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a0914f24-4c00-417e-adea-9fbc50c6d74d', 'Mantine', 'https://mantine.dev', NULL, 'Batteries-included React component library with 120+ components and 100+ hooks. Covers rich text editors, date pickers, notifications, spotlight search, and drag-and-drop.', 'npm install @mantine/core @mantine/hooks', 'web-frontend', 'component-libraries-implement', 'implement', 'hook', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1b4dbd4f-6bf8-4c84-9296-8da88ab845c8', 'Material UI', 'https://mui.com', NULL, 'React implementation of Google''s Material Design. 90+ components, extensive theming system, enterprise support.', 'npm install @mui/material @emotion/react @emotion/styled', 'web-frontend', 'component-libraries-implement', 'implement', NULL, NULL, 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2ab0269c-6f02-4ae9-84df-1f7d679e77a8', 'Chakra UI', 'https://chakra-ui.com', NULL, 'Accessible React component library with style props API. Strong focus on accessibility (WCAG compliance).', 'npm install @chakra-ui/react', 'web-frontend', 'component-libraries-implement', 'implement', NULL, NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4e3803b1-2cd8-4a60-bb18-1d29bd4ebcee', 'Stylelint + stylelint-declaration-strict-value', 'https://github.com/AndyOGo/stylelint-declaration-strict-value', 'https://github.com/AndyOGo/stylelint-declaration-strict-value', 'Enforces that specified CSS properties use variables/tokens instead of hardcoded values. Catches literal hex colors, pixel values, and font names where design tokens should be used.', 'npm install -D stylelint stylelint-declaration-strict-value', 'web-frontend', 'design-system-enforcement-verify', 'verify', 'hook', NULL, 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1be81155-19c0-4aa6-8d96-73833bf6bf4c', 'ESLint Custom Rules', NULL, NULL, 'Custom ESLint rules that catch hardcoded color values, spacing, and non-token style usage in JSX/TSX files.', 'eslint-plugin-no-hardcoded-colors', 'web-frontend', 'design-system-enforcement-verify', 'verify', 'plugin', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('122a31dd-c94e-418c-b4a0-aab9f94b97ac', 'Semgrep', 'https://semgrep.dev', NULL, 'Static analysis tool that can write pattern-based rules for any language, including CSS and HTML. Can enforce design system token usage and catch non-compliant patterns.', 'pip install semgrep', 'web-frontend', 'design-system-enforcement-verify', 'verify', 'mcp', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7a02cc09-084c-4a31-9110-f27a99a135b0', 'Tokens Studio', 'https://tokens.studio', NULL, 'Syncs design tokens from Figma to code via GitHub/GitLab. Supports color, typography, spacing, border-radius, and shadow tokens. 264,000+ active users.', 'npm install -D @tokens-studio/sd-transforms', 'web-frontend', 'design-system-enforcement-verify', 'plan,verify', 'mcp', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f8a15ff4-5d1d-4c1b-8fa4-b31676f8c8d6', 'Lighthouse CI', 'https://github.com/GoogleChrome/lighthouse-ci', 'https://github.com/GoogleChrome/lighthouse-ci', 'Runs Lighthouse audits (performance, accessibility, best practices, SEO) in CI or locally. Sets performance budgets and fails builds when Core Web Vitals (LCP, CLS, TBT) regress.', 'npm install -g @lhci/cli', 'web-frontend', 'performance-bundle-analysis-verify', 'verify', 'cli', 'web', 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('48d86514-5f62-400b-8697-0ee9feb8c727', 'web-vitals', 'https://github.com/GoogleChrome/web-vitals', 'https://github.com/GoogleChrome/web-vitals', 'Tiny library (1.5KB) for measuring Core Web Vitals (LCP, CLS, INP, FCP, TTFB) in the browser. Reports real user metrics.', 'npm install web-vitals', 'web-frontend', 'performance-bundle-analysis-verify', 'verify', 'cli', 'web', 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d979346b-9771-4e22-b99b-d078a3f28d45', 'size-limit', 'https://github.com/ai/size-limit', 'https://github.com/ai/size-limit', 'Calculates the real cost (size + load time) of your JS. Modular architecture with plugins for webpack, esbuild, and time estimation. Shows pull request size impact via GitHub Action.', 'npm install -D size-limit @size-limit/preset-app', 'web-frontend', 'performance-bundle-analysis-verify', 'verify', 'plugin', 'web', NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ea9bddeb-231b-4f7c-b832-943369d1155c', 'webpack-bundle-analyzer', 'https://github.com/webpack-contrib/webpack-bundle-analyzer', 'https://github.com/webpack-contrib/webpack-bundle-analyzer', 'Generates interactive treemap visualizations of webpack bundle contents. Shows parsed, gzipped, and Brotli sizes of every module.', 'npm install -D webpack-bundle-analyzer', 'web-frontend', 'performance-bundle-analysis-verify', 'verify', 'plugin', 'web', NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('edf6fab5-2b2b-4bc3-bcb1-c4687fe5ba14', 'bundlesize', 'https://github.com/siddharthkp/bundlesize', 'https://github.com/siddharthkp/bundlesize', 'Tests asset sizes against thresholds. Integrates with GitHub to post pass/fail status on PRs. Supports gzip and Brotli compression.', 'npm install -D bundlesize', 'web-frontend', 'performance-bundle-analysis-verify', 'verify', 'cli', NULL, 'go', 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('60eb054a-4a64-449e-a4c5-8fd6936d77ae', 'Vitest', 'https://vitest.dev', NULL, 'Vite-native testing framework with Jest-compatible API. Smart watch mode, native v8/istanbul coverage, browser mode for component testing. Supports Vue, React, Svelte, Lit, and Marko.', 'npm install -D vitest', 'web-frontend', 'performance-bundle-analysis-verify', 'verify', 'cli', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bc4a61f7-0ed4-47c3-ab8f-68aa739b67e3', 'Playwright MCP Server', 'https://github.com/microsoft/playwright-mcp', 'https://github.com/microsoft/playwright-mcp', 'Official MCP server that gives Claude Code direct browser control. 34 tools across core automation, tab management, vision-based interactions, and test assertions. Uses accessibility snapshots by default (no screenshots needed for structure).', 'claude mcp add playwright -- npx @playwright/mcp@latest', 'web-frontend', 'browser-integration-verify', 'verify', 'mcp', NULL, NULL, 'web/frontend-frameworks-and-linters.md');
