INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a2e1ca98-c287-415d-ad83-abdf040264e0', 'EditorConfig', 'https://editorconfig.org/', NULL, 'Configuration file (`.editorconfig`) that defines code style rules consumed by `dotnet format`, Roslyn analyzers, and IDEs. Supports .NET-specific rules like `dotnet_style_*` and `csharp_style_*`.', NULL, 'windows', 'linters-formatters-implementverify', 'implement,verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('eac8857a-e659-47cf-8b1b-ea3fa0dc6d01', 'StyleCop Analyzers', 'https://github.com/DotNetAnalyzers/StyleCopAnalyzers', 'https://github.com/DotNetAnalyzers/StyleCopAnalyzers', 'Roslyn-based analyzers enforcing StyleCop''s layout, ordering, spacing, readability, and documentation rules. ~200 rules with SA-prefix diagnostic IDs.', 'dotnet add package StyleCop.Analyzers', 'windows', 'linters-formatters-implementverify', 'implement,verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1ff6c84a-e64a-456b-afc6-ce6d8c2ff8c5', 'Roslynator', 'https://github.com/dotnet/roslynator', 'https://github.com/dotnet/roslynator', '500+ analyzers, refactorings, and code fixes for C#, powered by Roslyn. Actively maintained under the `dotnet` GitHub org. Analyzers package contains 200+ diagnostic rules; refactorings package adds 200+ more.', 'dotnet add package Roslynator.Analyzers', 'windows', 'linters-formatters-implementverify', 'implement,verify', NULL, NULL, 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bbb9f972-d3ef-462f-b447-e31eca09b899', 'Meziantou.Analyzer', 'https://github.com/meziantou/Meziantou.Analyzer', 'https://github.com/meziantou/Meziantou.Analyzer', 'Roslyn analyzer enforcing best practices for performance, security, usage, and design in C#. Actively maintained with frequent releases.', 'dotnet add package Meziantou.Analyzer', 'windows', 'linters-formatters-implementverify', 'implement,verify', NULL, NULL, 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8a2e0367-b844-4a47-b2c5-ef7028112f03', 'CSharpier', 'https://csharpier.com/', NULL, 'Opinionated code formatter for C# (inspired by Prettier). Parses and re-prints code using its own rules, eliminating style debates. Minimal configuration by design. v1.2.6 is current.', 'dotnet tool install -g csharpier', 'windows', 'linters-formatters-implementverify', 'implement,verify', 'hook', NULL, 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0499a799-1632-4664-9c02-e9d5559e199a', 'xUnit', 'https://xunit.net/', NULL, 'The most widely adopted .NET test framework. Default in Visual Studio templates, 469M+ NuGet downloads, used by 65%+ of C# open-source projects. Supports parallel execution, theory/data-driven tests, and extensible assertions.', 'dotnet add package xunit', 'windows', 'test-runners', 'verify', NULL, NULL, 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('71a90b55-74e1-461c-b7d5-1ad61054f4b9', 'NUnit', 'https://nunit.org/', NULL, 'Mature framework with rich attribute-driven configuration (`[TestCase]`, `[SetUp]`, `[TearDown]`, custom constraints). Best for legacy codebases and teams needing parameterized test metadata.', 'dotnet add package NUnit', 'windows', 'test-runners', 'verify', NULL, 'ios', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('86dfaa5d-3b77-4c03-ba66-197276fb3580', 'MSTest', 'https://learn.microsoft.com/en-us/dotnet/core/testing/unit-testing-with-mstest', NULL, 'Microsoft''s built-in test framework, included with Visual Studio. MSTest v3/v4 are modern and competitive. Simplest setup for new developers.', 'dotnet add package MSTest.TestFramework', 'windows', 'test-runners', 'verify', NULL, NULL, 'go', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('876bcb53-b6bb-4c4b-a3bf-c42c92721747', 'FluentAssertions', 'https://fluentassertions.com/', NULL, 'Fluent assertion syntax for readable test expectations. Supports xUnit, NUnit, MSTest, MSpec, and TUnit. Rich failure messages with expected/actual diffs.', 'dotnet add package FluentAssertions', 'windows', 'assertion-libraries', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e7ad2e6a-0e7b-48a9-bf49-5653e01ea9d4', 'Shouldly', 'https://docs.shouldly.org/', NULL, 'Terse assertion library focused on great error messages. Extension-method syntax: `result.ShouldBe(42)`. v4.3.0 targets .NET 8+ and .NET Standard 2.0.', 'dotnet add package Shouldly', 'windows', 'assertion-libraries', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f81ec18e-698e-49b5-b634-2b074bac07c1', 'NSubstitute', 'https://nsubstitute.github.io/', NULL, 'Friendly mocking library with clean syntax. `Substitute.For<IService>()` creates mocks with minimal ceremony. No `Setup`/`Verify` boilerplate.', 'dotnet add package NSubstitute', 'windows', 'mocking', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('118d0975-4aa7-45e7-87a4-cbf02f2afeba', 'Moq', 'https://github.com/devlooped/moq', 'https://github.com/devlooped/moq', 'Strongly-typed mocking with `Setup`/`Verify` pattern. More control over mock behavior at the cost of verbosity. Widely used in enterprise codebases.', 'dotnet add package Moq', 'windows', 'mocking', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('62fd6ca0-5481-4fe9-a626-e8f5ce796e6a', 'FakeItEasy', 'https://fakeiteasy.github.io/', NULL, 'Simple mocking library with a focus on ease of use. `A.Fake<IService>()` creates fakes. Syntax falls between NSubstitute''s brevity and Moq''s explicitness.', 'dotnet add package FakeItEasy', 'windows', 'mocking', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1f0cb0ca-28c3-4686-a128-100e92df374b', 'Bogus', 'https://github.com/bchavez/Bogus', 'https://github.com/bchavez/Bogus', 'Fake data generator for .NET. Generates realistic names, emails, addresses, dates, and domain-specific data using a fluent API. Inspired by faker.js.', 'dotnet add package Bogus', 'windows', 'test-data-generation', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('aadfb32e-d636-4249-bd8e-0b8b05ba2511', 'AutoFixture', 'https://autofixture.github.io/', NULL, 'Automatic test object creation. Generates anonymous instances of any class, filling properties with random but valid data. Integrates with xUnit, NUnit, NSubstitute, Moq.', 'dotnet add package AutoFixture', 'windows', 'test-data-generation', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('abca56d9-ad7c-48ed-a012-49fa3646f46a', 'Verify', 'https://github.com/VerifyTests/Verify', 'https://github.com/VerifyTests/Verify', 'Snapshot testing for .NET. Serializes test output to a `.verified.txt` file and diffs against it on subsequent runs. Supports xUnit, NUnit, MSTest, and Expecto.', 'dotnet add package Verify.Xunit', 'windows', 'snapshot-testing', 'verify', 'plugin', NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4ca30ba3-e6c1-4ed7-bda6-fe83bc09e0a2', 'Stryker.NET', 'https://stryker-mutator.io/docs/stryker-net/introduction/', NULL, 'Mutation testing for .NET. Automatically mutates source code (flips conditionals, removes statements, changes operators) and verifies tests catch the mutations. Generates a mutation score report.', 'dotnet tool install -g dotnet-stryker', 'windows', 'mutation-testing', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d0a3c6ca-2dd3-453a-a6aa-07aef96cd846', '.NET Analyzers (CA rules)', 'https://learn.microsoft.com/en-us/dotnet/fundamentals/code-analysis/overview', NULL, 'Built-in Roslyn analyzers included with the .NET SDK. CA-prefix rules cover security, performance, design, globalization, and reliability. IDE-prefix rules cover code style.', NULL, 'windows', 'static-analysis-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('69f19e1e-eefc-4381-945e-531e847d1d26', 'SonarAnalyzer.CSharp', 'https://github.com/SonarSource/sonar-dotnet', 'https://github.com/SonarSource/sonar-dotnet', '380+ C# rules and 130+ VB.NET rules from SonarSource. Covers bugs, vulnerabilities, code smells, and security hotspots. Works standalone (NuGet) or with SonarQube/SonarCloud.', 'dotnet add package SonarAnalyzer.CSharp', 'windows', 'static-analysis-verify', 'verify', NULL, NULL, 'go,c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('35163347-4cf4-4cdc-81fc-1830a37a121e', 'Semgrep', 'https://semgrep.dev/docs/languages/csharp', NULL, 'Lightweight static analysis supporting 30+ languages including C# (GA). Pattern-based rules that look like source code. Semgrep Supply Chain scans NuGet dependencies for reachable vulnerabilities.', 'pip install semgrep', 'windows', 'static-analysis-verify', 'verify', 'cli', 'windows', 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7892a1f3-33f3-45c5-9f91-631339f36a04', 'SecurityCodeScan', 'https://security-code-scan.github.io/', NULL, 'Vulnerability pattern detector for C# and VB.NET. Detects SQL injection, XSS, CSRF, XXE, and other OWASP Top 10 issues.', 'dotnet add package SecurityCodeScan.VS2019', 'windows', 'static-analysis-verify', 'verify', NULL, NULL, 'c#,sql', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1e8fb51d-68cd-4d45-a215-d6f00a9da0e3', 'NDepend', 'https://www.ndepend.com/', NULL, 'Enterprise static analysis with deep interprocedural flow analysis, cross-project dependency mapping, architectural rule enforcement, and technical debt tracking. 150+ default code rules.', NULL, 'windows', 'static-analysis-verify', 'verify', 'cli', NULL, 'go', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('14b60469-8b96-402b-8774-33d5a4a5f2b9', 'dotnet CLI', 'https://learn.microsoft.com/en-us/dotnet/core/tools/', NULL, 'Unified CLI for building, testing, publishing, packaging, and managing .NET projects. Core commands: `build`, `test`, `run`, `publish`, `pack`, `tool`, `new`.', NULL, 'windows', 'build-tooling-implementverify', 'plan,implement,verify', 'cli', NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2c8b93ed-05e4-4a63-b6d8-98e8cce8ab31', 'MSBuild', 'https://learn.microsoft.com/en-us/visualstudio/msbuild/msbuild', NULL, 'The build engine behind `dotnet build`. Direct `msbuild` commands give finer control: custom targets, property evaluation (`-getProperty`), binary logging (`-bl`).', NULL, 'windows', 'build-tooling-implementverify', 'implement,verify', NULL, NULL, 'lua', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b48008ae-32b3-4ae1-a45d-ad4c2701da4f', 'Directory.Build.props', 'https://learn.microsoft.com/en-us/visualstudio/msbuild/customize-your-build', NULL, 'MSBuild file placed at the repo root that applies common properties to all projects in the solution. Centralizes `<LangVersion>`, `<Nullable>`, `<TreatWarningsAsErrors>`, analyzer packages, etc.', NULL, 'windows', 'build-tooling-implementverify', 'implement,verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('afac2fb1-1d10-469e-9b43-0b2da56db84f', 'Directory.Build.targets', 'https://learn.microsoft.com/en-us/visualstudio/msbuild/customize-your-build', NULL, 'Like `Directory.Build.props` but evaluated after individual project files. Used for custom build targets, post-build steps, and conditional logic that depends on per-project properties.', NULL, 'windows', 'build-tooling-implementverify', 'implement,verify', NULL, 'ios', 'lua', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('666a1246-5890-4824-b0a7-3d568e7a0b7d', 'Central Package Management', 'https://learn.microsoft.com/en-us/nuget/consume-packages/central-package-management', NULL, 'Centralizes NuGet package versions in a single `Directory.Packages.props` file. Projects use `<PackageReference>` without `Version`; versions are resolved from the central file.', NULL, 'windows', 'build-tooling-implementverify', 'implement,verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('79831d9d-9b00-40fe-854f-a5e28f437e84', 'global.json', 'https://learn.microsoft.com/en-us/dotnet/core/tools/global-json', NULL, 'Pins the .NET SDK version for the repo. Ensures consistent builds across developer machines and CI.', NULL, 'windows', 'build-tooling-implementverify', 'implement,verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('dbb2b4af-237e-4680-8c20-960497962b40', 'Roslyn Source Generators', 'https://learn.microsoft.com/en-us/dotnet/csharp/roslyn-sdk/source-generators-overview', NULL, 'Compile-time code generation with full access to the Roslyn semantic model. Runs as part of every build, zero runtime overhead, full IDE support. The `IIncrementalGenerator` API (Roslyn 4.0+/.NET 6+) is the modern standard.', NULL, 'windows', 'code-generation-implement', 'implement', 'cli', NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('364f0ddb-9cd2-48fa-a228-6bbe15709662', 'T4 Templates', 'https://learn.microsoft.com/en-us/visualstudio/modeling/code-generation-and-t4-text-templates', NULL, 'Text template engine for generating any text output (C#, SQL, config, HTML). Available since .NET 3.5. Runs outside the build pipeline by default, though [T4.SourceGenerator](https://github.com/CptWesley/T4.SourceGenerator) bridges to Roslyn.', NULL, 'windows', 'code-generation-implement', 'implement', 'cli', NULL, 'c#,sql', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3bf5b6b0-d086-4878-b533-fe53fc7e71d5', 'dotnet new (templates)', 'https://learn.microsoft.com/en-us/dotnet/core/tools/dotnet-new', NULL, 'Project and item scaffolding. Built-in templates for webapi, console, classlib, blazor, etc. Custom templates via `template.json`.', NULL, 'windows', 'code-generation-implement', 'implement', NULL, 'web', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('e38d2d60-98d8-4343-8758-d4b0a53c42bc', 'EF Core Scaffolding', 'https://learn.microsoft.com/en-us/ef/core/managing-schemas/scaffolding/', NULL, 'Reverse-engineers a database into C# entity classes and a DbContext. Supports T4 template customization for output format.', 'dotnet tool install -g dotnet-ef', 'windows', 'code-generation-implement', 'implement', 'cli', NULL, 'c#,sql', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1b7b3b90-3eec-43cb-bf1c-b9766c23761c', 'dotnet add package', 'https://learn.microsoft.com/en-us/dotnet/core/tools/dotnet-add-package', NULL, 'Adds a NuGet package reference to a project file. Resolves the latest stable version by default, or a specified version.', 'dotnet add package Newtonsoft.Json', 'windows', 'package-management-implement', 'implement', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bf573df5-e278-4360-aa2d-c16e6dc70abe', 'dotnet list package', 'https://learn.microsoft.com/en-us/dotnet/core/tools/dotnet-list-package', NULL, 'Lists all package references for a project or solution. Flags: `--vulnerable`, `--deprecated`, `--outdated`, `--include-transitive`.', NULL, 'windows', 'package-management-implement', 'implement,verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('297ce13b-e54d-44de-9817-168b86c60d1d', 'NuGet Audit', 'https://devblogs.microsoft.com/dotnet/nugetaudit-2-0-elevating-security-and-trust-in-package-management/', NULL, 'Automatic vulnerability scanning during `dotnet restore`. NuGet Audit 2.0 scans direct and transitive dependencies against the GitHub Advisory Database. In .NET 10+, audit mode defaults to "all" (direct + transitive).', NULL, 'windows', 'package-management-implement', 'implement', NULL, NULL, 'rust', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('5b36c63e-89ca-4834-b30f-f3578ed9d045', 'NuGet CLI (nuget.exe)', 'https://learn.microsoft.com/en-us/nuget/reference/nuget-exe-cli-reference', NULL, 'Standalone NuGet command-line tool for restore, pack, push, and config management. Required for some .NET Framework scenarios.', NULL, 'windows', 'package-management-implement', 'implement', 'cli', 'ios', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7f50dc44-9513-4803-9a62-c4357ef7f6ba', 'XML Documentation Comments', 'https://learn.microsoft.com/en-us/dotnet/csharp/language-reference/xmldoc/', NULL, 'Triple-slash (`///`) comments with XML tags (`<summary>`, `<param>`, `<returns>`, `<exception>`, `<example>`). Compiler generates `.xml` files consumed by IntelliSense and doc generators.', NULL, 'windows', 'documentation-implement', 'implement', NULL, NULL, 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7a8fcedc-d59b-4d13-a3e3-edcd10827883', 'DocFX', 'https://dotnet.github.io/docfx/', NULL, 'Microsoft''s static site generator for .NET API documentation. Consumes XML doc comments and Markdown to produce a searchable HTML site. Supports C#, VB.NET, and F#. The successor to Sandcastle.', 'dotnet tool install -g docfx', 'windows', 'documentation-implement', 'implement', 'cli', NULL, 'c#', 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('502d8a69-bdf9-4366-9434-7c4a4dec67b8', 'Sandcastle Help File Builder', 'https://github.com/EWSoftware/SHFB', 'https://github.com/EWSoftware/SHFB', 'Legacy documentation generator producing CHM, MSHV, and website output from XML comments. Command-line based, no GUI.', NULL, 'windows', 'documentation-implement', 'implement', NULL, 'web', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('d014bcd7-fe40-4ad3-9172-b3ae5fec7959', 'dotnet list package --vulnerable', 'https://learn.microsoft.com/en-us/dotnet/core/tools/dotnet-list-package', NULL, 'Lists packages with known security vulnerabilities from the GitHub Advisory Database. Add `--include-transitive` to scan the full dependency graph.', NULL, 'windows', 'dependency-security-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8a6eb481-e8a2-4b37-b926-6b6496a81147', 'dotnet list package --deprecated', 'https://learn.microsoft.com/en-us/dotnet/core/tools/dotnet-list-package', NULL, 'Lists packages marked as deprecated by their authors, including suggested replacements.', NULL, 'windows', 'dependency-security-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('66d2be4b-131b-4525-9990-b45aea8615ba', 'Snyk .NET', 'https://docs.snyk.io/supported-languages-package-managers-and-frameworks/.net/guidance-for-snyk-for-.net', NULL, 'Commercial SCA platform with .NET/NuGet support. Scans for vulnerabilities, provides remediation advice, and monitors continuously. Integrates with CI/CD via GitHub Actions (`snyk/actions/dotnet`).', 'npm install -g snyk', 'windows', 'dependency-security-verify', 'verify', 'cli', NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1f214c15-1742-4081-b14b-a161e3e88aa3', 'OWASP Dependency-Check', 'https://owasp.org/www-project-dependency-check/', NULL, 'Open-source SCA tool scanning project dependencies against the NVD (National Vulnerability Database). Supports .NET via CLI or plugins.', NULL, 'windows', 'dependency-security-verify', 'verify', 'plugin', NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('9a069f7f-bd74-4a22-b9d9-2c9e471ab0a8', 'BenchmarkDotNet', 'https://benchmarkdotnet.org/', NULL, 'The standard .NET microbenchmarking library. Automates warmup, iteration, and statistical analysis. Produces markdown/HTML reports with execution time, memory allocation, and GC metrics. Used by Microsoft and .NET OSS maintainers.', 'dotnet add package BenchmarkDotNet', 'windows', 'performance-profiling-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1f356874-6399-4c49-9db8-e06179417994', 'dotnet-counters', 'https://learn.microsoft.com/en-us/dotnet/core/diagnostics/dotnet-counters', NULL, 'Live performance monitoring for running .NET processes. Displays EventCounter and Meter API values (CPU, GC, threadpool, exceptions, custom counters) in real time.', 'dotnet tool install -g dotnet-counters', 'windows', 'performance-profiling-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('040112e8-b8fd-43aa-b5ee-e72aed0474e9', 'dotnet-trace', 'https://learn.microsoft.com/en-us/dotnet/core/diagnostics/dotnet-trace', NULL, 'Collects detailed runtime traces from a running .NET process without a native debugger. Exports to `.nettrace` format (convertible to `.speedscope.json` or Chromium trace).', 'dotnet tool install -g dotnet-trace', 'windows', 'performance-profiling-verify', 'verify', NULL, 'macos,windows,linux', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('65976f63-6abb-4f6c-b425-48800e473567', 'dotnet-dump', 'https://learn.microsoft.com/en-us/dotnet/core/diagnostics/dotnet-dump', NULL, 'Collects and analyzes process dumps without a native debugger. Supports SOS debugging commands (`dumpheap`, `dumpobj`, `gcroot`) for memory leak investigation.', 'dotnet tool install -g dotnet-dump', 'windows', 'performance-profiling-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('1e10058c-47a8-4e84-ba0f-a98358033236', 'dotnet-gcdump', 'https://learn.microsoft.com/en-us/dotnet/core/diagnostics/dotnet-gcdump', NULL, 'Collects GC (garbage collector) dumps showing live object graphs. Lighter than a full process dump -- captures only managed heap information.', 'dotnet tool install -g dotnet-gcdump', 'windows', 'performance-profiling-verify', 'verify', NULL, NULL, NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('00c37812-a232-4713-ac14-c307e10d726b', 'PerfView', 'https://github.com/Microsoft/perfview', 'https://github.com/Microsoft/perfview', 'Microsoft''s free advanced performance analysis tool for Windows. Analyzes ETW traces, GC behavior, JIT compilation, CPU sampling, and memory allocation. Steep learning curve but unmatched depth.', NULL, 'windows', 'performance-profiling-verify', 'verify', NULL, 'windows', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6822acb7-f952-4229-8b89-d52732045659', 'dotnet-monitor', 'https://learn.microsoft.com/en-us/dotnet/core/diagnostics/dotnet-monitor', NULL, 'Sidecar diagnostic tool that exposes REST APIs for collecting traces, dumps, counters, and logs from running .NET apps. Designed for containerized/production environments.', 'dotnet tool install -g dotnet-monitor', 'windows', 'performance-profiling-verify', 'verify', NULL, 'ios,kubernetes', NULL, 'windows/dotnet-tooling.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('ffd10307-e07d-4ecc-a413-5fcf7fd2392d', 'Verify (VerifyTests)', 'https://github.com/VerifyTests/Verify', 'https://github.com/VerifyTests/Verify', 'Snapshot testing tool for .NET that simplifies assertion of complex data models, documents, and images. The de facto standard for snapshot testing in .NET.', 'dotnet add package Verify.Xunit', 'windows', 'screenshot-snapshot-testing-verify', 'verify', NULL, NULL, NULL, 'windows/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('2f1b993a-bde5-41aa-b9b2-3c0a5785b3d3', 'ApprovalTests.Net', 'https://github.com/approvals/ApprovalTests.Net', 'https://github.com/approvals/ApprovalTests.Net', 'Approval-based verification library with dedicated WPF and WinForms screenshot extensions.', NULL, 'windows', 'screenshot-snapshot-testing-verify', 'verify', NULL, NULL, NULL, 'windows/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bc44d8ec-3736-4804-9354-b937588cafb6', 'Snapshooter', 'https://github.com/SwissLife-OSS/snapshooter', 'https://github.com/SwissLife-OSS/snapshooter', 'Snapshot testing tool for .NET Core and .NET Framework with JSON-focused comparison.', 'dotnet add package Snapshooter.Xunit', 'windows', 'screenshot-snapshot-testing-verify', 'verify', NULL, NULL, NULL, 'windows/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('53622c41-3b32-45ce-82d6-7f80e4d70e52', 'FlaUI', 'https://github.com/FlaUI/FlaUI', 'https://github.com/FlaUI/FlaUI', '.NET UI automation library based on Microsoft''s UI Automation (UIA) framework. Supports UIA2 (legacy) and UIA3 (modern, recommended). Works with WPF, WinForms, WinUI 3, and UWP apps. Provides strongly-typed access to UI elements with readable, fluent APIs.', NULL, 'windows', 'winui-testing-verify', 'verify', 'cli', NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('f73ac59e-7ea6-49a6-b6ea-95ece59ba636', 'FlaUInspect', 'https://github.com/FlaUI/FlaUInspect', 'https://github.com/FlaUI/FlaUInspect', 'Visual inspection tool for exploring UI Automation trees of running Windows applications. The modern replacement for Inspect.exe.', 'choco install flauinspect', 'windows', 'ui-automation-verify', 'verify', 'cli', 'windows', NULL, 'windows/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a94e3078-57e1-463b-9506-c48fd08b8d52', 'Microsoft UI Automation (UIA)', 'https://learn.microsoft.com/en-us/dotnet/framework/ui-automation/', NULL, 'The built-in Windows accessibility and automation framework. Ships with .NET Framework and Windows SDK.', 'UIAutomationClient.dll', 'windows', 'ui-automation-verify', 'verify', 'cli', 'windows', NULL, 'windows/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a86a58d0-aa8b-460c-92b5-973aca16571d', 'WinAppDriver', 'https://github.com/microsoft/WinAppDriver', 'https://github.com/microsoft/WinAppDriver', 'Microsoft''s Selenium/Appium-compatible service for automating Windows desktop app UI. Supports UWP, WinUI 3, WPF, WinForms, and Win32. Runs as a local REST service on `http://127.0.0.1:4723/` and accepts WebDriver-protocol commands.', NULL, 'windows', 'winui-testing-verify', 'verify', 'cli', 'windows,web', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('dd671a98-92d7-4e8c-a4e0-e4729e76bcdb', 'NovaWindows Driver (Appium)', 'https://github.com/AutomateThePlanet/appium-novawindows-driver', 'https://github.com/AutomateThePlanet/appium-novawindows-driver', 'Open-source Appium 2 driver for Windows desktop automation. Drop-in replacement for the abandoned WinAppDriver/Appium Windows driver.', 'appium driver install novawindows', 'windows', 'ui-automation-verify', 'verify', 'cli', NULL, NULL, 'windows/ui-verification.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3969be08-b8a0-465f-a774-b3e68057b5b4', 'Accessibility Insights for Windows', 'https://accessibilityinsights.io/docs/windows/overview/', NULL, 'Free, open-source Microsoft tool for finding and fixing accessibility issues in Windows apps. The recommended replacement for legacy SDK accessibility tools.', NULL, 'windows', 'accessibility-testing-verify', 'verify', 'cli', 'windows', NULL, 'windows/ui-verification.md');
