INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('6354b4bb-9bd3-4bab-a6b3-19b89475e279', 'Snoop', 'https://github.com/snoopwpf/snoopwpf', 'https://github.com/snoopwpf/snoopwpf', 'Open-source WPF spy/inspector utility. Browses the visual tree, logical tree, and automation tree of any running WPF app without a debugger. Allows live property editing, trigger inspection, and breakpoints on property changes.', NULL, 'windows', 'wpf-testing-verify', 'implement,verify', NULL, NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('3af784d0-7c35-4f3b-b00c-7d5e68ddefe1', 'MVVM Unit Testing', NULL, NULL, 'ViewModels in WPF/MAUI follow MVVM, making them testable without UI automation. Test commands, property changes (`INotifyPropertyChanged`), and service interactions using standard unit test frameworks.', NULL, 'windows', 'wpf-testing-verify', 'verify', 'cli', NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c1cbd33f-dc93-4ebe-9265-8b3726416b59', 'Appium for MAUI', 'https://learn.microsoft.com/en-us/dotnet/maui/deployment/unit-testing', NULL, 'Microsoft''s recommended approach for MAUI UI testing. Uses the Appium WebDriver protocol with platform-specific drivers (WinAppDriver on Windows, XCUITest on iOS, UIAutomator2 on Android) to automate MAUI apps across all targets.', NULL, 'windows', 'maui-testing-verify', 'verify', 'plugin', 'ios,android,windows,web', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('cb5c9ab9-59b4-4ec6-a459-6961cb10b99c', 'DeviceRunners', 'https://github.com/mattleibow/DeviceRunners', 'https://github.com/mattleibow/DeviceRunners', 'Runs unit tests directly on physical devices or emulators. Splits the UI from the test runner so tests execute in the context of a running MAUI app. Supports xUnit and NUnit.', NULL, 'windows', 'maui-testing-verify', 'verify', 'cli', 'ios', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b36e58f0-28cc-4c92-8dbb-0626fd7d5ab1', 'MAUI Unit Testing', 'https://learn.microsoft.com/en-us/dotnet/maui/deployment/unit-testing', NULL, 'Standard .NET unit tests targeting MAUI ViewModels, services, and converters. No MAUI runtime required -- tests run in a plain .NET test project.', NULL, 'windows', 'maui-testing-verify', 'verify', 'cli', NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('921b8b97-4889-47e6-8882-db76d86b63e1', 'MakeAppx.exe', 'https://learn.microsoft.com/en-us/windows/msix/package/create-app-package-with-makeappx-tool', NULL, 'Creates MSIX/APPX packages and bundles from loose files. Also extracts, encrypts, and decrypts packages. Included in the Windows SDK.', 'C:\Program Files (x86)\Windows Kits\10\bin\<version>\x64\makeappx.exe', 'windows', 'packaging-certification-verify', 'verify', 'cli', 'ios,windows', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7f9819f8-d992-4f20-bbac-f1fb7b67e2d9', 'SignTool.exe', 'https://learn.microsoft.com/en-us/windows/msix/package/sign-app-package-using-signtool', NULL, 'Digitally signs MSIX packages and executables. Required for MSIX installation -- unsigned packages cannot be installed.', 'C:\Program Files (x86)\Windows Kits\10\bin\<version>\x64\signtool.exe', 'windows', 'packaging-certification-verify', 'verify', 'cli', 'windows,azure', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('997a2bc3-35b2-42fc-b80f-b63507136997', 'Windows App Certification Kit', 'https://learn.microsoft.com/en-us/windows/uwp/debug-test-perf/windows-app-certification-kit', NULL, 'Validates that an MSIX package meets Microsoft Store requirements. Tests security, performance, and API compliance. Required before Store submission.', 'appcert.exe', 'windows', 'packaging-certification-verify', 'verify', 'cli', 'windows', 'go', 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('063a2fd3-d458-487b-8866-22312d608b86', 'Microsoft Store Developer CLI', 'https://github.com/microsoft/msstore-cli', 'https://github.com/microsoft/msstore-cli', 'Cross-platform CLI (Windows, macOS, Linux) for publishing apps to the Microsoft Store. Configures projects, creates MSIX packages, and submits to Partner Center APIs.', NULL, 'windows', 'packaging-certification-verify', 'verify', 'cli', 'macos,windows,linux', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('175f1f0c-aa8b-4aa9-9d92-a3d53b18169d', 'GitHub Actions', 'https://github.com/jfversluis/MauiGithubActionsSample', 'https://github.com/jfversluis/MauiGithubActionsSample', 'GitHub-hosted Windows runners include the .NET SDK, Windows SDK, and MSBuild. Builds WinUI, WPF, and MAUI Windows targets. The `windows-latest` image includes Visual Studio Build Tools.', NULL, 'windows', 'cicd-integration-verify', 'verify', NULL, 'windows', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('7c7e77fb-95c1-4b38-8e35-c02d6140a554', 'Azure DevOps Pipelines', 'https://learn.microsoft.com/en-us/windows/msix/desktop/cicd-overview', NULL, 'Microsoft''s CI/CD platform with deep MSIX integration. MSIX Packaging Extension available from the Visual Studio Marketplace. Supports Azure Key Vault for certificate management.', NULL, 'windows', 'cicd-integration-verify', 'verify', 'cli', 'windows,azure', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('30803dae-16ba-42d7-9913-6daaaac3c802', 'WACK GitHub Action', 'https://github.com/ChristopheLav/wack-certification', 'https://github.com/ChristopheLav/wack-certification', 'GitHub Action that runs the Windows App Certification Kit and generates test results as artifacts.', NULL, 'windows', 'cicd-integration-verify', 'verify', NULL, 'windows', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('a3b0011b-b4a0-4c05-a6ab-ae8534517ee4', 'XAML Hot Reload', 'https://learn.microsoft.com/en-us/visualstudio/xaml-tools/xaml-hot-reload', NULL, 'Incrementally updates XAML UI in a running WPF, UWP, WinUI 3, or MAUI app without restarting. Starting in Visual Studio 2022 v17.14 Preview 2, also available at design-time (not just during debugging).', NULL, 'windows', 'development-diagnostic-tools-implement', 'implement', NULL, 'windows', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('28c27224-cdfa-4aa0-8870-e6026584a941', 'Live Visual Tree', 'https://learn.microsoft.com/en-us/visualstudio/xaml-tools/inspect-xaml-properties-while-debugging', NULL, 'Built-in Visual Studio tool that displays the live visual tree of a running XAML app (WPF, UWP, WinUI 3, MAUI). Allows inspecting and editing properties in real time during debugging.', NULL, 'windows', 'development-diagnostic-tools-implement', 'implement', NULL, NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('bd911e4f-4a67-4262-b7cc-759f9beabc64', 'UWPSpy', 'https://github.com/m417z/UWPSpy', 'https://github.com/m417z/UWPSpy', 'Inspection tool for UWP and WinUI 3 applications. Views and manipulates UI elements and their properties in real time. Uses the XAML Diagnostic APIs (Windows 10 v1703+).', 'UWPSpy.exe', 'windows', 'development-diagnostic-tools-implement', 'implement', NULL, 'windows', NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('4248b47f-5ea3-4a32-9c14-fda55b3d4a3d', 'WinUI3.Design.Diagnostics', 'https://github.com/KyleC69/WinUI3.Design.Diagnostics', 'https://github.com/KyleC69/WinUI3.Design.Diagnostics', 'In-app diagnostics tool for WinUI 3 providing a live visual tree, style inspector, and resource lookup tracer. Embeds directly in your app.', NULL, 'windows', 'development-diagnostic-tools-implement', 'implement', 'cli', 'ios', 'go', 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('70aeabc8-ab1f-4bc9-85e0-abacca16922c', 'Roslyn Analyzers & StyleCop', 'https://github.com/DotNetAnalyzers/StyleCopAnalyzers', 'https://github.com/DotNetAnalyzers/StyleCopAnalyzers', 'Static code analysis integrated into the build. Roslyn analyzers run during `dotnet build` and report diagnostics. StyleCop.Analyzers enforces C# style rules. Microsoft.CodeAnalysis.NetAnalyzers provides CA-prefixed quality rules.', NULL, 'windows', 'development-diagnostic-tools-implement', 'implement,verify', 'cli', NULL, 'c#', 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('0ece030a-3ff5-4054-8dea-03f09aa6bfe7', 'dotnet test', 'https://learn.microsoft.com/en-us/dotnet/core/tools/dotnet-test', NULL, 'Runs unit and integration tests for xUnit, NUnit, MSTest, and TUnit projects. Supports two test platforms: VSTest (legacy) and Microsoft.Testing.Platform (MTP, modern).', NULL, 'windows', 'test-infrastructure-verify', 'verify', 'cli', NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('b71eaf0a-8436-463c-ac14-4b808c5cdc91', 'Coverlet + ReportGenerator', 'https://github.com/coverlet-coverage/coverlet', 'https://github.com/coverlet-coverage/coverlet', 'Coverlet collects code coverage data during test runs. ReportGenerator converts coverage XML into human-readable HTML reports.', NULL, 'windows', 'test-infrastructure-verify', 'verify', 'cli', NULL, NULL, 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c304010c-49c4-4a8c-a1de-715b801be722', 'C# LSP Plugin', 'https://claude.com/plugins/csharp-lsp', NULL, 'Enables IDE-like code intelligence in Claude Code for C# projects. Provides go-to-definition, find-references, hover type information, and real-time diagnostics. Finding all call sites takes ~50ms (vs ~45s with text search).', NULL, 'windows', 'claude-code-integration-all-phases', 'plan,implement,verify', 'plugin', NULL, 'go,c#', 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('8dbc808f-3b93-4f9b-88db-4019751b03d2', 'csharp-lsp-mcp', 'https://github.com/HYMMA/csharp-lsp-mcp', 'https://github.com/HYMMA/csharp-lsp-mcp', 'MCP server providing C# and XAML language intelligence for Claude Code. Exposes IntelliSense, diagnostics, and code analysis through the Model Context Protocol. Supports both `.cs` and `.xaml` files.', NULL, 'windows', 'claude-code-integration-all-phases', 'plan,implement,verify', 'mcp', NULL, 'c#,lua', 'windows/winui-and-build.md');
INSERT INTO tools (id, name, url, github_url, description, install_command, category, subcategory, loop_phases, integration_method, platforms, languages, source_file) VALUES ('c1ed7ab8-5b5a-4969-aa01-7a3cfa5798a4', 'Claude Code LSP', 'https://github.com/ktnyt/cclsp', 'https://github.com/ktnyt/cclsp', 'Non-IDE-dependent LSP integration for Claude Code. Supports 11 languages including C#. Provides go-to-definition, find-references, and diagnostics.', NULL, 'windows', 'claude-code-integration-all-phases', 'plan,implement,verify', 'plugin', NULL, 'go,c#', 'windows/winui-and-build.md');
